-- Poems batch 73
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('69b236e5-0a72-4f82-a581-7d8d83122f6c','句','梁鍠','唐','唐诗','tang','','[]','堂高憑上望，宅廣乘車行。',12,'全唐诗/poet.tang.9000.json','["堂高憑上望，宅廣乘車行。"]'),
('735c5425-745a-4a91-97e3-e6d262dce5fc','客中作','杜儼','唐','唐诗','tang','','[]','書劒催人不暫閑，洛陽羈旅復秦關。',32,'全唐诗/poet.tang.9000.json','["書劒催人不暫閑，洛陽羈旅復秦關。", "容顏歲歲愁邊改，鄉國時時夢裏還。"]'),
('b31f56ac-0f36-4a9b-9800-7db89789a1cf','三月三日曲江侍宴','趙良器','唐','唐诗','tang','','[]','聖祖發神謀，靈符叶帝求。',72,'全唐诗/poet.tang.9000.json','["聖祖發神謀，靈符叶帝求。", "一人光錫命，萬國荷時休。", "雷解圜丘畢，雲需曲水遊。", "岸花迎步輦，仙仗擁行舟。", "睿藻天中降，恩波海外流。", "小臣同品物，陪此樂皇猷。"]'),
('08e41396-2809-423d-9bbc-1e6fb24c0ca1','日詩','宋太祖','宋','宋诗','song-poetry','','[]','欲出未出光辣達，千山萬山如火發。',32,'全唐诗/poet.song.0.json','["欲出未出光辣達，千山萬山如火發。", "須臾走向天上來，逐却殘星趕却月。"]'),
('adaa27a4-389b-48ca-8021-80f0471433c4','句','宋太祖','宋','宋诗','song-poetry','','[]','未離海底千山黑，纔到天中萬國明。',16,'全唐诗/poet.song.0.json','["未離海底千山黑，纔到天中萬國明。"]'),
('05efccd1-3be1-44e8-a38a-78b9f9715a1f','登戎州江樓閑望','幸夤遜','宋','宋诗','song-poetry','','[]','滿目江山四望幽，白雲高卷嶂烟收。',48,'全唐诗/poet.song.0.json','["滿目江山四望幽，白雲高卷嶂烟收。", "日回禽影穿疏木，風遞猿聲入小樓。", "遠岫似屏橫碧落，斷帆如葉截中流。"]'),
('f7a148f0-e5ea-413e-8647-da1650104682','雪','幸夤遜','宋','宋诗','song-poetry','','[]','片片飛來靜又閑，樓頭江上復山前。',32,'全唐诗/poet.song.0.json','["片片飛來靜又閑，樓頭江上復山前。", "飄零盡日不歸去，帖破清光萬里天。"]'),
('f70f9128-5221-4bdc-9dbf-63492c40e826','雲','幸夤遜','宋','宋诗','song-poetry','','[]','因登巨石知來處，勃勃元生綠蘚痕。',64,'全唐诗/poet.song.0.json','["因登巨石知來處，勃勃元生綠蘚痕。", "靜即等閑藏草木，動時頃刻徧乾坤。", "橫天未必朋元惡，捧日還曾瑞至尊。", "不獨朝朝在巫峽，楚王何事謾勞魂。"]'),
('7c1fd332-2799-436a-ba46-e61162308431','句  其一','幸夤遜','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','若教作鎮居中國，爭得泥金在泰山。',16,'全唐诗/poet.song.0.json','["若教作鎮居中國，爭得泥金在泰山。"]'),
('f05b3477-8925-4179-aa4a-1dc0af9b1f52','句  其二','幸夤遜','宋','宋诗','song-poetry','','[]','纔聞暖律先偷眼，既待和風始展眉。',16,'全唐诗/poet.song.0.json','["纔聞暖律先偷眼，既待和風始展眉。"]'),
('10e6b857-f147-4bc5-817d-9137cace7182','句  其三','幸夤遜','宋','宋诗','song-poetry','','[]','嚼處春冰敲齒冷，嚥時雪液沃心寒。',16,'全唐诗/poet.song.0.json','["嚼處春冰敲齒冷，嚥時雪液沃心寒。"]'),
('24e061ec-2274-4603-a6bf-5747abbd955b','句  其四','幸夤遜','宋','宋诗','song-poetry','','[]','蒙君知重惠瓊實，薄起金刀釘玉深。',16,'全唐诗/poet.song.0.json','["蒙君知重惠瓊實，薄起金刀釘玉深。"]'),
('c7c24b86-9f66-468d-96b1-f9a143a186d2','句  其五','幸夤遜','宋','宋诗','song-poetry','','[]','深妝玉瓦平無壠，亂拂蘆花細有聲。',16,'全唐诗/poet.song.0.json','["深妝玉瓦平無壠，亂拂蘆花細有聲。"]'),
('8f77e50b-c7bb-4023-9659-6b8ec42a92bb','句  其六','幸夤遜','宋','宋诗','song-poetry','','[]','片逐銀蟾落醉觥。',8,'全唐诗/poet.song.0.json','["片逐銀蟾落醉觥。"]'),
('cdd8a93a-7ded-4426-9238-f9a656689f05','句  其七','幸夤遜','宋','宋诗','song-poetry','','[]','巧剪銀花亂，輕飛玉葉狂。',12,'全唐诗/poet.song.0.json','["巧剪銀花亂，輕飛玉葉狂。"]'),
('e9e84861-423e-45d6-9a3a-3811b97268ff','句  其八','幸夤遜','宋','宋诗','song-poetry','','[]','寒艷芳姿色盡明。',8,'全唐诗/poet.song.0.json','["寒艷芳姿色盡明。"]'),
('4b2159aa-5594-4f4c-ab8b-2a99cddb29b8','金陵覽古 秦淮','朱存','宋','宋诗','song-poetry','','[]','一氣東南王斗牛，祖龍潜爲子孫憂。',32,'全唐诗/poet.song.0.json','["一氣東南王斗牛，祖龍潜爲子孫憂。", "金陵地脈何曾斷，不覺真人已姓劉。"]'),
('69cf5a0e-55c2-41ee-8bb8-812ce5637d84','金陵覽古 石頭城','朱存','宋','宋诗','song-poetry','','[]','五城樓雉各相望，山水英靈宅帝王。',32,'全唐诗/poet.song.0.json','["五城樓雉各相望，山水英靈宅帝王。", "此地定由天造險，古來長恃作金湯。"]'),
('7d360354-5d01-4856-b1b8-ec12aa10bfd2','金陵覽古 段石岡','朱存','宋','宋诗','song-poetry','','[]','孫吳紀德舊刊碑，草沒蟠螭與伏龜。',32,'全唐诗/poet.song.0.json','["孫吳紀德舊刊碑，草沒蟠螭與伏龜。", "惆悵岡頭三段石，至今猶似鼎分時。"]'),
('3ef8c611-c75f-4601-b8b9-cdbcbb92dde9','金陵覽古 北渠','朱存','宋','宋诗','song-poetry','','[]','金殿分來玉砌流，黑龍湖徹鳳池頭。',32,'全唐诗/poet.song.0.json','["金殿分來玉砌流，黑龍湖徹鳳池頭。", "後庭花落恩波斷，翻與南唐作御溝。"]'),
('66aabafa-fa03-48fc-b156-5aaba996837c','金陵覽古 新亭','朱存','宋','宋诗','song-poetry','','[]','滿目江山異洛陽，昔人何必重悲傷。',32,'全唐诗/poet.song.0.json','["滿目江山異洛陽，昔人何必重悲傷。", "倘能戮力扶王室，當自新亭復故鄉。"]'),
('73366c6c-4fd2-4d30-ad86-25d6d14c5bb5','金陵覽古 天闕山','朱存','宋','宋诗','song-poetry','','[]','牛頭天際碧凝嵐，王導無稽亦妄談。',32,'全唐诗/poet.song.0.json','["牛頭天際碧凝嵐，王導無稽亦妄談。", "若指遠山爲上闕，長安應合指終南。"]'),
('33db812d-3cb4-4d2c-8e3b-44a87b7f3103','金陵覽古 東山','朱存','宋','宋诗','song-poetry','','[]','鎮物高情濟世才，欲隨猿鶴老巖隈。',32,'全唐诗/poet.song.0.json','["鎮物高情濟世才，欲隨猿鶴老巖隈。", "山花處處紅粧面，髣髴如初擁妓來。"]'),
('be1847b4-6a06-4a20-abad-8d470f80dbc9','金陵覽古 烏衣巷','朱存','宋','宋诗','song-poetry','','[]','人物風流往往非，空餘陋巷作烏衣。',32,'全唐诗/poet.song.0.json','["人物風流往往非，空餘陋巷作烏衣。", "舊時簾幕無從覓，只有年年社燕歸。"]'),
('37b1afb2-400f-4de4-ad15-d3b7c9cb0225','金陵覽古 阿育王塔','朱存','宋','宋诗','song-poetry','','[]','窣堵凝然鎮梵宮，舉頭層級在雲中。',32,'全唐诗/poet.song.0.json','["窣堵凝然鎮梵宮，舉頭層級在雲中。", "金棺舍利藏何處，鐸繞危簷聲撼風。"]'),
('942c23d9-fbbd-4780-9581-0f5b80f9593b','金陵覽古 烏衣巷','朱存','宋','宋诗','song-poetry','','[]','閥閱淪亡梐枑移，年年舊燕亦雙歸。',32,'全唐诗/poet.song.0.json','["閥閱淪亡梐枑移，年年舊燕亦雙歸。", "茅簷葦箔無冠蓋，不見烏衣見白衣。"]'),
('818a2cb4-0025-4139-bfc0-efb9c51c6e87','金陵覽古 後湖','朱存','宋','宋诗','song-poetry','','[]','雷轟疊鼓火翻旗，三翼翩翩試水師。',32,'全唐诗/poet.song.0.json','["雷轟疊鼓火翻旗，三翼翩翩試水師。", "驚起黑龍眠不得，狂風猛雨下多時。"]'),
('2f3f8e5b-94a0-431f-9527-5a8fa05510d1','金陵覽古 半陽湖','朱存','宋','宋诗','song-poetry','','[]','江南龍節水爲鄉，水不純陰又半陽。',32,'全唐诗/poet.song.0.json','["江南龍節水爲鄉，水不純陰又半陽。", "一片湖光共深淺，兩般泉脈異溫凉。"]'),
('b0384a60-36c2-4144-9405-80d4c620e367','金陵覽古 潮溝','朱存','宋','宋诗','song-poetry','','[]','流水東西傍帝臺，六朝重爲兩朝開。',32,'全唐诗/poet.song.0.json','["流水東西傍帝臺，六朝重爲兩朝開。", "曾有鷁首知高下，莫問魚舟識去來。"]'),
('ffd90226-e181-48d5-bbda-16811e5f9086','金陵覽古 直瀆','朱存','宋','宋诗','song-poetry','','[]','晝役人功夜鬼功，陽開陰闔幾時終。',32,'全唐诗/poet.song.0.json','["晝役人功夜鬼功，陽開陰闔幾時終。", "不聞擲土江中語，爭得盈流一水通。"]'),
('c93a79dd-919a-43fe-ae3b-b18b4d7073c7','金陵覽古 運瀆','朱存','宋','宋诗','song-poetry','','[]','舳艫銜尾日無虛，更鑿都城引漕渠。',32,'全唐诗/poet.song.0.json','["舳艫銜尾日無虛，更鑿都城引漕渠。", "何事餒來貪雀穀，不知留得幾年儲。"]'),
('3c012f50-6e02-491d-876d-9cab0a78586f','金陵覽古 鳳凰臺','朱存','宋','宋诗','song-poetry','','[]','竹影桐陰滿舊山，鳳凰多載不飛還。',32,'全唐诗/poet.song.0.json','["竹影桐陰滿舊山，鳳凰多載不飛還。", "登臺只有吹簫者，爭得和鳴墮世間。"]'),
('a9853529-3904-4626-ad43-7b521b01c296','偈','釋德韶','宋','宋诗','song-poetry','','[]','通玄峰頂，不是人門。',20,'全唐诗/poet.song.0.json','["通玄峰頂，不是人門。", "心外無法，滿目青山。"]'),
('0768d60c-8155-4683-89d0-d428b894ab3a','頌','釋德韶','宋','宋诗','song-poetry','','[]','暫下高峰已顯揚，般若圜通遍十方。',32,'全唐诗/poet.song.0.json','["暫下高峰已顯揚，般若圜通遍十方。", "人天浩浩無差別，法界縱橫處處彰。"]'),
('9f0cdc41-63a8-4718-9466-fc2932d5226a','偈','釋志端','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','來年二月二，與汝暫相棄。',24,'全唐诗/poet.song.0.json','["來年二月二，與汝暫相棄。", "燒灰散長江，勿占檀那地。"]'),
('12ed7aed-cc5f-459f-9cd7-266d3aac4853','句','釋志端','宋','宋诗','song-poetry','','[]','木馬走似烟，石人趁不及。',12,'全唐诗/poet.song.0.json','["木馬走似烟，石人趁不及。"]'),
('47ed830e-1589-43b6-9379-09ac4c3e7b57','春社日寄李學士','李濤','宋','宋诗','song-poetry','','[]','社翁今日沒心情，爲乞治聾酒一瓶。',32,'全唐诗/poet.song.0.json','["社翁今日沒心情，爲乞治聾酒一瓶。", "惱亂玉堂將欲徧，依稀巡到第三廳。"]'),
('1032f3ab-ec36-4a5a-9839-e9d540052a17','題泥水關不動尊院','李濤','宋','宋诗','song-poetry','','[]','走却坐禪客，移將不動尊。',24,'全唐诗/poet.song.0.json','["走却坐禪客，移將不動尊。", "世間顛倒事，八萬四千門。"]'),
('0d10a855-4cdc-4064-a221-f95e554504c0','贈山翁','李濤','宋','宋诗','song-poetry','','[]','松蘿深處住，閑野不生愁。',48,'全唐诗/poet.song.0.json','["松蘿深處住，閑野不生愁。", "鳥語烟嵐靜，水聲門戶秋。", "花間歸洞路，山下釣魚舟。", "沐浴聖王化，自憐絲滿頭。"]'),
('0a196806-4b83-4a13-ac55-3487cef68519','題處士林亭','李濤','宋','宋诗','song-poetry','','[]','帝里高人宅，蒼苔遶徑深。',48,'全唐诗/poet.song.0.json','["帝里高人宅，蒼苔遶徑深。", "卷簾山入戶，摘菓鳥移林。", "石沼養龜水，月臺留客琴。", "生涯一樽酒，名利不關心。"]'),
('7b4d7315-69ed-4d68-8876-37bcba9fed9f','雜詩四首  其一','李濤','宋','宋诗','song-poetry','','[]','滔滔東流水，赴海無歸期。',48,'全唐诗/poet.song.0.json','["滔滔東流水，赴海無歸期。", "亭亭右轉日，今茲復來茲。", "人生寄天地，百年七十稀。", "思慮復營營，恐爲達此嗤。"]'),
('95b636a2-edce-41a2-a3e7-ef599ad64ba1','雜詩四首  其二','李濤','宋','宋诗','song-poetry','','[]','燕雀賀厦屋，蟲蟻慕腥羶。',48,'全唐诗/poet.song.0.json','["燕雀賀厦屋，蟲蟻慕腥羶。", "野花引飛蝶，古木來新蟬。", "秋天百蟲吟，春天百鳥喧。", "翟公真闇事，喜慍見色言。"]'),
('aa6a37cc-561d-4740-98b4-3659941c322f','雜詩四首  其三','李濤','宋','宋诗','song-poetry','','[]','明主不棄士，我自志山林。',48,'全唐诗/poet.song.0.json','["明主不棄士，我自志山林。", "爵服豈無華，才疏力難任。", "鳥向深山棲，魚由深淵沉。", "吾亦愛吾廬，高歌復微吟。"]'),
('024a1d05-f82a-4676-8db1-50777a1b136f','雜詩四首  其四','李濤','宋','宋诗','song-poetry','','[]','深巖有老翁，龐眉鬚鬢雪。',60,'全唐诗/poet.song.0.json','["深巖有老翁，龐眉鬚鬢雪。", "夜半呼我名，授我微妙訣。", "字畫古籀樣，體勢訛復缺。", "雙眸忽炯炯，須臾竟披閱。", "至今得其傳，心會口難說。"]'),
('329ddd62-6d24-4e48-aad7-78a4708b4d6a','句','李濤','宋','宋诗','song-poetry','','[]','一言寤主寧復聽，三諫不從歸去來。',23,'全唐诗/poet.song.0.json','["一言寤主寧復聽，三諫不從歸去來。", "諫晉主不從作。"]'),
('83debf4a-91a7-4ae9-9c59-69d4008c0722','俞公巖','陳摶','宋','宋诗','song-poetry','','["\u8861\u5c71"]','萬事若在手，百年聊稱情。',24,'全唐诗/poet.song.0.json','["萬事若在手，百年聊稱情。", "他時南嶽去，記得此巖名。"]'),
('4d0889b0-849b-4b45-88bc-4ea9337fd768','歸隠','陳摶','宋','宋诗','song-poetry','','[]','十年蹤跡走紅塵，回首青山入夢頻。',64,'全唐诗/poet.song.0.json','["十年蹤跡走紅塵，回首青山入夢頻。", "紫陌縱榮爭及睡，朱門雖貴不如貧。", "愁聞劍戟扶危主，悶見笙歌聒醉人。", "携取舊書歸舊隠，野花啼鳥一般春。"]'),
('090f3ff4-9ed8-411f-a9e8-b648f9b67ba4','贈金勵睡詩  其一','陳摶','宋','宋诗','song-poetry','','[]','常人無所重，惟睡乃爲重。',48,'全唐诗/poet.song.0.json','["常人無所重，惟睡乃爲重。", "舉世皆爲息，魂離神不動。", "覺來無所知，貪求心愈用。", "堪笑塵中人，不知夢是夢。"]'),
('d6306463-c389-4f5c-8bd7-cf4c1b6b62bd','贈金勵睡詩  其二','陳摶','宋','宋诗','song-poetry','','[]','至人本無夢，其夢本遊仙。',48,'全唐诗/poet.song.0.json','["至人本無夢，其夢本遊仙。", "真人本無睡，睡則浮雲烟。", "爐裏近爲藥，壺中別有天。", "欲知睡夢裏，人間第一玄。"]'),
('3a6a389e-3096-4a13-b902-5285e5504049','題石水澗','陳摶','宋','宋诗','song-poetry','','[]','銀河灑落翠光冷，一派回環湛晚暉。',32,'全唐诗/poet.song.0.json','["銀河灑落翠光冷，一派回環湛晚暉。", "幾恨却爲頑石礙，琉璃滑處玉花飛。"]'),
('42741e82-7268-4f46-abf7-5d8831ac2566','冬日晚望','陳摶','宋','宋诗','song-poetry','','[]','山鬼煖或呼，溪魚寒不跳。',24,'全唐诗/poet.song.0.json','["山鬼煖或呼，溪魚寒不跳。", "晚景愈堪觀，危峰露殘照。"]'),
('57462fb3-4dd9-4423-a938-d21e546f720a','西峰','陳摶','宋','宋诗','song-poetry','','[]','爲愛西峰好，吟頭盡日昂。',48,'全唐诗/poet.song.0.json','["爲愛西峰好，吟頭盡日昂。", "巖花紅作陣，溪水綠成行。", "幾夜礙新月，半山無夕陽。", "寄言嘉遁客，此處是仙鄉。"]'),
('cfc36435-540b-4bab-8db7-7f9bb2403198','華山','陳摶','宋','宋诗','song-poetry','','[]','半夜天香入巖谷，西風吹落嶺頭蓮。',32,'全唐诗/poet.song.0.json','["半夜天香入巖谷，西風吹落嶺頭蓮。", "空愛掌痕侵碧漢，無人曾歎巨靈仙。"]'),
