('a41d7612-f1b0-4743-9002-5344e588c80b','山居詩  其一','釋延壽','宋','宋诗','song-poetry','','[]','此事從來已絕疑，安然樂道合希夷。',64,'全唐诗/poet.song.0.json','["此事從來已絕疑，安然樂道合希夷。", "依山偶得還源旨，拂石閒題出格詩。", "水待凍開成細溜，薪從霜後拾枯枝。", "因茲永斷攀緣意，誓與青松作老期。"]'),
('ba99895f-ada2-43b1-bfd9-c79bd1d73e08','山居詩  其二','釋延壽','宋','宋诗','song-poetry','','[]','古樹交盤簇徑深，闃無人到爲難尋。',64,'全唐诗/poet.song.0.json','["古樹交盤簇徑深，闃無人到爲難尋。", "祇和算計千般事，誰解消停一點心。", "冰鎖瀑聲中夜斷，雲吞嶽影半天沈。", "寒燈欲絕禪初起，透牖疏風觸短襟。"]'),
('40cd43e8-9980-4a58-8273-e0c752c572bf','山居詩  其三','釋延壽','宋','宋诗','song-poetry','','[]','祇園閒適樂簞瓢，莫訝烟霞道路遥。',64,'全唐诗/poet.song.0.json','["祇園閒適樂簞瓢，莫訝烟霞道路遥。", "龍穴定知潛碧海，鵬程終是望丹霄。", "撥雲巖下來泉脈，嚼草坡邊辨藥苗。", "門鎖薜蘿無客至，庵前時有白雲朝。"]'),
('89c0a14f-8fe8-4f21-b651-1c2f27fe14e6','山居詩  其四','釋延壽','宋','宋诗','song-poetry','','[]','貪生養命事皆同，獨坐閒居意頗慵。',64,'全唐诗/poet.song.0.json','["貪生養命事皆同，獨坐閒居意頗慵。", "入夏驅馳巢樹鵲，經春勞役探花蜂。", "石爐香盡寒灰薄，鐵磬聲微古鏽濃。", "寂寂虛懷無一念，任從蒼蘚沒行蹤。"]'),
('5f2f7a0a-2bee-4292-93d7-1dea538483f4','山居詩  其五','釋延壽','宋','宋诗','song-poetry','','[]','心地須教合死灰，藏機泯跡絕梯媒。',64,'全唐诗/poet.song.0.json','["心地須教合死灰，藏機泯跡絕梯媒。", "芳蘭祇爲因香折，良木多從被直摧。", "寒逼花枝紅未吐，日融水面綠全開。", "支頤獨坐經窗下，一片雲閒入戶來。"]'),
('8517f71a-7443-441b-9bc9-392dda53af16','山居詩  其六','釋延壽','宋','宋诗','song-poetry','','[]','達來何處更追尋，放曠誰論古與今。',64,'全唐诗/poet.song.0.json','["達來何處更追尋，放曠誰論古與今。", "風带泉聲流谷口，雲和山影落潭心。", "資身自有衣中寶，濟世誰藏室內金。", "策杖偶來林下坐，鳥聲相和唱圓音。"]'),
('f02b7f56-a973-4bf7-bca4-8e6e06114b19','山居詩  其七','釋延壽','宋','宋诗','song-poetry','','[]','事多興廢莫持論，唯有禪宗理可尊。',64,'全唐诗/poet.song.0.json','["事多興廢莫持論，唯有禪宗理可尊。", "似訥始平分別路，如愚方塞是非門。", "刳腸祇爲生靈智，剖舌多因强語言。", "爭似息機高卧客，年來年去道長存。"]'),
('f64fd5c3-87b4-4f3e-847f-13c0451568be','山居詩  其八','釋延壽','宋','宋诗','song-poetry','','[]','碧嶠經年常寂寂，更無閒事可相於。',64,'全唐诗/poet.song.0.json','["碧嶠經年常寂寂，更無閒事可相於。", "超倫每效高僧行，得力難忘古佛書。", "落葉亂渠憑水蕩，浮雲翳月倩風除。", "方知嬾與真空合，一衲閒披憩舊廬。"]'),
('3826c3a3-65d9-497f-9418-5e8264dbe3b5','山居詩  其九','釋延壽','宋','宋诗','song-poetry','','[]','幽齋獨坐絕參詳，兀爾何如驟世忙。',64,'全唐诗/poet.song.0.json','["幽齋獨坐絕參詳，兀爾何如驟世忙。", "拯濟終憑宏願力，安閒須得守愚方。", "柴門半掩花空落，苔徑虛蹤草自荒。", "最好靜中無一事，翛然唯得道芽長。"]'),
('ca7c37df-1604-4e0b-8f56-daf16bb80ef8','山居詩  其一○','釋延壽','宋','宋诗','song-poetry','','[]','曠然不被興亡墜，豁爾難教寵辱驚。',64,'全唐诗/poet.song.0.json','["曠然不被興亡墜，豁爾難教寵辱驚。", "鼓角城遥無伺候，輪蹄路絕免逢迎。", "暖眠紙帳茅堂密，穩坐蒲團石面平。", "祇有此途爲上策，更無餘事可關情。"]'),
('11a5902c-4035-4376-960c-70b19dd72b97','山居詩  其一一','釋延壽','宋','宋诗','song-poetry','','[]','觸目堪嗟失路人，坦然王道却迷津。',64,'全唐诗/poet.song.0.json','["觸目堪嗟失路人，坦然王道却迷津。", "井籐梗上存餘命，石火光中保幻身。", "任老豈知頭頂白，忘緣誰覺世閒春。", "容顔枯槁元非病，亭沼消疏不是貧。"]'),
('b5081005-4d13-4657-b420-3662daf9321a','山居詩  其一二','釋延壽','宋','宋诗','song-poetry','','[]','言行相應宜此地，空談大隠也無端。',64,'全唐诗/poet.song.0.json','["言行相應宜此地，空談大隠也無端。", "升沈岐路非他得，生熟根機且自看。", "瞋火微烟還漸息，貪泉餘潤亦消乾。", "平生正直須甘取，虛幻門中莫自瞞。"]'),
('186c56c0-9fe2-4850-b3ef-9f58469d06a2','山居詩  其一三','釋延壽','宋','宋诗','song-poetry','','[]','怡和心境了然同，大道無私處處通。',64,'全唐诗/poet.song.0.json','["怡和心境了然同，大道無私處處通。", "舉世豈懷身後慮，誰人暫省事前空。", "門開巖石千山月，簾捲溪樓一檻風。", "羸體健來知藥力，緣心寂後覺神功。"]'),
('8384b616-6ed5-49db-a330-b9d6958ea71e','山居詩  其一四','釋延壽','宋','宋诗','song-poetry','','[]','進退應須與智論，浮萍自在爲無根。',64,'全唐诗/poet.song.0.json','["進退應須與智論，浮萍自在爲無根。", "埽門何太拋途轍，解珮猶能棄渥恩。", "草徑旋封迷舊跡，苔階亂織露新痕。", "不唯此景供遊賞，無限烟蘿盡一吞。"]'),
('c5fe3aed-fc9a-4d06-8ced-ea1b3b55a060','山居詩  其一五','釋延壽','宋','宋诗','song-poetry','','[]','塵網休重織是非，冥心何不合玄微。',64,'全唐诗/poet.song.0.json','["塵網休重織是非，冥心何不合玄微。", "莊周夢裏多迷旨，惠子漁中少見機。", "拶路古松和凍折，盤空枯葉带霜飛。", "一言可達知音者，還得從吾此路歸。"]'),
('23df95d2-6549-431c-9807-7eda14962c9c','山居詩  其一六','釋延壽','宋','宋诗','song-poetry','','[]','抱朴澄神藴道光，石爐閒爇六時香。',64,'全唐诗/poet.song.0.json','["抱朴澄神藴道光，石爐閒爇六時香。", "曳空橫野雲和靜，逗石穿崖水自忙。", "晚圃雨來葵葉嫩，晴坡燒後蕨苗長。", "一心包盡乾坤內，莫把閒文更度量。"]'),
('87535283-ae8c-4cb0-97b7-237ea628562c','山居詩  其一七','釋延壽','宋','宋诗','song-poetry','','[]','松蘿閒鎖一身孤，履道安禪是密謨。',64,'全唐诗/poet.song.0.json','["松蘿閒鎖一身孤，履道安禪是密謨。", "借問野雲誰斷續，思量春草自榮枯。", "多見異獸心堪伏，來慣幽禽不用呼。", "萬物盡從成熟得，莫教容易喪工夫。"]'),
('d6ac9feb-1e56-4950-83b7-62109399a2ec','山居詩  其一八','釋延壽','宋','宋诗','song-poetry','','[]','平生初志已酬之，懷抱怡然寂有歸。',64,'全唐诗/poet.song.0.json','["平生初志已酬之，懷抱怡然寂有歸。", "古帙懶開緣得意，幽房長閉爲忘機。", "數行鳥陣連雲沒，一带泉聲隔嶺微。", "道合古今渾總是，何須更慮昔年非。"]'),
('86be38c2-3d95-4f83-aff3-e180f36d2947','山居詩  其一九','釋延壽','宋','宋诗','song-poetry','','[]','青山一坐萬緣休，努力應須與古儔。',64,'全唐诗/poet.song.0.json','["青山一坐萬緣休，努力應須與古儔。", "散誕襟懷因絕趣，消疏活計爲無求。", "花明小砌和春月，松暗前軒带雨秋。", "景像自開還自合，怡然何必更忘憂。"]'),
('f7cc3ee3-c738-4b7c-bf1a-4f083441742e','山居詩  其二○','釋延壽','宋','宋诗','song-poetry','','[]','自甘疏拙懶經營，大道從來戒滿盈。',64,'全唐诗/poet.song.0.json','["自甘疏拙懶經營，大道從來戒滿盈。", "但起貪心迷有限，誰能觸目悟無生。", "雲融遠景危峰小，風戛寒溪野艇橫。", "禪後不妨敷六義，祇圖歌出野人情。"]'),
('6622eb2e-609a-4baa-a8a1-035c4e2229c0','山居詩  其二一','釋延壽','宋','宋诗','song-poetry','','[]','忙處須閒淡處濃，世情疏後道情通。',64,'全唐诗/poet.song.0.json','["忙處須閒淡處濃，世情疏後道情通。", "了然得旨青冥外，兀爾虛心罔象中。", "泉細石根飛不盡，雲濛山脚出無窮。", "樵夫釣客雖閒散，未必真棲與我同。"]'),
('6c7d4481-f68a-4c7d-90d3-881659c71c6a','山居詩  其二二','釋延壽','宋','宋诗','song-poetry','','[]','且停多事莫矜誇，寂寞門中有道華。',64,'全唐诗/poet.song.0.json','["且停多事莫矜誇，寂寞門中有道華。", "隈嶺靜同猿窟宅，栽松閒共鶴生涯。", "榮來祇愛添餘祿，春過誰能悟落花。", "唯有卧雲塵外客，無思無慮老烟霞。"]'),
('acdab0e6-3522-4db9-9ecf-9479c511dd19','山居詩  其二三','釋延壽','宋','宋诗','song-poetry','','[]','沈沈竹院鎖輕烟，澹澹霞光欲曙天。',64,'全唐诗/poet.song.0.json','["沈沈竹院鎖輕烟，澹澹霞光欲曙天。", "遇境偶吟情自逸，逢人話道意無偏。", "古松交處眠青帳，細草濃時坐碧氈。", "祇此逍遥何所得，蔬食寒寢度年年。"]'),
('f11eea14-3026-41e3-a3ad-dc07b22de2cf','山居詩  其二四','釋延壽','宋','宋诗','song-poetry','','[]','危嶺如登百尺樓，千般異景望中收。',64,'全唐诗/poet.song.0.json','["危嶺如登百尺樓，千般異景望中收。", "浮生但向忙時過，萬事須從靜處休。", "道直豈教容鬼怪，理平唯祇使魔愁。", "空門莫說無知己，滿目松蘿是我儔。"]'),
('a766c2d4-5dda-4249-8556-916ed83b9eeb','山居詩  其二五','釋延壽','宋','宋诗','song-poetry','','[]','巨侵層巒本自平，只緣人世强分明。',64,'全唐诗/poet.song.0.json','["巨侵層巒本自平，只緣人世强分明。", "五侯門外悲觀意，長樂坡頭去住情。", "學道不如忘有念，修身爭是了無生。", "三祗功業猶難及，誰信塵勞直下明。"]'),
('352ebe28-a598-4c28-8e66-929f9a02b2b6','山居詩  其二六','釋延壽','宋','宋诗','song-poetry','','[]','霧鎖烟霾宴寂堂，含虛凝綠水雲鄉。',64,'全唐诗/poet.song.0.json','["霧鎖烟霾宴寂堂，含虛凝綠水雲鄉。", "搜玄偈裏真風遠，招隠詩中野思長。", "真柏最宜堆厚雪，危花終怯下輕霜。", "滔滔一點無依處，舉足方知盡道場。"]'),
('21da8bff-90e1-4a41-96e9-b5b1e23b63ae','山居詩  其二七','釋延壽','宋','宋诗','song-poetry','','[]','投足烟巒養病軀，馳求終是用工夫。',64,'全唐诗/poet.song.0.json','["投足烟巒養病軀，馳求終是用工夫。", "千般有作皆從智，萬種無依自合愚。", "意地已拋塵事業，心田唯種稻根株。", "非時免見千人世，野食山袍自有謨。"]'),
('0c665928-8ef6-48c1-99d9-8a83a9fb4e08','山居詩  其二八','釋延壽','宋','宋诗','song-poetry','','[]','急景韶顔不可追，豈堪回首暫思之。',64,'全唐诗/poet.song.0.json','["急景韶顔不可追，豈堪回首暫思之。", "浮雲已斷平生望，高節須存往日期。", "庭樹任猿偷熟果，崖松停鶴惜高枝。", "輪蹄碌碌何時歇，輾盡紅塵爲阿誰。"]'),
('9b1c3f7f-08ed-412c-a1cc-09fa0e556eef','山居詩  其二九','釋延壽','宋','宋诗','song-poetry','','[]','幽棲豈可事徒然，晝諷蓮經夜坐禪。',64,'全唐诗/poet.song.0.json','["幽棲豈可事徒然，晝諷蓮經夜坐禪。", "吟裏有聲皆實相，定中無境不虛玄。", "直教似月臨千界，還遣如空度萬緣。", "從此必知宏此志，免教虛擲愧前賢。"]'),
('c0258a90-ecec-48f8-b803-09f9f8d1a269','山居詩  其三○','釋延壽','宋','宋诗','song-poetry','','[]','何如深谷一遺人，宴坐經行不累身。',64,'全唐诗/poet.song.0.json','["何如深谷一遺人，宴坐經行不累身。", "廢宅可嗟頻換主，凋叢愁見幾迴春。", "尖尖石笑烟籠碧，點點苔錢雨洗新。", "堪笑古人非我意，居山多是避强秦。"]'),
('7883d06b-9bef-4739-a63f-9f8b791c8e2a','山居詩  其三一','釋延壽','宋','宋诗','song-poetry','','[]','有山有水更何憂，知足能令萬事休。',64,'全唐诗/poet.song.0.json','["有山有水更何憂，知足能令萬事休。", "大道不從心外得，浮榮須向世閒求。", "衝開烟縷飛黄鳥，點破潭心瀁白鷗。", "好景盡歸余掌握，豈勞艱險訪瀛洲。"]'),
('caff9c41-86e1-4166-8510-97c55b3795c6','山居詩  其三二','釋延壽','宋','宋诗','song-poetry','','[]','萬事從來祇自招，安危由己路非遥。',64,'全唐诗/poet.song.0.json','["萬事從來祇自招，安危由己路非遥。", "笙歌韻裏花先落，松檜枝閒雲未消。", "數下磬聲孤月夜，一爐香翥白雲朝。", "誰人會我高樓意，門掩空庭思寂寥。"]'),
('14c0d2fe-cd0d-4bc0-b902-f5bd5d555657','山居詩  其三三','釋延壽','宋','宋诗','song-poetry','','[]','萬象從來一徑通，但緣分別便西東。',64,'全唐诗/poet.song.0.json','["萬象從來一徑通，但緣分別便西東。", "遺簪祇爲情難盡，泣路方知意未窮。", "偃仰不拋青嶂裏，往來多在白雲中。", "平生分野應難比，澗飲林棲得古風。"]'),
('6ec6af59-6628-44aa-963c-3774b5f4dc67','山居詩  其三四','釋延壽','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','遁逸從來格自高，莫將泰嶽比秋毫。',64,'全唐诗/poet.song.0.json','["遁逸從來格自高，莫將泰嶽比秋毫。", "冷烟寒月真吾侶，瘦竹蒼松是我曹。", "霜樹葉疏幽徑出，雲泉聲急曉風高。", "唯當話道閒吟外，時得工夫補毳袍。"]'),
('522e3fbb-53e3-48ae-a911-2afc8fbbd163','山居詩  其三五','釋延壽','宋','宋诗','song-poetry','','[]','任運騰騰無所依，閒游長坐性怡怡。',64,'全唐诗/poet.song.0.json','["任運騰騰無所依，閒游長坐性怡怡。", "疏林不遣閒人到，密意多應夜月知。", "驟雨過時苔路滑，撥雲行處石橋危。", "塵沙劫盡清風在，何假虛名上古碑。"]'),
('c5001c22-037a-4e64-865e-3306ade1716d','山居詩  其三六','釋延壽','宋','宋诗','song-poetry','','[]','抱拙藏鋒過暮年，高名何必指前賢。',64,'全唐诗/poet.song.0.json','["抱拙藏鋒過暮年，高名何必指前賢。", "祇於心上標空界，誰說壺中別有天。", "鬰密遠林停宿霧，蕭騷疏竹埽寒烟。", "從茲不更移瓶錫，身外無餘意了然。"]'),
('aa29c64f-94fd-4d9d-bf36-4700694e1188','山居詩  其三七','釋延壽','宋','宋诗','song-poetry','','[]','息業怡神道最孤，藏名匿跡合良圖。',64,'全唐诗/poet.song.0.json','["息業怡神道最孤，藏名匿跡合良圖。", "冥心難使龍神見，出語須教海嶽枯。", "雲駐庵前疑有意，鳥鳴庭際似相呼。", "資持隨分安排了，最急應須與道俱。"]'),
('87278a67-3451-4b9f-a1ee-863560a54f52','山居詩  其三八','釋延壽','宋','宋诗','song-poetry','','[]','松陰疏冷罩寒門，靜見吾宗已絕論。',64,'全唐诗/poet.song.0.json','["松陰疏冷罩寒門，靜見吾宗已絕論。", "驅得萬途歸理窟，更無一事出心源。", "烟雲忽閉巖前洞，鷄犬時聞嶺下村。", "放曠本來無別意，免教停海起波痕。"]'),
('41d0515c-1b2a-4cd5-99fc-0a543f463a1a','山居詩  其三九','釋延壽','宋','宋诗','song-poetry','','[]','景虛情澹兩何依，抱一冥真絕萬機。',64,'全唐诗/poet.song.0.json','["景虛情澹兩何依，抱一冥真絕萬機。", "松韻餘風凉竹戶，柏摇殘露溼禪衣。", "巖燈霧逼寒光小，石像塵昏古畫微。", "得趣了然無所慮，任緣終日送斜暉。"]'),
('e13be8f5-d458-4957-8f20-bfed13df59eb','山居詩  其四○','釋延壽','宋','宋诗','song-poetry','','[]','遁迹無圖匿姓名，萬重山後葺茅亭。',64,'全唐诗/poet.song.0.json','["遁迹無圖匿姓名，萬重山後葺茅亭。", "隨情因事搜新偈，探妙窮微閱古經。", "與道交時心絕念，從緣感處物通靈。", "應須長遠存高節，屹屹喬松老更青。"]'),
('505c59be-e316-4115-a386-042209178afb','山居詩  其四一','釋延壽','宋','宋诗','song-poetry','','[]','閒思塵世大悠哉，進趣門中盡可該。',64,'全唐诗/poet.song.0.json','["閒思塵世大悠哉，進趣門中盡可該。", "拋却工夫平世路，枉勞心力搆僊臺。", "隘空雲水千重合，帀野烟霞一徑開。", "幸有圓成平坦處，辛勤誰解望山來。"]'),
('80d82618-941d-46d5-b93d-3293a3585855','山居詩  其四二','釋延壽','宋','宋诗','song-poetry','','[]','千途盡向空源出，萬景終歸一路通。',64,'全唐诗/poet.song.0.json','["千途盡向空源出，萬景終歸一路通。", "忽爾有心成大患，坦然無事却全功。", "春開小岫調新綠，水漾漂霞蘸晚紅。", "莫道境緣能幻惑，達來何處不消融。"]'),
('2b449f1c-989c-47f5-ac53-1b1c66acc491','山居詩  其四三','釋延壽','宋','宋诗','song-poetry','','[]','身心閒後思怡然，緬想難忘契道言。',64,'全唐诗/poet.song.0.json','["身心閒後思怡然，緬想難忘契道言。", "千種却教歸淡薄，萬般須是到根源。", "疏疏雨趁歸巢鳥，密密烟藏抱子猿。", "禪罷吟來無一事，遠山驅景入茅軒。"]'),
('35674b93-129e-4cf4-9ca3-6008186c142e','山居詩  其四四','釋延壽','宋','宋诗','song-poetry','','[]','萬境閒來情澹澹，羣囂息後思微微。',64,'全唐诗/poet.song.0.json','["萬境閒來情澹澹，羣囂息後思微微。", "當時白業無門入，今日玄關有路歸。", "熟果不摇翻自落，生禽誰喚却驚飛。", "到頭何用空忙得，任運應須待對機。"]'),
('69fd08e6-c2c0-4200-85d8-ae19fdb91b0f','山居詩  其四五','釋延壽','宋','宋诗','song-poetry','','[]','携筇閒步望山行，竟日逍遥任野情。',64,'全唐诗/poet.song.0.json','["携筇閒步望山行，竟日逍遥任野情。", "上嶺梯登危石側，渡溪橋踏古槎橫。", "綠羅水皺巖根急，紅錦霞舒海面明。", "一軸詠懷高尚意，援毫因事偶吟成。"]'),
('d623038a-edc2-4a1e-a0fa-8783e1cf18bf','山居詩  其四六','釋延壽','宋','宋诗','song-poetry','','[]','負氣爭權事可悲，金貂繡轂盡何之。',64,'全唐诗/poet.song.0.json','["負氣爭權事可悲，金貂繡轂盡何之。", "唯聞野棘盤荒冢，祇見空陵疊壞碑。", "燈暗竹堂行道夜，烟昏石窟坐禪時。", "怡然自得真棲處，何用經營別路岐。"]'),
('14f754f3-513c-4047-9afa-d57e12694117','山居詩  其四七','釋延壽','宋','宋诗','song-poetry','','[]','豪貴從他縱勝遊，多歡終是復多愁。',64,'全唐诗/poet.song.0.json','["豪貴從他縱勝遊，多歡終是復多愁。", "茅茨舍宇偏安穩，糞埽衣裳最自由。", "數片雲飛書案上，一條泉路卧床頭。", "分明自有安身處，爭柰人閒不肯休。"]'),
('aada7b9c-bf35-4f20-b8a3-e3357b8426f4','山居詩  其四八','釋延壽','宋','宋诗','song-poetry','','[]','高才宏略氣凌雲，世上浮名夢裏身。',64,'全唐诗/poet.song.0.json','["高才宏略氣凌雲，世上浮名夢裏身。", "蘇氏謾稱降六國，韓公休說捲三秦。", "當朝雖立千年事，古廟唯存一聚塵。", "畢竟思量渾大錯，何如林下養天真。"]'),
('69c718e3-ccca-49df-9022-ecbf6b9abc8d','山居詩  其四九','釋延壽','宋','宋诗','song-poetry','','[]','高懷怡淡景相和，纔到塵途事便多。',64,'全唐诗/poet.song.0.json','["高懷怡淡景相和，纔到塵途事便多。", "碧嶂好期長定計，朱門唯見暫時過。", "雄雄負氣爭權路，岌岌新墳占野坡。", "成敗分明剛不悟，未知凡俗意如何。"]'),
('de9e95b9-502a-407b-a25e-3ea03d7d4344','山居詩  其五○','釋延壽','宋','宋诗','song-poetry','','[]','得理元來行自成，萬般情斷一心冥。',64,'全唐诗/poet.song.0.json','["得理元來行自成，萬般情斷一心冥。", "樵人不到緣山僻，遊客難逢爲嶽靈。", "食蘗苦心何日就，看花醉眼幾時醒。", "索然身外無餘物，雲滿前山水滿瓶。"]'),
('95357ce6-06bb-47da-90e4-9fda84c91d6a','山居詩  其五一','釋延壽','宋','宋诗','song-poetry','','[]','名利梯媒事已忘，唯憑拙直定行藏。',64,'全唐诗/poet.song.0.json','["名利梯媒事已忘，唯憑拙直定行藏。", "探玄休煉長生藥，助道時抄歇食方。", "溪汲古痕山雨漲，樹摧殘枿野風狂。", "一言欲寄休回首，塵路如今事正忙。"]'),
('5484d4d6-4177-4c0c-a78f-462883a90db2','山居詩  其五二','釋延壽','宋','宋诗','song-poetry','','[]','豈是疏慵僻愛山，且圖餘事不相關。',64,'全唐诗/poet.song.0.json','["豈是疏慵僻愛山，且圖餘事不相關。", "休誇鳳詔千年貴，難敵禪扉半日閒。", "透水戲魚隨浪沒，投巢孤鶴带雲還。", "自然得到無心地，寂寂虛堂一景閒。"]'),
('12ead692-5b80-43f9-92b5-9793355b7e37','山居詩  其五三','釋延壽','宋','宋诗','song-poetry','','[]','林下安身別有方，營營何太路岐忙。',64,'全唐诗/poet.song.0.json','["林下安身別有方，營營何太路岐忙。", "侯門夢過光陰促，禪室玄棲氣味長。", "引水灌花春日媚，移松夾道暑天凉。", "銜恩略報元功處，一炷晨風散後香。"]'),
('6cb35d7c-0ad9-4b24-8642-0afb38786d3f','山居詩  其五四','釋延壽','宋','宋诗','song-poetry','','[]','萬般惟道最堪依，一瞬榮枯萬古悲。',64,'全唐诗/poet.song.0.json','["萬般惟道最堪依，一瞬榮枯萬古悲。", "强笑低顔何忽忽，忘機絕慮自怡怡。", "潛龍終要投深浦，巢鳥應須占健枝。", "名利門中難立足，隠藏雲水更何之。"]'),
('dfced579-439d-402e-93e6-08e76d778b63','山居詩  其五五','釋延壽','宋','宋诗','song-poetry','','[]','退跡何人繼昔賢，凡途終是事謀先。',64,'全唐诗/poet.song.0.json','["退跡何人繼昔賢，凡途終是事謀先。", "只知競逐浮雲富，誰解驚嗟逝水年。", "寒影半疏霜後樹，秋聲千點雨中禪。", "千般不更經營得，一榻無餘任自然。"]'),
('43d841c7-7b80-4cf4-b530-05e95ed4b9e0','山居詩  其五六','釋延壽','宋','宋诗','song-poetry','','[]','野景陶情皆得意，凡夫舉目盡堪愁。',64,'全唐诗/poet.song.0.json','["野景陶情皆得意，凡夫舉目盡堪愁。", "秦川幾度埋番骨，棘路還曾聳玉樓。", "幻體不知波上沫，狂心須認鏡中頭。", "浮生役役貪榮者，求到真空卒未休。"]'),
('4bd2ca53-c71d-45e0-aaf6-41d5a4a13d55','山居詩  其五七','釋延壽','宋','宋诗','song-poetry','','[]','一生占斷白雲鄉，適意孤高志自强。',64,'全唐诗/poet.song.0.json','["一生占斷白雲鄉，適意孤高志自强。", "報曉音聲棲鳥語，漏春消息早梅香。", "吟經徐傍芙蕖岸，得偈閒書薜荔牆。", "大道最親無達者，苦携瓶錫叩禪堂。"]'),
('2b0641af-63b7-4b29-a7c2-737f29b1c673','山居詩  其五八','釋延壽','宋','宋诗','song-poetry','','[]','養性攄情不記年，免尋雲水更參禪。',64,'全唐诗/poet.song.0.json','["養性攄情不記年，免尋雲水更參禪。", "有心用處還應錯，無意看時却宛然。", "析法尚嫌灰斷果，燒丹堪愍地行仙。", "欲知此理誰人會，水自朝東月自圓。"]'),
('9c7f08fe-bcdf-497f-a988-85b892d84834','山居詩  其五九','釋延壽','宋','宋诗','song-poetry','','[]','世途從此免相關，萬慮潛消野思閒。',64,'全唐诗/poet.song.0.json','["世途從此免相關，萬慮潛消野思閒。", "菴樹逼春花自吐，巖巢欲暮鳥空還。", "門前霧閉疑無路，檻外雲開忽有山。", "宴坐石巖樵徑絕，姓名應不到人閒。"]'),
('a6b3696a-18dc-4654-9645-476928184fa7','山居詩  其六○','釋延壽','宋','宋诗','song-poetry','','[]','獨行獨坐任天然，幽隠難逢世網牽。',64,'全唐诗/poet.song.0.json','["獨行獨坐任天然，幽隠難逢世網牽。", "一志直教齊大道，萬般總是涉因緣。", "水磨澗石平如鏡，春引巖藤直似弦。", "虛幻已知休更續，蹄輪應不到山前。"]'),
('ceb5a348-6bdb-43c6-af5b-5083884617bf','山居詩  其六一','釋延壽','宋','宋诗','song-poetry','','[]','散誕疏狂得自然，免教拘迫事相牽。',64,'全唐诗/poet.song.0.json','["散誕疏狂得自然，免教拘迫事相牽。", "潛龍不離滔滔水，孤鶴唯宜遠遠天。", "透室寒光松檻月，逼人凉氣石渠泉。", "非吾獨了西來意，竹祖桐孫盡入玄。"]'),
('eefb6d3e-360d-4953-9879-0ef9457ef0c3','山居詩  其六二','釋延壽','宋','宋诗','song-poetry','','[]','綠柳堤邊春色多，數樹重重裊翠蘿。',64,'全唐诗/poet.song.0.json','["綠柳堤邊春色多，數樹重重裊翠蘿。", "紅白花枝爭鬭發，晴陰天氣半相和。", "中山謾醉千壺酒，易水徒悲一曲歌。", "塵世無憑唯道外，榮枯瞬息盡消磨。"]'),
('90cdaad0-5f60-4d40-a142-bdaea1cd78a0','山居詩  其六三','釋延壽','宋','宋诗','song-poetry','','[]','清平大業行皆奢，豈獨堯時聽所加。',64,'全唐诗/poet.song.0.json','["清平大業行皆奢，豈獨堯時聽所加。", "豐儉由人天不遠，安危在智道非賒。", "關津防害翻爲害，法令除邪却長邪。", "爭似無言敷密化，既能成國又成家。"]'),
('715c2fb3-0908-4b0a-bbb5-b5d2f27597d0','山居詩  其六四','釋延壽','宋','宋诗','song-poetry','','[]','焦翼枯鱗成底事，分明可驗莫愁哉。',64,'全唐诗/poet.song.0.json','["焦翼枯鱗成底事，分明可驗莫愁哉。", "君恩只可量功受，世利應須任運來。", "豈信敗從成處得，誰知榮是辱邊媒。", "但看越分殊求者，唯向身中積禍胎。"]'),
('5e1af038-e17f-4f46-b3b8-c8a217d1d0e5','山居詩  其六五','釋延壽','宋','宋诗','song-poetry','','[]','棲真境界太玄鄉，靜見吾宗不可量。',64,'全唐诗/poet.song.0.json','["棲真境界太玄鄉，靜見吾宗不可量。", "好句祇憑詩斷送，閒緣唯遣道消亡。", "雨絲雲織輕條密，烟素風抽細縷長。", "竟日虛懷無一事，金瓶秋水石爐香。"]'),
('afc85ff8-e076-431a-b703-430dba6f9d98','山居詩  其六六','釋延壽','宋','宋诗','song-poetry','','[]','得喪從來事甚均，任緣徒用苦勞神。',64,'全唐诗/poet.song.0.json','["得喪從來事甚均，任緣徒用苦勞神。", "野蔬隨分堪充口，石室依稀可庇身。", "碧海幾時無去棹，紅衢何日息征輪。", "若教求道如求利，舉世渾成無事人。"]'),
('c5f635a2-182f-4d1b-a653-176bde7e57da','山居詩  其六七','釋延壽','宋','宋诗','song-poetry','','[]','數朝興廢狂風過，千載榮枯掣電飛。',64,'全唐诗/poet.song.0.json','["數朝興廢狂風過，千載榮枯掣電飛。", "早向權門思息意，莫於塵世自沈機。", "一條水引閒花出，萬里雲隨獨鶴歸。", "最要身安成大道，免教他後始知非。"]'),
('523f4597-231d-43bb-abc8-812ddf102375','山居詩  其六八','釋延壽','宋','宋诗','song-poetry','','[]','幽棲带郭半山峰，密意虛懷莫可同。',64,'全唐诗/poet.song.0.json','["幽棲带郭半山峰，密意虛懷莫可同。", "事到定中消息靜，景於吟處煉磨空。", "玲瓏色淡松根月，敲磕聲清竹罅風。", "獨坐獨行誰會我，羣星朝北水朝東。"]'),
('c4045b45-8abe-4430-aa17-309df670dd22','山居詩  其六九','釋延壽','宋','宋诗','song-poetry','','[]','三度曾經遊此地，從緣權順世閒情。',64,'全唐诗/poet.song.0.json','["三度曾經遊此地，從緣權順世閒情。", "登山雖有謝安志，遁迹慚無慧遠名。", "翠疊寒枝松未老，影深幽徑竹新成。", "莫言去住關懷抱，雲本無心水自清。"]'),
('18f949d7-0fa1-4d7c-8a41-8ea2f332ef35','偈一首','釋延壽','宋','宋诗','song-poetry','','[]','欲識永明旨，門前一湖水。',24,'全唐诗/poet.song.0.json','["欲識永明旨，門前一湖水。", "日照光明生，風來波浪起。"]'),
('1415febf-ba51-4ad9-9075-ff34eb160644','金鷄峰','釋延壽','宋','宋诗','song-poetry','','[]','松蘿高鎮夏長寒，透出羣峰畫恐難。',32,'全唐诗/poet.song.0.json','["松蘿高鎮夏長寒，透出羣峰畫恐難。", "造化功成彰五德，洞天雲散露花冠。"]'),
('b769e594-e19b-4cc5-b6c9-d0f72461fe75','蛾眉峰','釋延壽','宋','宋诗','song-poetry','','[]','盤空勢險露巖根，深洞聲寒落石泉。',32,'全唐诗/poet.song.0.json','["盤空勢險露巖根，深洞聲寒落石泉。", "好是雨餘江上見，水雲僧出認西天。"]'),
('ef4732e7-64b6-49b5-9a52-3b30daf137a8','積翠峰','釋延壽','宋','宋诗','song-poetry','','[]','翠壓羣峰地形直，落日猿聲在空碧。',32,'全唐诗/poet.song.0.json','["翠壓羣峰地形直，落日猿聲在空碧。", "天風吹散斷崖雲，古松長露三秋色。"]'),
('dc0aacf6-3e95-4aae-b386-92b3e1cae59e','凌雲峰','釋延壽','宋','宋诗','song-poetry','','[]','烟蘿高巘勢凌雲，影瀉斜陽出海門。',32,'全唐诗/poet.song.0.json','["烟蘿高巘勢凌雲，影瀉斜陽出海門。", "曾與支公探隠去，夜寒雷雨上方聞。"]'),
('8d752220-3347-4c64-a01b-4c487131cffe','白馬峰','釋延壽','宋','宋诗','song-poetry','','[]','湖外層峰瀉危瀑，天際陰陰長寒木。',32,'全唐诗/poet.song.0.json','["湖外層峰瀉危瀑，天際陰陰長寒木。", "南北行人望莫窮，秋雲一片橫幽谷。"]'),
('b6aabf10-4b90-4216-b9d8-86b76cf28ecf','偈一首','釋延壽','宋','宋诗','song-poetry','','[]','孤猿叫落中巖月，野客吟殘半夜燈。',32,'全唐诗/poet.song.0.json','["孤猿叫落中巖月，野客吟殘半夜燈。", "此境此時誰會意，白雲深處坐禪僧。"]'),
('f5d93305-1356-447d-8817-90515f7519f5','舟中','釋延壽','宋','宋诗','song-poetry','','[]','一水浮千棹，悠悠來去人。',48,'全唐诗/poet.song.0.json','["一水浮千棹，悠悠來去人。", "纜開湘浦岸，帆落楚江濱。", "風色東西變，潮痕旦暮新。", "祗茲澄漢色，幾度化爲塵。"]'),
('8026338a-472e-405a-a820-f9faacb60a61','閒居','釋延壽','宋','宋诗','song-poetry','','[]','閒居誰似我，退跡理難過。',48,'全唐诗/poet.song.0.json','["閒居誰似我，退跡理難過。", "要勢危身早，浮榮敗德多。", "雨催蟲出穴，寒逼鳥移窠。", "野逕無人翦，疏窗入薜蘿。"]'),
('9346fa00-cf2a-4d7e-bdd2-471999240ced','野遊','釋延壽','宋','宋诗','song-poetry','','[]','獨步出衡茅，寒雲著地交。',24,'全唐诗/poet.song.0.json','["獨步出衡茅，寒雲著地交。", "燒平多敗穴，葉落見危巢。"]'),
('bac56787-3e55-4223-9870-a395dd117efd','同于秘丞賦瀑泉','釋延壽','宋','宋诗','song-poetry','','[]','大禹不知鑿，來源亦自成。',48,'全唐诗/poet.song.0.json','["大禹不知鑿，來源亦自成。", "色應憐衆白，聲合讓孤清。", "遠勢曾吞海，飛流欲噴鯨。", "靈槎如可泛，天際問歸程。"]'),
('3fd6f954-f93c-46f1-963b-42d80a8b2eb2','武肅王有旨石橋設齋會進一詩  其一','釋延壽','宋','宋诗','song-poetry','','[]','南有天台事可尊，孕靈含秀獨超羣。',64,'全唐诗/poet.song.0.json','["南有天台事可尊，孕靈含秀獨超羣。", "重重曲澗侵危石，步步層巖踏碎雲。", "金雀每從雲裏現，異香多向夜深聞。", "當知此界非凡界，一道幽奇各自分。"]'),
('20d368f8-e5a0-464f-8f59-a1054ac13177','武肅王有旨石橋設齋會進一詩  其二','釋延壽','宋','宋诗','song-poetry','','[]','仙源佛窟有天台，今古嘉名遍九垓。',64,'全唐诗/poet.song.0.json','["仙源佛窟有天台，今古嘉名遍九垓。", "石磴嵌空神匠出，瀑泉雄壯雨聲來。", "景强偏感高僧住，地勝能令遠思開。", "一等翹誠依此處，自然靈貺作梯媒。"]'),
('9e38238c-c231-44b3-b1ac-2a41f3bbac1d','武肅王有旨石橋設齋會進一詩  其三','釋延壽','宋','宋诗','song-poetry','','[]','智泉福海莫能逾，親自王恩運睿謨。',64,'全唐诗/poet.song.0.json','["智泉福海莫能逾，親自王恩運睿謨。", "感現盡冥心境界，資持全固道根株。", "石梁低翥紅鸚鵡，烟嶺高翔碧鷓鴣。", "勝妙重重惟禱祝，永資軍庶息災虞。"]'),
('0b0b6a80-cd8c-4ff2-9d76-2551ea8a0c08','武肅王有旨石橋設齋會進一詩  其四','釋延壽','宋','宋诗','song-poetry','','[]','凌晨迎請倍精誠，親敬鮮花異處清。',64,'全唐诗/poet.song.0.json','["凌晨迎請倍精誠，親敬鮮花異處清。", "羅漢攀枝呈梵相，巖僧倚樹現真形。", "神幡雙出紅霞動，寶塔全開白氣生。", "都爲王心標意切，滿空盈月瑞分明。"]'),
('13ae65f6-f088-452b-96d2-0c49f0885c74','武肅王有旨石橋設齋會進一詩  其五','釋延壽','宋','宋诗','song-poetry','','[]','幡花寶蓋滿清川，祈禱迎來聖半千。',64,'全唐诗/poet.song.0.json','["幡花寶蓋滿清川，祈禱迎來聖半千。", "莫道聖緣無影響，須知嘉會有因緣。", "空中長似聞天樂，巖畔嘗疑有地仙。", "何必更尋兜率去，重重靈應事昭然。"]'),
('8c90f2f0-6257-4410-baf1-e676f5fc33e4','武肅王有旨石橋設齋會進一詩  其六','釋延壽','宋','宋诗','song-poetry','','[]','登雲步嶺涉烟程，好景隨心次第生。',64,'全唐诗/poet.song.0.json','["登雲步嶺涉烟程，好景隨心次第生。", "聖者已符祥瑞事，地靈全副禱祈情。", "洞深重疊拖雲濕，灘淺潺湲漱水清。", "願滿事圓歸去路，便風相送片帆輕。"]'),
('232e6cf6-4890-4f3c-8a41-bec337fe8b7f','定慧相資歌','釋延壽','宋','宋诗','song-poetry','','[]','祖教宗中有二門，十度萬行稱爲尊。',368,'全唐诗/poet.song.0.json','["祖教宗中有二門，十度萬行稱爲尊。", "初名止觀助新學，後成定慧菩提根。", "唯一法，似雙分。", "法性寂然體真止，寂而常照妙觀存。", "定爲父，慧爲母，能孕千聖之門戶。", "增長根力養聖胎，念念出生成佛祖。", "定爲將，慧爲相，能弼心王成無上。", "永作羣生證道門，即是古佛菩提樣。", "定如月，光爍外道邪星滅。", "能挑智炬轉分明，滋潤道芽除愛結。", "慧如日，照破無明之暗室。", "能令邪見愚夫禪，盡成般若波羅蜜。", "少時默，剎那靜，漸漸增修成正定。", "諸聖較量功不多，終見靈臺之妙性。", "瞥聞法，纔歷耳，能熏識藏覺種起。", "一念回光正智開，須臾成佛法如是。", "禪定力，不思義，變凡爲聖剎那時。", "無邊生死根由斷，積劫塵勞巢穴墮。", "湛心水，浄意珠，光吞萬象爍千途。", "抉開己眼無瑕翳，三界元無一法拘。", "覺觀賊，應時剋，攀援病，倏然浄。", "蕩念垢兮洗惑塵，顯法身兮堅慧命。", "如斷山，若停海，天翻地覆終無改。", "瑩似琉璃含寶月，倏然無寄而無待。"]'),
('c7a49aee-3848-40f8-9c0e-5a4ae338b58b','句  其一','釋延壽','宋','宋诗','song-poetry','','[]','步步寒華結，言言徹底冰。',12,'全唐诗/poet.song.0.json','["步步寒華結，言言徹底冰。"]'),
