('01348b48-eb4e-4f3e-baa6-d3e8ddc5e167','贈顔詡','孟賓于','宋','宋诗','song-poetry','','[]','園林蕭爽聞來久，欲訪因循二十秋。',32,'全唐诗/poet.song.0.json','["園林蕭爽聞來久，欲訪因循二十秋。", "此日開襟吟不盡，碧山重疊水長流。"]'),
('80f3fbc3-77c6-42a8-86aa-bea8cfc9380a','獻主司','孟賓于','宋','宋诗','song-poetry','','[]','那堪雨後更聞蟬，溪隔重湖路七千。',32,'全唐诗/poet.song.0.json','["那堪雨後更聞蟬，溪隔重湖路七千。", "憶昔故園楊柳岸，全家送上渡頭船。"]'),
('47e446d9-e54e-4085-b8d5-400ffd37ede9','磻溪懷古','孟賓于','宋','宋诗','song-poetry','','[]','良哉呂尚父，深隠始歸周。',48,'全唐诗/poet.song.0.json','["良哉呂尚父，深隠始歸周。", "釣石千年在，春風一水流。", "松根盤蘚石，花影卧沙鷗。", "誰更懷韜術，追思古渡頭。"]'),
('9f2fe972-97a6-4984-9071-736619042fc2','懷連上舊居','孟賓于','宋','宋诗','song-poetry','','[]','閒思連上景難齊，樹遶仙鄉路遶溪。',64,'全唐诗/poet.song.0.json','["閒思連上景難齊，樹遶仙鄉路遶溪。", "明月夜舟漁父唱，春風平野鷓鴣啼。", "城邊寄信歸雲外，花下傾盃到日西。", "更憶海陽垂釣侶，昔年相遇草萋萋。"]'),
('76d0adc1-8ef9-4a57-9841-0946d451ac80','第四舉','孟賓于','宋','宋诗','song-poetry','','[]','失意從他桃李春，嵩陽經過歇行塵。',32,'全唐诗/poet.song.0.json','["失意從他桃李春，嵩陽經過歇行塵。", "雲僧不見城中事，問是今年第幾人。"]'),
('d22c4244-85a2-4278-9db9-b278f7558f48','題梅仙館','孟賓于','宋','宋诗','song-poetry','','[]','仙界路遥雲縹緲，古壇風冷葉蕭騷。',32,'全唐诗/poet.song.0.json','["仙界路遥雲縹緲，古壇風冷葉蕭騷。", "後來豈合言淹滯，一尉昇騰道最高。"]'),
('e851cc90-c993-4b30-8738-c28c7a3f4c13','公子行','孟賓于','宋','宋诗','song-poetry','','[]','錦衣紅奪彩霞明，侵曉春遊向野庭。',32,'全唐诗/poet.song.0.json','["錦衣紅奪彩霞明，侵曉春遊向野庭。", "不識農夫辛苦力，驕驄踏爛麥青青。"]'),
('de424fd1-083e-4f71-8a67-a6bbf8b24c27','晚眺','孟賓于','宋','宋诗','song-poetry','','[]','倚杖殘秋裏，吟中四顧頻。',48,'全唐诗/poet.song.0.json','["倚杖殘秋裏，吟中四顧頻。", "西風天際雁，落日渡頭人。", "草色衰平野，山陰歛暮塵。", "却尋苔徑去，明月照村鄰。"]'),
('d498fb91-2896-44b9-867e-b9f9b91af4a5','湘江亭','孟賓于','宋','宋诗','song-poetry','','[]','獨宿大中年裏寺，樊籠得出事無心。',32,'全唐诗/poet.song.0.json','["獨宿大中年裏寺，樊籠得出事無心。", "寒山夢覺一聲磬，霜葉滿林秋正深。"]'),
('c73b151d-2012-41aa-bcd9-6705ff87d52d','耒陽杜工部祠堂','孟賓于','宋','宋诗','song-poetry','','[]','南遊何感思，更甚葉繽紛。',48,'全唐诗/poet.song.0.json','["南遊何感思，更甚葉繽紛。", "一夜耒江雨，百年工部文。", "青山當日見，白酒至今聞。", "惟有爲詩者，經過時弔君。"]'),
