('4a4420a6-0721-4962-bc00-a9a58eba9ddb','寄贈宣義大師','賈玭','宋','宋诗','song-poetry','','[]','篆寫千文邁古今，感陶承旨撰碑陰。',64,'全唐诗/poet.song.0.json','["篆寫千文邁古今，感陶承旨撰碑陰。", "兩朝雨露書中得，滿篋詩章物外尋。", "衡嶽水雲長挂夢，帝城烟月不關心。", "西遊去後無消息，想共陳摶一處吟。"]'),
('569b5979-ba22-4ce1-b8c4-19918b074dea','贈夢英大師','郭從義','宋','宋诗','song-poetry','','[]','水僧來說我師，換鵝書札轉高奇。',63,'全唐诗/poet.song.0.json','["水僧來說我師，換鵝書札轉高奇。", "揮毫傳下千年字，貞石曾留幾處碑。", "混俗市廛人莫測，和光蹤跡鶴應知。", "蓮花結社須容我，不似陶潛愛濕巵。"]'),
('804ce661-6ffa-4791-aa3f-a43877d39723','戲周默','宋溫故','宋','宋诗','song-poetry','','[]','驕陽爲戾已成災，頼有開筵周秀才。',32,'全唐诗/poet.song.0.json','["驕陽爲戾已成災，頼有開筵周秀才。", "莫道上天無感應，故教風雨一齊來。"]'),
('5c781bb8-c50a-41d1-99be-232fd4ed4a62','送孟賓于','馬致恭','宋','宋诗','song-poetry','','[]','曾聞洛下綴神仙，火樹南棲幾十年。',64,'全唐诗/poet.song.0.json','["曾聞洛下綴神仙，火樹南棲幾十年。", "白首自忻丹桂在，詩名已得四方傳。", "行隨秋渚將歸雁，吟傍梅花欲雪天。", "今日還家莫惆悵，不同初上渡頭船。"]'),
('2a3d9878-990e-4711-9fd6-84a6059f076e','塞上  其一','譚用之','宋','宋诗','song-poetry','','[]','秋風漢北雁飛天，單騎那堪遶賀蘭。',64,'全唐诗/poet.song.0.json','["秋風漢北雁飛天，單騎那堪遶賀蘭。", "磧暗更無巖樹影，地平時有野燒瘢。", "貂披寒色和衣冷，劍佩胡霜隔匣寒。", "早晚橫戈似飛尉，擁旄深入異田單。"]'),
('1a76ec8f-54ca-42e6-a3e9-3dc42caf0f01','塞上  其二','譚用之','宋','宋诗','song-poetry','','[]','鉢略城邊日欲西，遊人却憶舊山歸。',64,'全唐诗/poet.song.0.json','["鉢略城邊日欲西，遊人却憶舊山歸。", "牛羊集水烟黏步，鵰鶚盤空雪滿圍。", "獵騎靜逢邊氣薄，戍樓寒對暮烟微。", "橫行總是男兒事，早晚重來似漢飛。"]'),
('02fe3269-0f06-4b1d-826e-1f9f2617bc93','贈索處士','譚用之','宋','宋诗','song-poetry','','[]','不將桂子種諸天，長得尋君水石邊。',64,'全唐诗/poet.song.0.json','["不將桂子種諸天，長得尋君水石邊。", "玄豹夜寒和霧隠，驪龍春暖抱珠眠。", "山中宰相陶弘景，洞裏真人葛稚川。", "一度相思一惆悵，水寒烟澹落花前。"]'),
('2edb670c-ce7d-4992-bf14-9226ab8d3e57','別雒下一二知己','譚用之','宋','宋诗','song-poetry','','[]','金鼎光輝照雪袍，雒陽春夢憶波濤。',64,'全唐诗/poet.song.0.json','["金鼎光輝照雪袍，雒陽春夢憶波濤。", "塵埃滿眼人情異，風雨前程馬足勞。", "接塞峨眉通蜀險，過山仙掌倚秦高。", "別來無限幽求子，應笑區區味六韜。"]'),
('8fb380fe-3a2c-429a-9f07-c61c7ac59033','約張處士遊梁','譚用之','宋','宋诗','song-poetry','','[]','莫學區區老一經，夷門關吏舊書生。',64,'全唐诗/poet.song.0.json','["莫學區區老一經，夷門關吏舊書生。", "晉朝滅後無中散，韓國亡來絕上卿。", "龍變洞中千谷冷，劍橫天外八風清。", "好携長策干時去，免逐漁樵度太平。"]'),
('8617dd2b-a8ce-4c06-be69-b8abe5d0f5b0','送友人歸青社','譚用之','宋','宋诗','song-poetry','','[]','鵰鶚途程在碧天，綵衣東去復何言。',64,'全唐诗/poet.song.0.json','["鵰鶚途程在碧天，綵衣東去復何言。", "二千賓客舊知己，十二山河新故園。", "吟看桂生溪月上，醉聽鯤化海濤翻。", "好期聖代重相見，莫學袁生老竹軒。"]'),
('dc67a3e6-c1f7-483b-a56e-bb68187d1ca9','送丁道士歸南中','譚用之','宋','宋诗','song-poetry','','[]','孤雲無定鶴辭巢，自負焦桐不說勞。',64,'全唐诗/poet.song.0.json','["孤雲無定鶴辭巢，自負焦桐不說勞。", "服藥幾年期碧落，驗符何處呪丹毫。", "子陵山曉紅雲密，青草湖平雪浪高。", "從此人稀見蹤跡，還應選地種仙桃。"]'),
('c217671a-7aac-4b60-9e66-b8b49e527355','月夜懷寄友人','譚用之','宋','宋诗','song-poetry','','[]','劍氣徒勞望斗牛，故人別後阻仙舟。',64,'全唐诗/poet.song.0.json','["劍氣徒勞望斗牛，故人別後阻仙舟。", "殘春謾道深傾酒，好月那堪獨上樓。", "何處是非隨馬足，由來得喪白人頭。", "清風未許重携手，幾度高吟寄水流。"]'),
('7a650ab2-c09f-4573-9bb9-febc1173b0ff','閒居寄陳山人','譚用之','宋','宋诗','song-poetry','','[]','閒居何處得閒名，坐掩衡茅損性靈。',64,'全唐诗/poet.song.0.json','["閒居何處得閒名，坐掩衡茅損性靈。", "破夢曉鐘聞竹寺，沁心秋雨浸莎庭。", "甕邊難負千杯綠，海上終眠萬仞青。", "珍重先生全太古，應看名利似浮雲。"]'),
('1b8027e7-08d7-43d0-8e71-00cfd00aa48e','憶南中','譚用之','宋','宋诗','song-poetry','','[]','碧江頭與白雲門，別後秋霜點鬢根。',64,'全唐诗/poet.song.0.json','["碧江頭與白雲門，別後秋霜點鬢根。", "長記學禪青石寺，最思共醉落花村。", "林間竹有湘妃淚，窗外禽多杜宇魂。", "未棹扁舟重回首，采薇收橘不堪論。"]'),
('83f1431f-2268-47dc-9aea-143e9f5a73c9','寄友人','譚用之','宋','宋诗','song-poetry','','[]','病多慵引架書看，官職無才思已闌。',64,'全唐诗/poet.song.0.json','["病多慵引架書看，官職無才思已闌。", "穴鳳瑞時來却易，人龍別後見何難。", "琴樽風月閒生計，金玉松筠舊歲寒。", "早晚烟村碧江畔，掛罾重對蓼花灘。"]'),
('277b660b-69e3-4934-b711-e38f3bd554dd','別江上一二友生','譚用之','宋','宋诗','song-poetry','','[]','國風千載務重華，須逐浮雲背若耶。',64,'全唐诗/poet.song.0.json','["國風千載務重華，須逐浮雲背若耶。", "無地可歸堪種玉，有天教上且乘槎。", "白綸巾卸蘇門月，紅錦衣裁御苑花。", "他日成都却回首，東山看取謝鯤家。"]'),
('59acb909-bc51-4b86-9207-8c728e494d59','寄岐山林逢吉明府','譚用之','宋','宋诗','song-poetry','','[]','岐山高與隴山連，製錦無私服晏眠。',64,'全唐诗/poet.song.0.json','["岐山高與隴山連，製錦無私服晏眠。", "鸚鵡語中分百里，鳳凰聲裏過三年。", "秦無舊俗雲烟媚，周有遺風父老賢。", "莫役生靈種楊柳，一枝枝折灞橋邊。"]'),
('1b64fbfe-a1ea-4463-ab21-357c23f51dbe','感懷呈所知','譚用之','宋','宋诗','song-poetry','','[]','十年流落賦歸鴻，誰傍昏衢駕燭龍。',64,'全唐诗/poet.song.0.json','["十年流落賦歸鴻，誰傍昏衢駕燭龍。", "竹屋亂烟思梓澤，酒家疏雨夢臨邛。", "千年別恨調琴懶，一片年光覽鏡慵。", "早晚休歌白石爛，放教歸去卧羣峰。"]'),
('bbcf7393-dc50-4c00-a1f5-40d76dd397f5','江上聞笛','譚用之','宋','宋诗','song-poetry','','[]','誰爲梅花怨未平，一聲高喚百龍驚。',64,'全唐诗/poet.song.0.json','["誰爲梅花怨未平，一聲高喚百龍驚。", "風當閶闔庭初靜，月在姑蘇秋正明。", "曲盡綠楊涵野渡，管吹青玉動江城。", "臨流不欲殷勤聽，芳草王孫舊有情。"]'),
('5527ad48-b978-4ec7-b851-1062ccd4d22a','寄孟進士','譚用之','宋','宋诗','song-poetry','','[]','依舊池邊草色芳，故人何處憶山陽。',64,'全唐诗/poet.song.0.json','["依舊池邊草色芳，故人何處憶山陽。", "書回科斗江帆暮，曲罷騶虞海樹蒼。", "吟望曉烟思桂渚，醉衣殘月夢餘杭。", "別來南國知誰在，空對襜褕一斷腸。"]'),
('b69c4a7d-acca-42fe-a257-4e553c58bfa1','寄閻記室','譚用之','宋','宋诗','song-poetry','','[]','織錦歌成下翠微，豈勞西去問搘機。',64,'全唐诗/poet.song.0.json','["織錦歌成下翠微，豈勞西去問搘機。", "未開水府珠先見，不掘豐城劍自輝。", "鼇逐玉蟾攀桂上，馬隨青帝踏花歸。", "相逢半是雲霄客，應笑歌牛一布衣。"]'),
('590cc569-16cf-43ae-8eb6-1779948e21d3','幽居寄李秘書','譚用之','宋','宋诗','song-poetry','','[]','幾年帝里阻烟波，敢向明時叩角歌。',64,'全唐诗/poet.song.0.json','["幾年帝里阻烟波，敢向明時叩角歌。", "看盡好花春卧穩，醉殘紅日夜吟多。", "印開夕照垂楊柳，畫破寒潭老芰荷。", "昨夜前溪有龍鬭，石橋風雨少人過。"]'),
('24ec8820-09ca-4a5f-aac5-98424d27bfc8','貽釣魚李處士','譚用之','宋','宋诗','song-poetry','','[]','罷吟鸚鵡草芊芊，又泛鴛鴦水上天。',64,'全唐诗/poet.song.0.json','["罷吟鸚鵡草芊芊，又泛鴛鴦水上天。", "一棹冷涵楊柳雨，片帆香挂芰荷烟。", "綠摇江澹萍離岸，紅點雲疏橘滿川。", "何處邈將歸畫府，數莖紅蓼一漁船。"]'),
('fdb9b167-35c5-49aa-9a66-4e6a99228063','河橋樓賦得群公夜讌','譚用之','宋','宋诗','song-poetry','','[]','芙蓉簾幕扇秋紅，蠻府新郎夜讌同。',64,'全唐诗/poet.song.0.json','["芙蓉簾幕扇秋紅，蠻府新郎夜讌同。", "滿座馬融吹笛月，一樓張翰過江風。", "杯黏紫酒金螺重，談轉琱璫玉麈空。", "深荷良宵慰顦顇，德星池館在江東。"]'),
('3a435387-3c07-4cd8-ba2d-5c883598604e','寄左先輩','譚用之','宋','宋诗','song-poetry','','[]','狂歌白鹿上青天，可似蘭塘釣紫烟。',64,'全唐诗/poet.song.0.json','["狂歌白鹿上青天，可似蘭塘釣紫烟。", "萬卷祖龍坑外物，一泓孫楚耳中泉。", "翩翾蠻榼薰晴浦，轂轆魚車響夜船。", "學取青蓮李居士，一生杯酒在神仙。"]'),
('f1dbb166-7a6f-47b3-9b6f-922ea7b451db','貽費道人','譚用之','宋','宋诗','song-poetry','','[]','誰如南浦傲烟霞，白葛衣輕稱帽紗。',64,'全唐诗/poet.song.0.json','["誰如南浦傲烟霞，白葛衣輕稱帽紗。", "碧玉蜉蝣迎客酒，黄金轂轆釣魚車。", "吟歌雲鳥歸樵谷，卧愛神仙入畫家。", "他日鳳書何處覓，武陵烟樹半桃花。"]'),
('a9e4be45-154e-447f-af63-1ff134006aae','寄許下前管記王侍御','譚用之','宋','宋诗','song-poetry','','[]','昔年南去得娛賓，頓遜杯前共好春。',64,'全唐诗/poet.song.0.json','["昔年南去得娛賓，頓遜杯前共好春。", "蟻泛羽觴蠻酒膩，鳳銜瑶句蜀牋新。", "花憐遊騎紅隨轡，草戀征車碧遶輪。", "別後青青鄭南陌，不知風月屬何人。"]'),
('411568a8-493a-4e7e-a2a5-4739cdacbd78','秋日圃田送人隨計','譚用之','宋','宋诗','song-poetry','','[]','僕射陂前是傳郵，去程鵰鶚弄高秋。',64,'全唐诗/poet.song.0.json','["僕射陂前是傳郵，去程鵰鶚弄高秋。", "吟拋芍藥裁詩圃，醉下茱萸飲酒樓。", "向日迥飛駒皎皎，臨風誰和鹿呦呦。", "明年二月仙山下，莫遣桃花逐水流。"]'),
('2970862b-3b08-4f4c-b552-8eb2b1a24a9c','途次宿友人別墅','譚用之','宋','宋诗','song-poetry','','[]','千里崤函一夢勞，豈知雲館共蕭騷。',64,'全唐诗/poet.song.0.json','["千里崤函一夢勞，豈知雲館共蕭騷。", "半簾綠透偎寒竹，一榻紅侵墜晚桃。", "蠻酒客稀知味長，蜀琴風定覺弦高。", "感君巖下閒招隠，細縷金盤鱠錯刀。"]'),
('051cef13-282d-466b-8806-e0b22edfd93f','春日期巢湖舊事','譚用之','宋','宋诗','song-poetry','','[]','暖掠紅香燕燕飛，五雲仙珮曉相携。',64,'全唐诗/poet.song.0.json','["暖掠紅香燕燕飛，五雲仙珮曉相携。", "花開鸚鵡韋郎曲，竹亞虯龍白帝溪。", "富貴萬場歸紫酒，是非千載逐芳泥。", "不知多少開元事，露泣春叢向日低。"]'),
('c89eb22c-19cd-4733-b1e5-f6afa72c75d8','再遊韋曲山寺','譚用之','宋','宋诗','song-poetry','','[]','鵲巖烟斷玉巢敧，罨畫春塘太白低。',64,'全唐诗/poet.song.0.json','["鵲巖烟斷玉巢敧，罨畫春塘太白低。", "馬踏翠開垂柳寺，人耕紅破落花蹊。", "千年勝概咸原上，幾代荒凉繡嶺西。", "碧吐紅芳舊行處，豈堪回首草萋萋。"]'),
('6df3e371-5e3c-4b13-a171-13a8df7631d5','寄徐拾遺','譚用之','宋','宋诗','song-poetry','','[]','長竿一繫白龍吟，誰和騶虞發素琴。',64,'全唐诗/poet.song.0.json','["長竿一繫白龍吟，誰和騶虞發素琴。", "野客碧雲魂易斷，故人芳草夢難尋。", "天從補後星辰穩，海自潮來島嶼深。", "好向明庭拾遺事，莫教玄豹老泉林。"]'),
('9b0af44d-e9f3-4ae1-a8aa-e8663c62532d','秋宿湘江遇雨','譚用之','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u79cb\u5929", "\u96e8", "\u6000\u624d\u4e0d\u9047"]','江上陰雲鎖夢魂，江邊深夜舞劉琨。',64,'全唐诗/poet.song.0.json','["江上陰雲鎖夢魂，江邊深夜舞劉琨。", "秋風萬里芙蓉國，暮雨千家薜荔村。", "鄉思不堪悲橘柚，旅遊誰肯重王孫。", "漁人相見不相問，長笛一聲歸島門。"]'),
('fe57dcb4-5715-41ec-b6f1-54dd2e56da63','貽南康陳處士陶','譚用之','宋','宋诗','song-poetry','','[]','白玉堆邊蔣逕橫，空涵二十四灘聲。',64,'全唐诗/poet.song.0.json','["白玉堆邊蔣逕橫，空涵二十四灘聲。", "老無征戰軒轅國，貧有茅茨帝舜城。", "丹鳳晝飛羣木冷，一龍秋卧九江清。", "時人莫笑非經濟，還待中原致太平。"]'),
('353ef0d7-dd66-464d-8b9a-e1b9286ac14b','渭城春晚','譚用之','宋','宋诗','song-poetry','','[]','秦樹朦朧春色微，香風烟煖樹依依。',64,'全唐诗/poet.song.0.json','["秦樹朦朧春色微，香風烟煖樹依依。", "邊城夜靜月初上，芳草路長人未歸。", "折柳且堪吟晚檻，弄花何處醉殘暉。", "釣鄉千里斷消息，滿目碧雲空自飛。"]'),
('f0ae67b1-c51e-4c4d-a10e-f656688030fa','山中春晚寄賈員外','譚用之','宋','宋诗','song-poetry','','[]','不隨黄鶴起烟波，應笑無成返薜蘿。',64,'全唐诗/poet.song.0.json','["不隨黄鶴起烟波，應笑無成返薜蘿。", "看盡好花春卧穩，醉殘紅日夜吟多。", "高添雅興松千尺，暗養清音竹數科。", "珍重仙曹舊知己，往來星騎一相過。"]'),
('5574ad72-02fb-47f6-bfa8-6f87b6375b3d','貽浄居寺新及第','譚用之','宋','宋诗','song-poetry','','[]','秋池雲下白蓮香，池上吟仙寄竹房。',64,'全唐诗/poet.song.0.json','["秋池雲下白蓮香，池上吟仙寄竹房。", "閒頌國風文字古，靜消心火夢魂凉。", "三春蓬島花無限，八月銀河路更長。", "此境空門不曾有，從頭好語與醫王。"]'),
('8db89b84-13c0-4c26-9459-c605da2e8955','江邊秋夕','譚用之','宋','宋诗','song-poetry','','[]','千鍾紫酒薦菖蒲，松島蘭舟瀲灩居。',64,'全唐诗/poet.song.0.json','["千鍾紫酒薦菖蒲，松島蘭舟瀲灩居。", "曲內橘香江客笛，字中嵐氣岳僧書。", "吟期汗漫驅金虎，坐約丹青跨玉魚。", "七色花虯一聲鶴，幾時乘興上清虛。"]'),
('4d564f9b-a321-4a10-8d82-a2410d7e3f18','送僧中孚南歸','譚用之','宋','宋诗','song-poetry','','[]','琵琶峽口月溪邊，玉乳頭佗憶舊川。',64,'全唐诗/poet.song.0.json','["琵琶峽口月溪邊，玉乳頭佗憶舊川。", "一錫冷涵蘭徑路，片帆香掛橘洲烟。", "苔封石錦棲霞室，水迸衣珠噴玉蟬。", "莫道翩翩去如夢，本來吟鳥在林泉。"]'),
('55fa18b8-e2f2-48ba-8236-3d2d4730ab7c','江館秋夕','譚用之','宋','宋诗','song-poetry','','[]','耿耿銀河雁半橫，夢敧金碧轆轤輕。',64,'全唐诗/poet.song.0.json','["耿耿銀河雁半橫，夢敧金碧轆轤輕。", "滿窗謝練江風白，一枕齊紈海月明。", "楊柳敗梢飛葉響，芰荷香柄折秋鳴。", "誰人更唱陽關曲，牢落烟霞夢不成。"]'),
('8b6acc8e-5afa-415e-9ecb-afd65751df84','秋夜同友人話舊','譚用之','宋','宋诗','song-poetry','','[]','露下銀河雁度頻，囊中壚火幾時真。',64,'全唐诗/poet.song.0.json','["露下銀河雁度頻，囊中壚火幾時真。", "數莖白髮生浮世，一盞寒燈共故人。", "雲外簟凉吟嶠月，島邊花暖釣江春。", "何當歸去重携手，依舊紅霞作近鄰。"]'),
('8e4da786-b3d2-46fb-a11f-a6cb3bfc2bcb','古劍','譚用之','宋','宋诗','song-poetry','','[]','鑄時天匠待英豪，紫焰寒星匣倍牢。',64,'全唐诗/poet.song.0.json','["鑄時天匠待英豪，紫焰寒星匣倍牢。", "三尺何年拂塵土，四溟今日絕波濤。", "雄應垓下收蛇陣，滯想溪頭伴豹韜。", "惜是真龍懶拋擲，夜來衝斗氣何高。"]'),
('c7593fea-f0e5-4ea6-b407-d4294e5ac25e','寄王侍御','譚用之','宋','宋诗','song-poetry','','[]','鳥盡弓藏良可哀，誰知歸釣子陵臺。',64,'全唐诗/poet.song.0.json','["鳥盡弓藏良可哀，誰知歸釣子陵臺。", "鍊多不信黄金耗，吟苦須驚白髮催。", "喘月吳牛知夜至，嘶風胡馬識秋來。", "燕歌別後休惆悵，黍已成畦菊已開。"]'),
('43a44c6a-b036-419f-9651-01d1af492358','別何處士陵俊老','譚用之','宋','宋诗','song-poetry','','[]','三皇上人春夢醒，東侯老大麒麟生。',64,'全唐诗/poet.song.0.json','["三皇上人春夢醒，東侯老大麒麟生。", "洞連龍穴全山冷，窗透鼇波盡室清。", "計拙恥居巖麓老，氣狂慚與斗牛平。", "誰人爲向青編上，直傍巢由寫一名。"]'),
('279cdc84-e1b6-4514-a200-4b843b97cf35','句  其一','譚用之','宋','宋诗','song-poetry','','[]','流水物情諳世態，落花春夢厭塵勞。',16,'全唐诗/poet.song.0.json','["流水物情諳世態，落花春夢厭塵勞。"]'),
