('e5bd3f61-0a9c-401a-a5b8-d9c2b19dbde9','歌','南昌老翁媼','宋','宋诗','song-poetry','','[]','藍采禾，藍采禾，塵世紛紛事更多。',32,'全唐诗/poet.song.0.json','["藍采禾，藍采禾，塵世紛紛事更多。", "爭如賣藥沽酒飲，歸去深崖拍手歌。"]'),
('a47e9fa9-5994-495b-9dd5-8c733db4a6bc','偈','釋玄應','宋','宋诗','song-poetry','','[]','今年六十六，世壽有延促。',36,'全唐诗/poet.song.0.json','["今年六十六，世壽有延促。", "無生火熾然，有爲薪不續。", "出谷與歸源，一時俱備足。"]'),
('f666c953-4281-49a4-9dc7-d62990bfdc2d','宿沖虛觀','胡衍','宋','宋诗','song-poetry','','[]','鐘靜日已夕，塵緣謝驅役。',72,'全唐诗/poet.song.0.json','["鐘靜日已夕，塵緣謝驅役。", "琪樹鶴爭定，山空萬籟寂。", "明月散庭除，寒光照床席。", "花鳥魂夢間，相見曾相識。", "五更仙鹿鳴，聲近在籬隙。", "曉來問童子，石徑無行跡。"]'),
('1c13fdd4-6a21-4bb3-a12d-3f136c34e07d','朝斗壇','胡衍','宋','宋诗','song-poetry','','[]','不見銅龍何處飛，空餘芳草舊臺基。',32,'全唐诗/poet.song.0.json','["不見銅龍何處飛，空餘芳草舊臺基。", "月明風冷禽聲碎，疑是仙人佩玉歸。"]'),
('1b8afbad-6772-41fa-b092-84046cffb1a9','誡兒姪八百字','范質','宋','宋诗','song-poetry','','[]','去年初釋褐，一命列蓬丘。',288,'全唐诗/poet.song.0.json','["去年初釋褐，一命列蓬丘。", "青袍春草色，白紵棄如仇。", "適會龍飛慶，王澤天下流。", "爾得六品階，無乃太爲優。", "凡登進士第，四選昇校讎。", "歷官十五考，敘階與爾儔。", "如何志未滿，意欲凌雲遊。", "若言品位卑，寄書來我求。", "省之再三歎，不覺淚盈眸。", "吾家本寒素，門地寡公侯。", "先子有令德，樂道尚優游。", "生逢世多僻，委順信沈浮。", "仕宦不喜達，吏隠同莊周。", "積善有餘慶，清白爲貽謀。", "伊余奉家訓，孜孜務進修。", "夙夜事勤肅，言行思悔尤。", "出門擇交友，防慎畏薰蕕。", "省躬常懼玷，恐掇庭闈羞。", "童年志於學，不惰爲箕裘。", "二十中甲科，赬尾化爲虬。", "三十入翰苑，步武向瀛洲。", "四十登宰輔，貂冠侍冕旒。", "備位行一紀，將何助帝猷。", "即非救旱雨，豈是濟川舟。"]'),
('b9423f90-7e22-4bc2-be5b-45df0d4b75bb','賀李昉','范質','宋','宋诗','song-poetry','','[]','翰苑重求李謫仙，詞鋒穎利勝龍泉。',64,'全唐诗/poet.song.0.json','["翰苑重求李謫仙，詞鋒穎利勝龍泉。", "朝趨建禮霞烘日，夜直承明月印天。", "聖主重知緣國士，相公多喜爲同年。", "青春才子金門貴，蜀錦袍新奪日鮮。"]'),
('0b130882-ac80-4718-9371-a8ddce929aec','答使者','釋定御','宋','宋诗','song-poetry','','[]','三年過了又三年，閱遍華巖滿五千。',32,'全唐诗/poet.song.0.json','["三年過了又三年，閱遍華巖滿五千。", "功德完滿珍重去，何勞使者上高田。"]'),
