('bf1f2537-5ff4-4349-9d1e-98b43839271c','存目  其一','扈蒙','宋','宋诗','song-poetry','','[]','詩題：原無題句：微臣自愧頭如雪，也向鈞天侍玉皇。',24,'全唐诗/poet.song.0.json','["詩題：原無題句：微臣自愧頭如雪，也向鈞天侍玉皇。"]'),
('6fa1b3b5-cc7d-404b-9add-9dd532653cb7','存目  其二','扈蒙','宋','宋诗','song-poetry','','[]','（以上劉瑛整理）。',9,'全唐诗/poet.song.0.json','["（以上劉瑛整理）。"]'),
('6bd4b204-c056-41fd-a624-ad7fb345ceb9','偶因團聚思想仙巖詣就觀瞻龕龕禮謁推砂掃窟之次忽睹南大像北邊一所古窟摧殘歲久毀壞年深去戊申歲末發其心願至己酉歲中方乃修全以咨推砂掃窟崇飾功德所申意者先奉爲龍天〔八〕部擁護河湟梵釋四王安人靜塞伏願當今帝主永坐蓬萊十道爭欽八方慕化次爲我府主令公長隆寶位命壽延年爲絕塞之人王作蒼生之父母榮同舜日化布堯時繼葉臨人承桃秉世觀音院主道真等十人悟四大而無實睹丘井以懸騰慮□地以火風恐强象而煎逼道真等唯見牛車火宅空然勸時侶發無上之善心誓堅修於勝果今因作罷略述數行拙解舖舒用留於壁余才虧翰墨學寡三墳不但荒蕪輒成短句','釋道真','宋','宋诗','song-poetry','','[]','人生四大惣是空，何箇不覓出煩籠。',96,'全唐诗/poet.song.0.json','["人生四大惣是空，何箇不覓出煩籠。", "造罪人多作福少，所以衆生長受窮。", "堅修苦行仍本分，禁戒奢華並不同。", "今生努力懃精練，冥路不溺苦海中。", "日逐持經强發願，弘道迴去莫難逢。", "唯報往來游禮者，這迴巡謁一層層。"]'),
('924cd973-7f37-40ad-bdb1-76405af64465','某又述','釋道真','宋','宋诗','song-poetry','','[]','白壁從來好丹青，無知箇箇亂題名。',64,'全唐诗/poet.song.0.json','["白壁從來好丹青，無知箇箇亂題名。", "三塗地獄交誰忍，十八湔銅灌一瓶。", "鎸龕必定添福利，鑿壁多層證無生。", "唯報往來遊翫者，輒莫於此騁書題。"]'),
('b83f5104-062f-43f5-98d5-7f59b5fe540c','依韻','釋道真','宋','宋诗','song-poetry','','[]','白壁雖然好丹青，無簡迷愚難悟醒。',64,'全唐诗/poet.song.0.json','["白壁雖然好丹青，無簡迷愚難悟醒。", "縱有百般僧氏巧，也有文徒書號名。", "空留佳妙不題宣，却入五趣陷塵境。", "唯報往來遊觀者，起聽前詞□□□。"]'),
('81bd54b5-753d-4eae-8506-249dadfa32f1','某又述','釋道真','宋','宋诗','song-poetry','','[]','能持凈意作□家，解駕牛羊白鹿車。',64,'全唐诗/poet.song.0.json','["能持凈意作□家，解駕牛羊白鹿車。", "嫌闌砌前栽樹少，怕空不種後園花。", "菩提上□因修得，佛果無生證有涯。", "此處涅盤觀境□，自然捷路到龍花。"]'),
('d7540229-7ee3-44c8-b973-147d86dad493','偶因閑日家事無牽蒙王氏以呼招乃書題於窟記伏見僧俗等五人箇箇苦行不異檀特山邊各各談空有似釋迦園內且曹都頭門傳閥閱帝子王孫衣上惹勳郁之香顔前棐桃花之色念讓寶之存寶行越前賢思知足而常足來救善友聽經不倦制意馬以停𧬊戀寂有誠撥心燈而更耀既有斯願必上羊車更多奇功興譽不盡輒上詩一首','釋道真','宋','宋诗','song-poetry','','[]','譙國門傳縉以紳，善男子即是帝王孫。',65,'全唐诗/poet.song.0.json','["譙國門傳縉以紳，善男子即是帝王孫。", "文商碑背題八字，武盛弓弦重六鈞。", "既出四門觀生老，便知六賊不相親。", "夜迶將心登峻嶺，心定菩提轉法輪。"]'),
('8eadfa2f-e778-4a6d-9b67-bf362cf824d9','□因從台駕隨侍□□（政）□（道）□（舍）□道真等七人就三危聖王寺□安下霸道場記□（維）□（天）□（福）十五年五月八日遊記之耳','釋道真','宋','宋诗','song-poetry','','[]','三危山內枲世□（賢），結此道場下停□（閑）。',79,'全唐诗/poet.song.0.json','["三危山內枲世□（賢），結此道場下停□（閑）。", "侍送門人往不絕，聖是山谷水未寬。", "一旬之間僧久住，感動山神賜霜樹。", "□值牟尼□（威）力重，此山本□住□（僧）□（田）。"]'),
('ba3105a3-3b02-4ec5-abe1-84a84b42a8ea','蒸豚','紫衣師','宋','宋诗','song-poetry','','[]','嘴長毛短淺含臕，久向山中食藥苗。',64,'全唐诗/poet.song.0.json','["嘴長毛短淺含臕，久向山中食藥苗。", "蒸處已將蕉葉裹，熟時兼用杏漿澆。", "紅鮮雅稱金盤飣，熟軟真堪玉箸挑。", "若把羶根來比並，羶根自合吃藤條。"]'),
('2899b63f-f082-4e67-aa73-41d17406b710','贈英公上人','宋溫舒','宋','宋诗','song-poetry','','[]','粹鍾衡岳誕吾師，十九彤廷賜紫衣。',64,'全唐诗/poet.song.0.json','["粹鍾衡岳誕吾師，十九彤廷賜紫衣。", "青簡篆文窮妙絕，碧雲詩句入玄微。", "降龍鉢裏無塵染，迴雁峰前有夢歸。", "他日好同蓮社約，逸眠禪坐兩忘機。"]'),
('4082a0f4-beee-47f7-af66-be1dbe3fc3f1','贈徐鼎臣常侍','釋印粲','宋','宋诗','song-poetry','','[]','不將才名暫時夸，人仰聲名遍海涯。',64,'全唐诗/poet.song.0.json','["不將才名暫時夸，人仰聲名遍海涯。", "月滿朝衣聽禁漏，更闌分直掃宮花。", "諫書未上先焚稿，御筆曾傳立草麻。", "見說下朝無一事，小池栽葦學僧家。"]'),
('20bc47aa-33c7-48bb-94aa-842b5d83b4e1','早春左省寓直','徐鉉','宋','宋诗','song-poetry','','[]','旭景鸞臺上，微雲象闕間。',48,'全唐诗/poet.song.0.json','["旭景鸞臺上，微雲象闕間。", "時清政事少，日永直官閒。", "遠籟飛簫管，零冰響珮環。", "終軍年二十，默坐叩玄關。"]'),
('cf27aa40-b08e-4ced-914e-fe86437d4cf6','寒食宿陳公塘上','徐鉉','宋','宋诗','song-poetry','','[]','垂楊界官道，茅屋倚高坡。',48,'全唐诗/poet.song.0.json','["垂楊界官道，茅屋倚高坡。", "月下春塘水，風中牧豎歌。", "折花閒立久，對酒遠情多。", "今夜孤亭夢，悠揚奈爾何。"]'),
('214524cb-abae-4830-b5ab-0d12e7e0fc9d','將去廣陵別史員外南齋','徐鉉','宋','宋诗','song-poetry','','[]','家聲曾與金張輩，官署去居何宋間。',64,'全唐诗/poet.song.0.json','["家聲曾與金張輩，官署去居何宋間。", "起得高齋臨靜曲，種成奇樹學他山。", "鴛鸞終日同醒醉，蘿薜常時共往還。", "賤子今朝獨南去，不堪回首望清閒。"]'),
('4813c5ab-b686-478b-b041-b5324c0f549a','將過江題白沙館','徐鉉','宋','宋诗','song-poetry','','[]','少長在維揚，依然認故鄉。',48,'全唐诗/poet.song.0.json','["少長在維揚，依然認故鄉。", "金陵佳麗地，不道少風光。", "稍望吳臺遠，行登楚塞長。", "殷勤語江嶺，歸夢莫相妨。"]'),
('1857b4de-ade5-45d3-b4c7-0041454fbff2','登甘露寺北望','徐鉉','宋','宋诗','song-poetry','','[]','京口潮來曲岸平，海門風起浪花生。',64,'全唐诗/poet.song.0.json','["京口潮來曲岸平，海門風起浪花生。", "人行沙上見日影，舟過江中聞櫓聲。", "芳草遠迷揚子渡，宿烟深映廣陵城。", "游人鄉思應如橘，相望須含兩地情。"]'),
('1a9b8d7f-c64b-4a9c-8652-2538e04e281e','山路花','徐鉉','宋','宋诗','song-poetry','','[]','不共垂楊映綺寮，倚山臨路自嬌饒。',64,'全唐诗/poet.song.0.json','["不共垂楊映綺寮，倚山臨路自嬌饒。", "游人過去知香遠，谷鳥飛來見影摇。", "半隔烟嵐遥隠隠，可堪風雨暮蕭蕭。", "城中春色還如此，幾處笙歌案舞腰。"]'),
('f405cfe1-cdaa-413a-ab44-cd7fb3beddd6','京口江際弄水','徐鉉','宋','宋诗','song-poetry','','[]','退公求靜獨臨川，揚子江南二月天。',64,'全唐诗/poet.song.0.json','["退公求靜獨臨川，揚子江南二月天。", "百尺翠屏甘露閣，數帆晴日海門船。", "波澄瀨石寒如玉，草接汀蘋綠似烟。", "安得乘槎更東去，十洲風外弄潺湲。"]'),
('23bec8e0-a1b3-43ae-86a6-c21eb739c0c5','早春旬假獨直寄江舍人','徐鉉','宋','宋诗','song-poetry','','[]','省署皆歸沐，西垣公事稀。',48,'全唐诗/poet.song.0.json','["省署皆歸沐，西垣公事稀。", "詠詩前砌立，聽漏向申歸。", "遠思風醒酒，餘寒雨濕衣。", "春光已堪探，芝蓋共誰飛。"]'),
('d14b5370-5c90-4958-95fb-d3605413332e','從駕東幸呈諸公','徐鉉','宋','宋诗','song-poetry','','[]','吳公臺下舊京城，曾掩衡門過十春。',64,'全唐诗/poet.song.0.json','["吳公臺下舊京城，曾掩衡門過十春。", "別後不知新景象，信來空問故交親。", "宦游京口無高興，習隠鍾山限俗塵。", "今日喜爲華表鶴，況陪鵷鷺免迷津。"]'),
('8f69f63d-e698-4e2e-b73a-ffd604d972aa','重遊木蘭亭','徐鉉','宋','宋诗','song-poetry','','[]','繚繞長隄带碧潯，昔年游此尚青衿。',64,'全唐诗/poet.song.0.json','["繚繞長隄带碧潯，昔年游此尚青衿。", "蘭橈破浪城陰直，玉勒穿花苑樹深。", "宦路塵埃成久別，仙家風景有誰尋。", "那知年長多情後，重凭欄干一獨吟。"]'),
('5a0286b6-9f06-49c0-a181-925ebcf4a726','賦得綵燕','徐鉉','宋','宋诗','song-poetry','','[]','縷綵成飛燕，迎和啟蟄時。',48,'全唐诗/poet.song.0.json','["縷綵成飛燕，迎和啟蟄時。", "翠翹生玉指，繡羽拂文楣。", "詎費銜泥力，無勞剪爪期。", "化工今在此，翻怪社來遲。"]'),
('0041e40e-ab02-42b1-b519-b774f1c53172','送魏舍人仲甫爲蘄州判官','徐鉉','宋','宋诗','song-poetry','','[]','從事蘄春興自長，蘄人應識紫微郎。',64,'全唐诗/poet.song.0.json','["從事蘄春興自長，蘄人應識紫微郎。", "山資足後拋名路，蒓菜秋來憶故鄉。", "以道卷舒猶自適，臨戈談笑固無妨。", "如聞郡閣吹橫笛，時望青谿憶野王。"]'),
('66b13797-0ca2-4dcf-ac81-c5928a5e5887','題殷舍人宅木芙蓉','徐鉉','宋','宋诗','song-poetry','','[]','憐君庭下木芙蓉，嫋嫋纖枝淡淡紅。',64,'全唐诗/poet.song.0.json','["憐君庭下木芙蓉，嫋嫋纖枝淡淡紅。", "曉吐芳心零宿露，晚摇嬌影媚清風。", "似含情態愁秋雨，暗減馨香借菊叢。", "默飲數杯應未稱，不知歌管與誰同。"]'),
('963b79a0-3c2d-4512-890c-c419c6a632d6','送史館高員外使嶺南','徐鉉','宋','宋诗','song-poetry','','[]','東觀時閒暇，還修喻蜀書。',48,'全唐诗/poet.song.0.json','["東觀時閒暇，還修喻蜀書。", "雙旌馳縣道，百越從軺車。", "桂蠹晨餐罷，貪泉訪古初。", "春江多好景，莫使醉吟疏。"]'),
('678b42ec-6442-4a8f-8514-d2e96c7b3871','春日紫巖山期客不至','徐鉉','宋','宋诗','song-poetry','','[]','郊外春華好，人家带碧溪。',48,'全唐诗/poet.song.0.json','["郊外春華好，人家带碧溪。", "淺莎藏鴨戲，輕靄隔雞啼。", "掩映紅桃谷，夤緣翠柳堤。", "王孫竟不至，芳草自萋萋。"]'),
('969544ee-254f-4245-8ec3-7b79c7831a1a','宿蔣帝廟明日遊山南諸寺','徐鉉','宋','宋诗','song-poetry','','[]','便返城闉尚未甘，更從山北到山南。',64,'全唐诗/poet.song.0.json','["便返城闉尚未甘，更從山北到山南。", "花枝似雪春雖半，桂魄如眉日始三。", "松蓋遮門寒黯黯，柳絲妨路翠毿毿。", "登臨莫怪偏留戀，游宦多年事事諳。"]'),
('e0ad75a4-79e4-4b73-b7b8-15eb1c0b7568','賦得有所思','徐鉉','宋','宋诗','song-poetry','','[]','所思何在杳難尋，路遠山長水復深。',64,'全唐诗/poet.song.0.json','["所思何在杳難尋，路遠山長水復深。", "衰草滿庭空佇立，清風吹袂更長吟。", "忘情好醉青田酒，寄恨宜調綠綺琴。", "落日鮮雲偏聚散，可能知我獨傷心。"]'),
('efec86b9-273a-41a8-90e5-e19d828cd9c0','贈王貞素先生','徐鉉','宋','宋诗','song-poetry','','[]','先生嘗已佩真形，紺髮朱顔骨氣清。',64,'全唐诗/poet.song.0.json','["先生嘗已佩真形，紺髮朱顔骨氣清。", "道秘未傳鴻寶術，院深時聽步虛聲。", "遼東幾度悲城郭，吳市終應變姓名。", "三十六天皆有籍，他年何處問歸程。"]'),
('5d330dc4-b9dd-458a-b465-6430de8f8433','春夜月','徐鉉','宋','宋诗','song-poetry','','[]','幽人春望本多情，況是花繁月正明。',32,'全唐诗/poet.song.0.json','["幽人春望本多情，況是花繁月正明。", "竟夕無言亦無寐，繞階芳草影隨行。"]'),
('82401c04-bbe8-4b97-8873-b54f0464a8d3','愛敬寺有老僧嘗遊長安言秦雍間事歷歷可聽因贈此詩兼示同行客','徐鉉','宋','宋诗','song-poetry','','[]','白首棲禪者，嘗談灞滻游。',48,'全唐诗/poet.song.0.json','["白首棲禪者，嘗談灞滻游。", "能令過江客，偏起失鄉愁。", "室倚桃花崦，門臨杜若洲。", "城中無此景，將子剩淹留。"]'),
('088f6f69-4ad2-4b2a-bb84-a34535ce984a','游蔣山題辛夷花寄陳奉禮本約陳同游不至','徐鉉','宋','宋诗','song-poetry','','[]','今歲游山已恨遲，山中仍喜見辛夷。',64,'全唐诗/poet.song.0.json','["今歲游山已恨遲，山中仍喜見辛夷。", "簪纓且免全爲累，桃李猶堪別作期。", "晴後日高偏照灼，晚來風急漸離披。", "山郎不作同行伴，折是何由寄所思。"]'),
('d16c9339-ea20-4753-bc16-5890553e7eb2','和殷舍人蕭員外春雪','徐鉉','宋','宋诗','song-poetry','','[]','萬里春陰乍履端，廣庭風起玉塵乾。',64,'全唐诗/poet.song.0.json','["萬里春陰乍履端，廣庭風起玉塵乾。", "梅花嶺上連天白，蕙草階前特地寒。", "晴去便爲經歲別，興來何惜徹宵看。", "此時鴛侶皆閒暇，贈答詩成禁漏殘。"]'),
('cdf7fcaf-b047-467d-bd97-9a7b297c0d07','寄蘄州高郎中','徐鉉','宋','宋诗','song-poetry','','[]','賈傅棲遲楚澤東，蘭臯三度換秋風。',64,'全唐诗/poet.song.0.json','["賈傅棲遲楚澤東，蘭臯三度換秋風。", "紛紛世事來無盡，黯黯離魂去不通。", "直道未能勝社鼠，孤飛徒自嘆冥鴻。", "知君多少思鄉恨，闇在山城一笛中。"]'),
('2b9b919b-3ecf-44de-9b2a-56c43de50761','寄和州韓舍人','徐鉉','宋','宋诗','song-poetry','','[]','急景駸駸度，遥懷處處生。',48,'全唐诗/poet.song.0.json','["急景駸駸度，遥懷處處生。", "風頭乍寒暖，天色半陰晴。", "久別魂空斷，終年道不行。", "殷勤雲上雁，爲過歷陽城。"]'),
('8c0f2ef6-a46a-4e68-9419-54210efe0368','從兄龍武將軍沒於邊戍過舊營宅作','徐鉉','宋','宋诗','song-poetry','','[]','前年都尉沒邊城，帳下何人領舊兵。',64,'全唐诗/poet.song.0.json','["前年都尉沒邊城，帳下何人領舊兵。", "徼外瘴烟沉鼓角，山前秋日照銘旌。", "笙歌却返烏衣巷，部曲皆還細柳營。", "今日園林過寒食，馬蹄猶擬入門行。"]'),
('c59df47f-d3ea-4feb-9583-921123d86f96','景陽臺懷古','徐鉉','宋','宋诗','song-poetry','','[]','後主亡家不悔，江南異代長春。',28,'全唐诗/poet.song.0.json','["後主亡家不悔，江南異代長春。", "今日景陽臺上，閒人何用傷神。"]'),
('c104c8fe-1243-4940-8abb-24d55b93c602','春分日','徐鉉','宋','宋诗','song-poetry','','[]','仲春初四日，春色正中分。',48,'全唐诗/poet.song.0.json','["仲春初四日，春色正中分。", "綠野裴回月，晴天斷續雲。", "燕飛猶箇箇，花落已紛紛。", "思婦高樓晚，歌聲不可聞。"]'),
('1778c75b-cfde-497b-ba52-b58368116d42','寄駕部郎中','徐鉉','宋','宋诗','song-poetry','','[]','賤子乖慵性，頻爲省直牽。',48,'全唐诗/poet.song.0.json','["賤子乖慵性，頻爲省直牽。", "交情每相見，多在相門前。", "君獨疏名路，爲郎過十年。", "炎風久成別，南望思悠然。"]'),
('3846a7be-4d22-47e9-aa68-46f3b319c54f','和王庶子寄題兄長建州廉使新亭','徐鉉','宋','宋诗','song-poetry','','[]','謝守高齋結構新，一方風景萬家情。',64,'全唐诗/poet.song.0.json','["謝守高齋結構新，一方風景萬家情。", "羣賢詎減山陰會，遠俗初聞正始聲。", "水檻片雲長不去，訟庭纖草轉應生。", "阿連詩句偏多思，遥想池塘晝夢成。"]'),
('0f92cc6d-4ead-4b2c-b032-b9989a2b35d3','謝文靜墓下作','徐鉉','宋','宋诗','song-poetry','','[]','越徼稽天討，周京亂虜塵。',48,'全唐诗/poet.song.0.json','["越徼稽天討，周京亂虜塵。", "蒼生何可奈，江表更無人。", "豈憚尋荒壟，猶思認後身。", "春風白楊裏，獨步淚霑巾。"]'),
('2219e860-d261-4168-8572-0e2a7747f4c7','觀人讀春秋','徐鉉','宋','宋诗','song-poetry','','[]','日覺儒風薄，誰將霸道羞。',24,'全唐诗/poet.song.0.json','["日覺儒風薄，誰將霸道羞。", "亂臣無所戄，何用讀春秋。"]'),
('b56cc7dd-4379-485e-89a5-c0e7fbe1c677','秋日雨中與蕭贊善訪殷舍人於翰林座中作','徐鉉','宋','宋诗','song-poetry','','[]','野出西垣步步遲，秋光如水雨如絲。',64,'全唐诗/poet.song.0.json','["野出西垣步步遲，秋光如水雨如絲。", "銅龍樓下逢閒客，紅藥階前訪舊知。", "亂點乍滋承露處，碎聲因想滴蓬時。", "銀臺鑰入須歸去，不惜餘歡盡酒巵。"]'),
('0528d939-4269-47b7-a5ee-da5c9827c70b','送和州張員外爲江都令','徐鉉','宋','宋诗','song-poetry','','[]','經年相望隔重湖，一旦相逢在上都。',64,'全唐诗/poet.song.0.json','["經年相望隔重湖，一旦相逢在上都。", "塞詔官班聊慰否，埋輪意氣尚存無。", "由來聖代憐才子，始覺清風激懦夫。", "若向西岡尋勝賞，舊題名處爲躊躕。"]'),
('2472eee6-3869-49e3-9d96-7b7da5899588','和明道人宿山寺','徐鉉','宋','宋诗','song-poetry','','[]','聞道經行處，山前與水陽。',48,'全唐诗/poet.song.0.json','["聞道經行處，山前與水陽。", "磬聲深小院，燈影迥高房。", "落宿依樓角，歸雲擁殿廊。", "羨師閒未得，早起逐班行。"]'),
('5da9aa6c-0b52-4599-a556-929cf7524c26','晚歸','徐鉉','宋','宋诗','song-poetry','','[]','暑服道情出，烟街薄暮還。',48,'全唐诗/poet.song.0.json','["暑服道情出，烟街薄暮還。", "風清飄短袂，馬健弄連環。", "水靜聞歸櫓，霞明見遠山。", "過從本無事，從此涉旬閒。"]'),
('f90de2ee-f8eb-4582-8c3f-0fbed76650ef','月真歌月真，廣陵妓人，翰林殷舍人所錄，携之垂訪，筵上贈此','徐鉉','宋','宋诗','song-poetry','','[]','揚州勝地多麗人，其間麗者名月真。',352,'全唐诗/poet.song.0.json','["揚州勝地多麗人，其間麗者名月真。", "月真初年十四五，能彈琵琶善歌舞。", "風前弱柳一枝春，花裏嬌鶑百般語。", "揚州帝京多名賢，其間賢者殷德川。", "德川初秉綸闈筆，職近名高常罕出。", "花前月下或遊從，一見月真如舊識。", "闈庭深院資賢宅，宅門嚴峻無凡客。", "垂簾偶坐唯月真，調弄琵琶郎爲拍。", "殷郎一旦過江去，鏡中懶作孤鸞舞。", "朝雲暮雨鎮相隨，石頭城下還相遇。", "二月三月江南春，滿城濛濛起香塵。", "隔牆試聽歌一曲，乃是資賢宅裏人。", "綠窗繡幌天將曉，殘燭依依香褭褭。", "離腸却恨苦多情，軟障熏籠空悄悄。", "殷郎去冬入翰林，九霄官署轉深沉。", "人間想望不可見，唯向月真存舊心。", "我慚闒茸何爲者，長感餘光每相假。", "陋巷蕭條正掩扉，相携訪我衡茅下。", "我本山人愚且貞，歌筵飲席常無情。", "自從一見月真後，至今贏得顛狂名。", "殷郎月真聽我語，少壯光陰能幾許。", "良辰美景數追隨，莫教長說相思苦。"]'),
('3d4cfaf4-993a-4a49-a7ee-f55fc36440a1','走筆送義興令趙宣輔','徐鉉','宋','宋诗','song-poetry','','[]','聞君孤棹汎荆谿，隴首雲隨別恨飛。',32,'全唐诗/poet.song.0.json','["聞君孤棹汎荆谿，隴首雲隨別恨飛。", "杜牧舊居憑買取，他年藜杖願同歸。"]'),
('e972d893-1258-40a4-8718-9f381b94e096','天闕山絕句','徐鉉','宋','宋诗','song-poetry','','[]','散誕愛山客，凄凉懷古心。',24,'全唐诗/poet.song.0.json','["散誕愛山客，凄凉懷古心。", "寒風天闕晚，盡日倚軒吟。"]'),
('4ef5f1a1-e1e8-43f9-92b9-e7aa442ac59c','除夜','徐鉉','宋','宋诗','song-poetry','','[]','寒燈耿耿漏遲遲，送故迎新了不欺。',64,'全唐诗/poet.song.0.json','["寒燈耿耿漏遲遲，送故迎新了不欺。", "往事併隨殘曆日，春風寧識舊容儀。", "預慚歲酒難先飲，更對鄉儺羨小兒。", "吟罷明朝贈知己，便須題作去年詩。"]'),
('5e61c18c-0042-48ef-8751-32ab5a224143','寄鍾謨','徐鉉','宋','宋诗','song-poetry','','[]','看看潘鬢二毛生，昨日林梢又轉鶑。',64,'全唐诗/poet.song.0.json','["看看潘鬢二毛生，昨日林梢又轉鶑。", "欲對春風忘世慮，敢言罇酒召時英。", "假中西閣應無事，筵上南威幸有情。", "不得車公終不樂，已教紅袖出門迎。"]'),
('45ee1522-269e-4909-a641-2c34d5a6a9e9','正初答鍾郎中見招','徐鉉','宋','宋诗','song-poetry','','[]','高齋遲景雪初晴，風拂喬枝待早鶑。',64,'全唐诗/poet.song.0.json','["高齋遲景雪初晴，風拂喬枝待早鶑。", "南省郎官名籍籍，東鄰妓女字英英。", "流年倏忽成陳事，春物依稀有舊情。", "新歲相思自過訪，不須虛左遠相迎。"]'),
('06bb1bbc-4c83-4100-ba05-91ad59920471','聞雁寄故人','徐鉉','宋','宋诗','song-poetry','','[]','久作他鄉客，深慚薄宦非。',48,'全唐诗/poet.song.0.json','["久作他鄉客，深慚薄宦非。", "不知雲上雁，何得每年歸。", "夜靜聲彌怨，天空影更微。", "往年離別淚，今夕重霑衣。"]'),
('6727bb56-6ecc-4b49-9866-83a3a78cee33','江舍人宅筵上有妓唱和州韓舍人歌辭因以寄','徐鉉','宋','宋诗','song-poetry','','[]','良宵絲竹偶成歡，中有佳人俯翠鬟。',64,'全唐诗/poet.song.0.json','["良宵絲竹偶成歡，中有佳人俯翠鬟。", "白雪飄颻傳樂府，阮郎憔悴在人間。", "清風朗月長相憶，佩蕙紉蘭早晚還。", "深夜酒空筵欲散，向隅惆悵鬢堪斑。"]'),
('2d5e6746-4b40-4f78-accb-54141f03544c','寒食日作','徐鉉','宋','宋诗','song-poetry','','[]','厨冷烟初禁，門閑日更斜。',48,'全唐诗/poet.song.0.json','["厨冷烟初禁，門閑日更斜。", "東風不好事，吹落滿庭花。", "過社紛紛燕，新晴淡淡霞。", "京都盛遊觀，誰訪子雲家。"]'),
('879c1892-8932-4534-a7de-9d37f73c2d1a','賀殷游二舍人入翰林江給事拜中丞','徐鉉','宋','宋诗','song-poetry','','[]','清晨待漏獨徘徊，霄漢懸心不易裁。',64,'全唐诗/poet.song.0.json','["清晨待漏獨徘徊，霄漢懸心不易裁。", "閣老深嚴歸翰苑，夕郎威望拜霜臺。", "青綾對覆蓬壺晚，赤棒前驅道路開。", "猶有西垣廳記在，莫忘同草紫泥來。"]'),
('d1aa0c4f-8fa0-4ce1-8b95-c523d1031756','歐陽大監雨中視决隄因墮水明日見於省中因戲之','徐鉉','宋','宋诗','song-poetry','','[]','聞道張晨蓋，徘徊石首東。',48,'全唐诗/poet.song.0.json','["聞道張晨蓋，徘徊石首東。", "濬川非伯禹，落水異三公。", "衣濕仍愁雨，冠剞更怯風。", "今朝復相見，疑是葛仙翁。"]'),
('92c994e1-af2c-47b2-a809-02211b4f8030','送吳郎中爲宣州推官知涇縣','徐鉉','宋','宋诗','song-poetry','','[]','征虜亭邊月，雞鳴伴客行。',48,'全唐诗/poet.song.0.json','["征虜亭邊月，雞鳴伴客行。", "可憐何水部，今事謝宣城。", "風物聊供賞，班資莫繫情。", "同心不同載，留滯爲浮名。"]'),
('e4ff3b2e-4ee0-4fed-8f7b-ba5ca1e46c86','寄舒州杜員外','徐鉉','宋','宋诗','song-poetry','','[]','信到得君書，知君已下車。',48,'全唐诗/poet.song.0.json','["信到得君書，知君已下車。", "粉闈情在否，蓮幕興何如。", "人望徵賢入，余思從子居。", "灊山真隠地，憑爲卜茅廬。"]'),
('771ac075-c23c-4992-9e4b-cb8bc109e21d','九月十一日寄陳郎中','徐鉉','宋','宋诗','song-poetry','','[]','我多吏事君多病，寂絕過從又幾旬。',32,'全唐诗/poet.song.0.json','["我多吏事君多病，寂絕過從又幾旬。", "前日龍山烟景好，風前落帽是何人。"]'),
('61be577a-b613-4675-8cb0-ba080c2417ad','和司門郎中陳彥','徐鉉','宋','宋诗','song-poetry','','[]','衡門寂寂逢迎少，不見仙郎向五旬。',32,'全唐诗/poet.song.0.json','["衡門寂寂逢迎少，不見仙郎向五旬。", "莫問龍山前日事，菊花開却爲閒人。"]'),
('78484686-846b-432e-a615-c0ef1d616af9','賦得擣衣','徐鉉','宋','宋诗','song-poetry','','[]','江上多離別，居人夜擣衣。',48,'全唐诗/poet.song.0.json','["江上多離別，居人夜擣衣。", "拂砧知露滴，促杵恐霜飛。", "漏轉聲頻斷，愁多力自微。", "裁縫依夢見，腰带定應非。"]'),
('481179a4-009d-47eb-9338-0db983668ca0','九月三十夜雨寄故人','徐鉉','宋','宋诗','song-poetry','','[]','聽空階雨，方知秋事悲。',47,'全唐诗/poet.song.0.json','["聽空階雨，方知秋事悲。", "寂寥旬假日，蕭颯夜長時。", "別念紛紛起，寒更故故遲。", "情人如不醉，定是兩相思。"]'),
('dd8a0840-faf0-494f-baf6-5ff538ace044','寄撫州鍾郎中','徐鉉','宋','宋诗','song-poetry','','[]','去載分襟後，尋聞在建安。',48,'全唐诗/poet.song.0.json','["去載分襟後，尋聞在建安。", "封疆正多事，罇俎若爲歡。", "都護空遺鏃，明君欲舞干。", "繞朝時不用，非是殺身難。"]'),
('125dffdb-48e4-4c06-965e-ab58495846e7','送歐陽大監游廬山','徐鉉','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','家家門外廬山路，唯有夫君乞假遊。',64,'全唐诗/poet.song.0.json','["家家門外廬山路，唯有夫君乞假遊。", "案牘乍拋公署晚，林泉已近暑天秋。", "海潮盡處逢陶石，江月圓時上庾樓。", "此去蕭然好長往，人間何事不悠悠。"]'),
('4b2abd47-3557-4ff6-95a6-ebd365e612e6','立秋後一日與朱舍人同直','徐鉉','宋','宋诗','song-poetry','','[]','一宿秋風未覺凉，數聲宮漏日猶長。',32,'全唐诗/poet.song.0.json','["一宿秋風未覺凉，數聲宮漏日猶長。", "林泉無計消殘暑，虛向瑶池費稻粱。"]'),
('9ce08db3-2fe3-490c-8973-c4ff829b5879','賦得霍將軍辭第','徐鉉','宋','宋诗','song-poetry','','[]','漢將承恩久，圖勳肯顧私。',72,'全唐诗/poet.song.0.json','["漢將承恩久，圖勳肯顧私。", "匈奴猶未滅，安用以家爲。", "郢匠雖聞詔，衡門竟不移。", "寧煩張老頌，無待晏嬰辭。", "甲乙人徒費，親鄰我自持。", "悠悠千載下，長作帥臣師。"]'),
('73b672f1-500e-46c4-aa37-fca016022910','和元帥書記蕭郎中觀習水師','徐鉉','宋','宋诗','song-poetry','','[]','元帥樓船出治兵，落星山外火旗明。',64,'全唐诗/poet.song.0.json','["元帥樓船出治兵，落星山外火旗明。", "千帆日助江陵勢，萬里風馳下瀨聲。", "殺氣曉嚴波上鷁，凱歌遥駭海邊鯨。", "仲宣一作從軍詠，迴顧儒衣自不平。"]'),
('7c8f8612-7efe-4476-be81-e4cfacf5eb03','秋日盧龍村舍','徐鉉','宋','宋诗','song-poetry','','[]','置却人間事，閒從野老游。',48,'全唐诗/poet.song.0.json','["置却人間事，閒從野老游。", "樹聲村店晚，草色古城秋。", "獨鳥飛天外，閒雲度隴頭。", "姓名君莫問，山木與虛舟。"]'),
('79315d76-8586-46d0-9c81-9b14718b95d7','和蕭郎中小雪日作','徐鉉','宋','宋诗','song-poetry','','[]','征西府裏日西斜，獨試新爐自煮茶。',64,'全唐诗/poet.song.0.json','["征西府裏日西斜，獨試新爐自煮茶。", "籬菊盡來低覆水，塞鴻飛去遠連霞。", "寂寥小雪閒中過，斑駁輕霜鬢上加。", "算得流年無奈處，莫將詩句祝蒼華。"]'),
('5fcbc56a-c62a-4228-a802-c0070c0167fb','中書相公谿亭閒宴依韻','徐鉉','宋','宋诗','song-poetry','','[]','雨霽秋光晚，亭空野興迴。',48,'全唐诗/poet.song.0.json','["雨霽秋光晚，亭空野興迴。", "沙鷗掠岸去，谿水上階來。", "客傲風欺幘，筵香菊在盃。", "東山長許醉，何事憶天台。"]'),
('49f23e4a-403d-4258-b724-55f5091d284b','寄饒州王郎中效李白體','徐鉉','宋','宋诗','song-poetry','','[]','珍重王光嗣，交情尚在不。',48,'全唐诗/poet.song.0.json','["珍重王光嗣，交情尚在不。", "蕪城連宅住，楚塞並車游。", "別後官三改，年來歲六周。", "銀鈎無一字，何以緩離愁。"]'),
('c4094c8b-9a71-40fb-9dd6-bb27a362c405','寄歙州呂判官','徐鉉','宋','宋诗','song-poetry','','[]','任公郡占好山川，谿水縈迴路屈盤。',64,'全唐诗/poet.song.0.json','["任公郡占好山川，谿水縈迴路屈盤。", "南國自來推勝境，故人此地作郎官。", "風光適意須留戀，祿秩資貧且喜歡。", "莫憶班行重迴首，是非多處是長安。"]'),
('8d397261-4b74-4ca6-8b0d-508f112bb7e6','宣威苗將軍貶官後重經故宅','徐鉉','宋','宋诗','song-poetry','','[]','蔣山南望近西坊，亭館依然鎖院牆。',64,'全唐诗/poet.song.0.json','["蔣山南望近西坊，亭館依然鎖院牆。", "天子未嘗過細柳，將軍尋已戍燉煌。", "欹傾怪石山無色，零落圓荷水不香。", "爲將爲儒皆寂寞，門前愁殺馬中郎。"]'),
('9f420418-fabe-4888-974e-3a7e3cbe1bda','附池州薛郎中書因寄歙州張員外','徐鉉','宋','宋诗','song-poetry','','[]','新安從事舊臺郎，直氣多才不可忘。',64,'全唐诗/poet.song.0.json','["新安從事舊臺郎，直氣多才不可忘。", "一旦江山馳別夢，幾年簪紱共周行。", "岐分出處何方是，情共窮通此義長。", "因附鄰州寄消息，接輿今日信爲狂。"]'),
('c77b5693-bb2c-4918-81dd-fbb191b04ea2','寄江都路員外','徐鉉','宋','宋诗','song-poetry','','[]','吾兄失意在東都，聞說襟懷任所如。',64,'全唐诗/poet.song.0.json','["吾兄失意在東都，聞說襟懷任所如。", "已縱乖慵爲傲吏，有何關鍵制豪胥。", "縣齋曉閉多移病，南畝秋荒憶遂初。", "知道故人相憶否，嵇康不得懶修書。"]'),
('10713075-b7f6-4a71-ae13-bdcc00658c65','張員外好茅山風景求爲句容令作此送','徐鉉','宋','宋诗','song-poetry','','[]','句曲山前縣，依依數舍程。',48,'全唐诗/poet.song.0.json','["句曲山前縣，依依數舍程。", "還同適勾漏，非是厭承明。", "柳谷供詩景，華陽契道情。", "金門容傲吏，官滿且還城。"]'),
('2ccdd781-3e3d-4ee6-9098-94c436403823','送應之道人歸江西','徐鉉','宋','宋诗','song-poetry','','[]','曾騎竹馬傍洪涯，二十餘年變物華。',64,'全唐诗/poet.song.0.json','["曾騎竹馬傍洪涯，二十餘年變物華。", "客夢等閒過驛閣，歸帆遥羨指龍沙。", "名題小篆矜垂露，詩作吳吟對綺霞。", "歲暮定知迴未得，信來憑爲寄梅花。"]'),
('f7c0fe91-4833-4f51-a554-2a7508f24c3c','送元帥書記高郎中出爲婺源建威軍使','徐鉉','宋','宋诗','song-poetry','','[]','寒風蕭瑟楚江南，記室戎裝挂錦帆。',64,'全唐诗/poet.song.0.json','["寒風蕭瑟楚江南，記室戎裝挂錦帆。", "倚馬未曾妨笑傲，斬牲先要厲威嚴。", "危言昔日嘗無隠，壯節今來信不凡。", "唯有盃盤思上國，酒醪甜淡菜蔬甘。"]'),
('d044ac98-8850-46f4-922d-8f469b6cdf4d','游方山宿李道士房','徐鉉','宋','宋诗','song-poetry','','[]','從來未面李先生，借我西窗卧月明。',32,'全唐诗/poet.song.0.json','["從來未面李先生，借我西窗卧月明。", "二十三家同願識，素騾何日暫還城。"]'),
('9675294f-ff85-46ac-addd-a174ae12d9a3','題畫石山','徐鉉','宋','宋诗','song-poetry','','[]','彼美巉巖石，誰施黼藻功。',96,'全唐诗/poet.song.0.json','["彼美巉巖石，誰施黼藻功。", "回巖明照地，絕壁爛臨空。", "錦段鮮須濯，羅屏展易窮。", "不因秋蘚綠，非假晚霞紅。", "羽客藏書洞，樵人取箭風。", "靈蹤理難問，仙路去何通。", "返駕歸塵裏，留情向此中。", "迴瞻畫圖畔，遥羨面山翁。"]'),
('4cfa5f64-7102-483b-b812-d5afc0f19bf0','臨石步港','徐鉉','宋','宋诗','song-poetry','','[]','碕岸隳縈带，微風起細漣。',48,'全唐诗/poet.song.0.json','["碕岸隳縈带，微風起細漣。", "綠陰三月後，倒影亂峰前。", "吹浪游鱗小，黏苔碎石圓。", "會將腰下組，換取釣魚船。"]'),
('5f7d9c36-f209-4f3c-8b17-d97016729431','病題二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','性靈慵懶百無能，唯被朝參遣夙興。',64,'全唐诗/poet.song.0.json','["性靈慵懶百無能，唯被朝參遣夙興。", "聖主優容恩未答，丹經疏闊病相陵。", "脾傷對客偏愁酒，眼暗看書每愧燈。", "進與時乖不知退，可憐身計謾騰騰。"]'),
('57163298-780e-44cb-8dc4-9e825469b88b','病題二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','人間多事本難論，况是人間懶慢人。',64,'全唐诗/poet.song.0.json','["人間多事本難論，况是人間懶慢人。", "不解養生何怪病，已能知命敢辭貧。", "向空咄咄煩書字，與世滔滔莫問津。", "金馬門前君識否，東方曼倩是前身。"]'),
('b766d7a8-383e-4b18-b46c-d2e3c49eb8c2','寄江州蕭給事','徐鉉','宋','宋诗','song-poetry','','[]','夕郎憂國不憂身，今向天涯作逐臣。',64,'全唐诗/poet.song.0.json','["夕郎憂國不憂身，今向天涯作逐臣。", "魂夢暗馳龍闕曙，嘯吟閒繞虎谿春。", "朝車載酒過山寺，諫紙題詩寄野人。", "惆悵懦夫何足道，自離羣後已同塵。"]'),
('b45c54e6-4006-418b-b097-ed4eb05d9561','和江州江中丞見寄','徐鉉','宋','宋诗','song-poetry','','[]','賈傅南遷久，江關道路遥。',48,'全唐诗/poet.song.0.json','["賈傅南遷久，江關道路遥。", "北來空見雁，西去不如潮。", "鼠穴依城社，鴻飛在泬寥。", "高低各有處，不擬更相招。"]'),
('c636e3c6-2c75-4bb2-a4d2-b95d4fd783eb','和鍾郎中送朱先輩還京垂寄','徐鉉','宋','宋诗','song-poetry','','[]','分司洗馬無人問，辭客殷勤輟棹歌。',64,'全唐诗/poet.song.0.json','["分司洗馬無人問，辭客殷勤輟棹歌。", "蒼蘚滿庭行徑小，高梧臨檻雨聲多。", "春愁盡付千盃酒，鄉思遥聞一曲歌。", "且共勝遊消永日，西岡風物近如何。"]'),
('85d45809-a8b3-47a7-9893-f26701dc3082','送郝郎中爲浙西判官','徐鉉','宋','宋诗','song-poetry','','[]','大藩從事本優賢，幕府仍當北固前。',64,'全唐诗/poet.song.0.json','["大藩從事本優賢，幕府仍當北固前。", "花繞樓臺山倚郭，寺臨江海水連天。", "恐君到即忘歸日，憶我遊曾歷二年。", "若許他時作閒伴，殷勤爲買釣魚船。"]'),
('c9582d70-dc2f-437d-9659-e4aaca96ff77','翰林游舍人清明日入院中塗見過余明日亦入西省上直因寄游君','徐鉉','宋','宋诗','song-poetry','','[]','榆柳開新焰，梨花發故枝。',48,'全唐诗/poet.song.0.json','["榆柳開新焰，梨花發故枝。", "輜軿隘城市，圭組坐曹司。", "獨對芝泥檢，遥憐白馬兒。", "禁林還視草，氣味兩相知。"]'),
('1e2d575d-e435-467a-a6a7-891d96228db5','陪王庶子游後湖涵虛閣','徐鉉','宋','宋诗','song-poetry','','[]','懸圃清虛乍過秋，看山尋水上茲樓。',64,'全唐诗/poet.song.0.json','["懸圃清虛乍過秋，看山尋水上茲樓。", "輕鷗的的飛難沒，紅葉紛紛晚更稠。", "風卷微雲分遠岫，浪摇晴日照中州。", "躋攀況有承華客，如在南皮奉勝遊。"]'),
('847a848c-5f1a-4caa-b058-08f67def9beb','柳枝辭十二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','把酒憑君唱柳枝，也從絲管遞相隨。',32,'全唐诗/poet.song.0.json','["把酒憑君唱柳枝，也從絲管遞相隨。", "逢春只合朝朝醉，記取秋風落葉時。"]'),
('77f217c5-be81-4db0-a452-fb520b372b25','柳枝辭十二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','南園日暮起春風，吹散楊花雪滿空。',32,'全唐诗/poet.song.0.json','["南園日暮起春風，吹散楊花雪滿空。", "不惜楊花飛也得，愁君老盡臉邊紅。"]'),
('b039b3ae-97c6-4991-8581-bfa3be4b16bb','柳枝辭十二首  其三','徐鉉','宋','宋诗','song-poetry','','[]','陌上朱門柳映花，簾鈎半卷綠陰斜。',32,'全唐诗/poet.song.0.json','["陌上朱門柳映花，簾鈎半卷綠陰斜。", "憑郎暫駐青驄馬，此是錢塘小小家。"]'),
('3aef44d7-2482-496e-aa68-bdaa6bbbc4de','柳枝辭十二首  其四','徐鉉','宋','宋诗','song-poetry','','[]','夾岸朱欄柳映樓，綠波平幔带花流。',32,'全唐诗/poet.song.0.json','["夾岸朱欄柳映樓，綠波平幔带花流。", "歌聲不出長條密，忽地風迴見綵舟。"]'),
('ce133744-8a1c-45cb-9423-b42a01a2b270','柳枝辭十二首  其五','徐鉉','宋','宋诗','song-poetry','','[]','老大逢春總恨春，綠楊陰裏最愁人。',32,'全唐诗/poet.song.0.json','["老大逢春總恨春，綠楊陰裏最愁人。", "舊游一別無因見，嫩葉如眉處處新。"]'),
('4fe4c1fe-92be-43c5-9030-620957c9c72d','柳枝辭十二首  其六','徐鉉','宋','宋诗','song-poetry','','[]','濛濛堤畔柳含烟，疑是陽和二月天。',32,'全唐诗/poet.song.0.json','["濛濛堤畔柳含烟，疑是陽和二月天。", "醉裏不知時節改，漫隨兒女打鞦韆。"]'),
('7ef56d7c-c31f-494f-9f15-89e8ad508b75','柳枝辭十二首  其七','徐鉉','宋','宋诗','song-poetry','','[]','水閣春來乍減寒，曉妝初罷倚欄干。',32,'全唐诗/poet.song.0.json','["水閣春來乍減寒，曉妝初罷倚欄干。", "長條亂拂春波動，不許佳人照影看。"]'),
('45092445-09ad-44be-95cf-70073d45a49c','柳枝辭十二首  其八','徐鉉','宋','宋诗','song-poetry','','[]','柳岸烟昏醉裏歸，不知深處有芳菲。',32,'全唐诗/poet.song.0.json','["柳岸烟昏醉裏歸，不知深處有芳菲。", "重來已見花飄盡，唯有黄鶑囀樹飛。"]'),
('30c275b2-8684-49d1-8f99-a794396954be','柳枝辭十二首  其九','徐鉉','宋','宋诗','song-poetry','','[]','此去仙源不是遥，垂楊深處有朱橋。',32,'全唐诗/poet.song.0.json','["此去仙源不是遥，垂楊深處有朱橋。", "共君同過朱橋去，密映垂楊聽洞簫。"]'),
('8a1442cd-a75c-429c-ac28-cc5e9ed9353b','柳枝辭十二首  其一○','徐鉉','宋','宋诗','song-poetry','','[]','暫別揚州十度春，不知光景屬何人。',32,'全唐诗/poet.song.0.json','["暫別揚州十度春，不知光景屬何人。", "一帆歸客千條柳，腸斷東風揚子津。"]'),
('72eced1e-7014-4fbc-a360-36d40bb2cca3','柳枝辭十二首  其一一','徐鉉','宋','宋诗','song-poetry','','[]','仙樂春來案舞腰，清聲偏似傍嬌饒。',32,'全唐诗/poet.song.0.json','["仙樂春來案舞腰，清聲偏似傍嬌饒。", "應緣鶑舌多情頼，長向雙成說翠條。"]'),
('48fdd8da-b23e-4e27-b542-00ce99fd63cd','柳枝辭十二首  其一二','徐鉉','宋','宋诗','song-poetry','','[]','鳳笙臨檻不能吹，舞袖當筵亦自疑。',32,'全唐诗/poet.song.0.json','["鳳笙臨檻不能吹，舞袖當筵亦自疑。", "唯有美人多意緒，解衣芳態畫雙眉。"]'),
('5199b72c-cf8c-4ed3-97ac-b538ba2f35a8','貶官泰州出城作','徐鉉','宋','宋诗','song-poetry','','[]','浮名浮利信悠悠，四海干戈痛主憂。',64,'全唐诗/poet.song.0.json','["浮名浮利信悠悠，四海干戈痛主憂。", "三諫不從爲逐客，一身無累似虛舟。", "滿朝權貴皆曾忤，繞郭林泉已徧游。", "唯有戀恩終不改，半程猶自望城樓。"]'),
('7c0fa407-cfd3-4264-a9db-bf21254f8614','過江','徐鉉','宋','宋诗','song-poetry','','[]','別路知何極，離腸有所思。',48,'全唐诗/poet.song.0.json','["別路知何極，離腸有所思。", "登樓望城遠，摇櫓過江遲。", "斷岸烟中失，長天水際垂。", "此心非橘柚，不爲兩鄉移。"]'),
('b1740149-abbf-4af3-89d6-908b6a44e196','經東都太子橋','徐鉉','宋','宋诗','song-poetry','','[]','綸闈放逐知何道，桂苑風流且暫歸。',32,'全唐诗/poet.song.0.json','["綸闈放逐知何道，桂苑風流且暫歸。", "莫問升遷橋上客，身謀疏拙舊心違。"]'),
('a42af670-1dc2-4202-8edc-b61424a62c5e','贈維揚故人','徐鉉','宋','宋诗','song-poetry','','[]','東京少長認維桑，書劍誰教入帝鄉。',64,'全唐诗/poet.song.0.json','["東京少長認維桑，書劍誰教入帝鄉。", "一事無成空放逐，故人相見重淒涼。", "樓臺寂寞官河晚，人物稀疏驛路長。", "莫怪臨風惆悵久，十年春色憶維揚。"]'),
('f607fd78-3f86-4b22-9b1b-45699a90ec6e','泰州道中却寄東京故人','徐鉉','宋','宋诗','song-poetry','','[]','風緊雨淒淒，川迴岸漸低。',48,'全唐诗/poet.song.0.json','["風緊雨淒淒，川迴岸漸低。", "吳州林外近，隋苑霧中迷。", "聚散紛如此，悲歡豈易齊。", "料君殘酒醒，還聽子規啼。"]'),
('036e6c0c-d77f-4049-b9d1-9743a482661a','得浙西郝判官書未及報聞燕王移鎮京口因寄此詩問方判官田書記消息','徐鉉','宋','宋诗','song-poetry','','[]','秋風海上久離居，曾得劉公一紙書。',64,'全唐诗/poet.song.0.json','["秋風海上久離居，曾得劉公一紙書。", "淡水心情長若此，銀鈎蹤迹更無如。", "嘗憂座側飛鴞鳥，未暇江中覓鯉魚。", "今日京吳建朱邸，問君誰共曳長裾。"]'),
('e167e3b0-eb6b-4b84-b8b9-131bad2b352c','贈陶使君求梨','徐鉉','宋','宋诗','song-poetry','','[]','昨宵宴罷醉如泥，惟憶張公大谷梨。',64,'全唐诗/poet.song.0.json','["昨宵宴罷醉如泥，惟憶張公大谷梨。", "白玉花繁曾綴處，黄金色嫩乍成時。", "冷侵肺腑醒偏蚤，香惹衣襟歇倍遲。", "今旦中山方酒渴，唯應此物最相宜。"]'),
('4be4ab5e-1b08-48a0-ac31-5157af0bb657','陳覺放還至泰州以詩見寄作此答之','徐鉉','宋','宋诗','song-poetry','','[]','朱雲曾爲漢家憂，不怕交親作世仇。',64,'全唐诗/poet.song.0.json','["朱雲曾爲漢家憂，不怕交親作世仇。", "壯氣未平空咄咄，狂言無驗信悠悠。", "今朝我作傷弓鳥，却羨君爲不繫舟。", "勞寄新詩平宿憾，此生心氣貫清秋。"]'),
('3fb479b5-fe67-4fa3-acd1-1b2260bdaea2','王三十七自京垂訪作此送之','徐鉉','宋','宋诗','song-poetry','','[]','失鄉遷客在天涯，門掩苔垣向水斜。',64,'全唐诗/poet.song.0.json','["失鄉遷客在天涯，門掩苔垣向水斜。", "只就鱗鴻求遠信，敢言車馬訪貧家。", "烟生柳岸將垂縷，雪壓梅園半是花。", "惆悵明朝罇酒散，夢魂相送到京華。"]'),
('19a4d427-64d3-4549-b762-313f4937ae81','陶使君挽歌二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','太守今何在，行春去不歸。',48,'全唐诗/poet.song.0.json','["太守今何在，行春去不歸。", "筵空收管吹，郊迥儼驂騑。", "營外星纔落，園中露已晞。", "傷心梁上燕，猶解向人飛。"]'),
('4b7734cd-ada1-45b2-b03a-66d1f2b6ec41','陶使君挽歌二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','始憶花前宴，笙歌醉夕陽。',48,'全唐诗/poet.song.0.json','["始憶花前宴，笙歌醉夕陽。", "那堪城外送，哀挽逐歸艎。", "鈴閣朝猶閉，風亭日已荒。", "唯餘遷客淚，霑灑後池傍。"]'),
('76b46612-d86f-460f-83a6-2432caf2adb1','雪中作','徐鉉','宋','宋诗','song-poetry','','[]','賦分多情客，經年去國心。',48,'全唐诗/poet.song.0.json','["賦分多情客，經年去國心。", "疏鐘寒郭晚，密雪水亭深。", "影迥鴻投渚，聲愁雀噪林。", "他鄉一罇酒，獨坐不成斟。"]'),
('bb2fbe48-2414-4cca-a8aa-6696cb4e958e','賦得風光草際浮','徐鉉','宋','宋诗','song-poetry','','[]','宿露依芳草，春郊古陌旁。',72,'全唐诗/poet.song.0.json','["宿露依芳草，春郊古陌旁。", "風輕不盡偃，日早未晞陽。", "耿耿依平遠，離離入望長。", "映空無定彩，飄逕有餘光。", "颭若荷珠亂，紛如爝火颺。", "詩人多感物，凝思繞池塘。"]'),
('db1a4c66-673c-4c42-a852-d7da92d44a12','寒食成判官垂訪因贈','徐鉉','宋','宋诗','song-poetry','','[]','常年寒食在京華，今歲清明在海涯。',64,'全唐诗/poet.song.0.json','["常年寒食在京華，今歲清明在海涯。", "遠巷蹋歌深夜月，隔牆吹管數枝花。", "鴛鸞得路音塵闊，鴻雁分飛道里賒。", "不是多情成二十，斷無人解訪貧家。"]'),
('acb910be-9872-40ab-a7cf-cf1f651d9bb9','送客至城西望圖山因寄浙西府中','徐鉉','宋','宋诗','song-poetry','','[]','枚叟鄒生笑語同，莫嗟江上聽秋風。',32,'全唐诗/poet.song.0.json','["枚叟鄒生笑語同，莫嗟江上聽秋風。", "君看逐客思鄉處，猶在圖山更向東。"]'),
('5995feea-2bdf-45ef-88cb-2ba76b83b14c','送寫真成處士入京','徐鉉','宋','宋诗','song-poetry','','[]','傳神蹤迹本來高，澤畔形容愧彩毫。',32,'全唐诗/poet.song.0.json','["傳神蹤迹本來高，澤畔形容愧彩毫。", "京邑功臣多佇望，凌烟閣上莫辭勞。"]'),
('4df688b2-71ac-4e76-b1e3-388566745c97','九日雨中','徐鉉','宋','宋诗','song-poetry','','[]','茱萸房重雨霏微，去國逢秋此恨稀。',64,'全唐诗/poet.song.0.json','["茱萸房重雨霏微，去國逢秋此恨稀。", "目極暫登臺上望，心遥長向夢中歸。", "荃蘼路遠愁霜早，兄弟鄉遥羨雁飛。", "唯有多情一枝菊，滿盃顔色自依依。"]'),
('4f917d6a-2317-4d38-9e09-284f106acd85','寄外甥苗武仲','徐鉉','宋','宋诗','song-poetry','','[]','放逐今來漲海邊，親情多在鳳臺前。',64,'全唐诗/poet.song.0.json','["放逐今來漲海邊，親情多在鳳臺前。", "且將聚散爲閑事，須信華枯是偶然。", "蟬噪疏林村倚郭，鳥飛殘照水連天。", "此中唯欠韓康伯，共對秋風詠數篇。"]'),
('9c78024b-5cfa-4be6-83bc-bc7a14e20812','寄從兄憲兼示二弟','徐鉉','宋','宋诗','song-poetry','','[]','別路吳將楚，離憂弟與兄。',48,'全唐诗/poet.song.0.json','["別路吳將楚，離憂弟與兄。", "斷雲驚晚吹，秋色滿孤城。", "信遠鴻初下，鄉遥月共明。", "一枝棲未穩，迴首望三京。"]'),
('098e34f3-6741-424e-b278-b28e9f5ccda5','附書與鍾郎中因寄京妓越賓','徐鉉','宋','宋诗','song-poetry','','[]','暮春橋下手封書，寄向南江問越姑。',32,'全唐诗/poet.song.0.json','["暮春橋下手封書，寄向南江問越姑。", "不道諸郎少歡笑，經年相別憶儂無。"]'),
('d01fd2f0-8653-4cfe-8ab4-18515146976b','亞元舍人不替深知猥貽佳作三篇清絕不敢輕酬因爲長歌聊以爲報未竟復得子喬校書示問故兼寄陳君庶資一笑耳','徐鉉','宋','宋诗','song-poetry','','[]','海陵城裏春正月，海畔朝陽照殘雪。',384,'全唐诗/poet.song.0.json','["海陵城裏春正月，海畔朝陽照殘雪。", "城中有客獨登樓，遥望天邊白銀闕。", "白銀闕下何英英，雕鞍繡轂趨承明。", "閶門曉闢旌旗影，玉墀風細佩環聲。", "此處追飛皆俊彥，當年何事容疵賤。", "懷鉛晝坐紫微宮，焚香夜直明光殿。", "王言簡靜官司閑，朋好殷勤多往還。", "新亭風景如東洛，邙嶺林泉似北山。", "光陰暗度盃盂裏，職業未妨談笑間。", "有時邀賓復携妓，造門不問都非是。", "酣歌叫笑驚四鄰，賦筆蹤橫動千字。", "任他銀箭轉更籌，不怕金吾司夜吏。", "可憐諸貴賢且才，時情物望兩無猜。", "伊余獨稟狂狷性，褊量多言仍薄命。", "吞舟可漏豈無恩，負乘自貽非不幸。", "一朝削跡爲遷客，旦暮青雲千里隔。", "離鴻別雁各分飛，折柳攀花兩無色。", "盧龍渡口問迷津，瓜步山前送暮春。", "白沙江上曾行路，青林花落何紛紛。", "漢皇昔幸回中道，極目牛羊卧芳草。", "舊宅重遊盡隙荒，故人相見多衰老。", "禪智寺，山光橋，風瑟瑟兮雨蕭蕭。", "行盃已醒殘夢斷，征途未極離魂消。", "海陵郡中陶太守，相逢本是隨行舊。"]'),
('0c63a208-41d6-4166-808c-eb6153bb4c5b','送蒯司錄歸京亮','徐鉉','宋','宋诗','song-poetry','','[]','早年聞有蒯先生，二十餘年道不行。',64,'全唐诗/poet.song.0.json','["早年聞有蒯先生，二十餘年道不行。", "抵掌曾論天下事，折腰猶悟俗人情。", "老還上國歡娛少，貧聚歸資結束輕。", "遷客臨流倍惆悵，冷風黄葉滿山城。"]'),
('15064aa1-9a3f-4217-89c7-3abf0c4b2d16','聞查建州陷賊寄鍾郎中','徐鉉','宋','宋诗','song-poetry','','[]','聞道將軍輕壯圖，螺江城下委犀渠。',64,'全唐诗/poet.song.0.json','["聞道將軍輕壯圖，螺江城下委犀渠。", "旌旗零落沉荒服，簪履蕭條返故居。", "皓首應全蘇武節，故人誰得李陵書。", "自憐放逐無長策，空使盧諶淚滿裾。"]'),
('4f0996b3-1ea5-444b-b2b4-777fa6d82f67','還過東都留守周公筵上贈座客','徐鉉','宋','宋诗','song-poetry','','[]','賈生三載在長沙，故友相思道路賒。',64,'全唐诗/poet.song.0.json','["賈生三載在長沙，故友相思道路賒。", "已分終年甘寂寞，豈知今日返京華。", "麟符上相恩偏厚，隋苑留歡日欲斜。", "明旦江頭倍惆悵，遠山芳草映殘霞。"]'),
('9e056811-da44-4da5-b91e-510979a88da3','送楊郎中唐員外奉使湖南','徐鉉','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','江邊微雨柳條新，握節含香二使臣。',64,'全唐诗/poet.song.0.json','["江邊微雨柳條新，握節含香二使臣。", "兩綬對懸雲夢日，方舟齊汎洞庭春。", "今朝草木逢新律，昨日山川滿戰塵。", "同是多情懷古客，不妨爲賦弔靈均。"]'),
('4bfe1bef-8110-424d-aa77-acb88664bfb0','和表弟包潁見寄','徐鉉','宋','宋诗','song-poetry','','[]','平生中表最情親，浮世那堪聚散頻。',64,'全唐诗/poet.song.0.json','["平生中表最情親，浮世那堪聚散頻。", "謝脁却吟歸省閣，劉楨猶自卧漳濱。", "舊游半似前生事，要路多逢後進人。", "且喜新吟報强健，明年相望杏園春。"]'),
('601923bc-05a5-4cd7-8475-388d4e5738a1','寄蕭給事','徐鉉','宋','宋诗','song-poetry','','[]','危言危行古時人，歸向西山卧白雲。',64,'全唐诗/poet.song.0.json','["危言危行古時人，歸向西山卧白雲。", "買宅尚尋徐處士，餐霞終訪許真君。", "容顔別後應如故，詩詠年來更不聞。", "今日城中春又至，落梅愁緒共紛紛。"]'),
('3e02ad91-3b23-45b7-b43d-9313b2225df3','賦石奉送德林少尹員外并序','徐鉉','宋','宋诗','song-poetry','','[]','我愛他山石，中含絕代珍。',48,'全唐诗/poet.song.0.json','["我愛他山石，中含絕代珍。", "烟披寒落落，沙淺靜磷磷。", "翠色辭文陛，清聲出泗濱。", "扁舟載歸去，知是汎槎人。"]'),
('fb3d8ae1-6321-4fef-901b-780631ab9787','贈泰州掾令狐克己','徐鉉','宋','宋诗','song-poetry','','[]','念子才多命且奇，亂中拋擲少年時。',64,'全唐诗/poet.song.0.json','["念子才多命且奇，亂中拋擲少年時。", "深藏七澤衣如雪，却見中朝鬢似絲。", "舊德在人終遠大，扁舟爲吏莫推辭。", "孤芳自愛凌霜處，詠取文公白菊詩。"]'),
('38ff457a-0171-442d-9893-f33b8a245125','送荻柴與秀才朱觀','徐鉉','宋','宋诗','song-poetry','','[]','羨子清吟處，茅齋面碧流。',48,'全唐诗/poet.song.0.json','["羨子清吟處，茅齋面碧流。", "解憎蓮艷俗，唯欠荻花幽。", "鷺立低枝晚，風驚折葉秋。", "贈君須種取，不必樹忘憂。"]'),
('4e1a4d68-56e6-4d68-9384-8c50f04f171e','使浙西先寄獻燕王侍中','徐鉉','宋','宋诗','song-poetry','','[]','京江風靜喜乘流，極目遥瞻萬歲樓。',64,'全唐诗/poet.song.0.json','["京江風靜喜乘流，極目遥瞻萬歲樓。", "喜氣蘢葱甘露晚，水烟波淡海門秋。", "五年不見鸞臺長，明日將陪兔苑遊。", "欲問平臺門下吏，相君還許吐茵不。"]'),
('682a1346-b702-42fd-a5c6-728d7c3eccb9','常州驛中喜雨','徐鉉','宋','宋诗','song-poetry','','[]','颯颯旱天雨，凉風一夕迴。',48,'全唐诗/poet.song.0.json','["颯颯旱天雨，凉風一夕迴。", "遠尋南畝去，細入驛亭來。", "蓑唱牛初牧，漁歌棹正開。", "盈庭頓無事，歸思酌金罍。"]'),
('328db973-3288-4f0d-85db-6ea6cc000a3e','驛中七夕','徐鉉','宋','宋诗','song-poetry','','[]','七夕雨初霽，行人正憶家。',48,'全唐诗/poet.song.0.json','["七夕雨初霽，行人正憶家。", "江天望河漢，水館折蓮花。", "獨坐凉何甚，微吟月易斜。", "今年不乞巧，鈍拙轉堪嗟。"]'),
('9c4de8b9-7944-4331-b2e2-0cffc686c8e2','贈浙西顧推官','徐鉉','宋','宋诗','song-poetry','','[]','盛府賓寮八十餘，閉門高卧興無如。',64,'全唐诗/poet.song.0.json','["盛府賓寮八十餘，閉門高卧興無如。", "梁王苑裏相逢早，澗浦城中得信疏。", "狼藉杯盤重會面，風流才調一如初。", "願君百歲猶强健，他日相尋隠士廬。"]'),
('b625b12a-21f1-4a67-845d-b44cbb985679','贈浙西妓亞仙','徐鉉','宋','宋诗','song-poetry','','[]','翠黛嚬如怨，朱顔醉更春。',48,'全唐诗/poet.song.0.json','["翠黛嚬如怨，朱顔醉更春。", "占將南國貌，惱殺別家人。", "粉汗沾巡盞，花鈿逐舞茵。", "明朝綺窗下，離恨兩殷勤。"]'),
('3246ff39-7a84-45e1-8f26-b58af173eca8','迴至瓜洲獻侍中','徐鉉','宋','宋诗','song-poetry','','[]','紫微垣裏舊賓從，來向吳門謁府公。',64,'全唐诗/poet.song.0.json','["紫微垣裏舊賓從，來向吳門謁府公。", "奉使謬持嚴助節，登門初識魯王宮。", "笙歌隠隠違離後，烟水茫茫悵望中。", "日暮瓜洲江北岸，兩行清淚滴西風。"]'),
('97da6aa7-cf76-4e01-ab3d-981dedadeb30','邵伯埭下寄高郵陳郎中','徐鉉','宋','宋诗','song-poetry','','[]','故人相別動經年，候館相逢倍慘然。',64,'全唐诗/poet.song.0.json','["故人相別動經年，候館相逢倍慘然。", "顧我飲冰難輟棹，感君扶病爲開筵。", "河灣水淺翹愁鷺，柳岸風微噪暮蟬。", "欲識酒醒魂斷處，謝公祠畔客亭前。"]'),
('a39d5dce-c295-49bd-88eb-7957ec3ff449','謫居舒州累得韓高二舍人書作此寄之','徐鉉','宋','宋诗','song-poetry','','[]','三峰烟靄碧臨谿，中有騷人理釣絲。',64,'全唐诗/poet.song.0.json','["三峰烟靄碧臨谿，中有騷人理釣絲。", "會友少於分袂日，謫居多却在朝時。", "丹心歷歷吾終信，俗慮悠悠爾不知。", "珍重韓君與高子，殷勤書札寄相思。"]'),
('1c4fa2d2-8b24-4ce8-8f9e-e7729fda8311','和張先輩見寄二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','去國離羣擲歲華，病容憔悴愧丹沙。',64,'全唐诗/poet.song.0.json','["去國離羣擲歲華，病容憔悴愧丹沙。", "谿連舍下衣長潤，山带城邊日易斜。", "幾處垂鈎依野岸，有時披褐到鄉家。", "故人書札頻相慰，誰道西京道路賒。"]'),
('98dd713c-7676-45ef-ba3d-d8e87d090111','和張先輩見寄二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','清時淪放在山州，邛竹紗巾處處游。',64,'全唐诗/poet.song.0.json','["清時淪放在山州，邛竹紗巾處處游。", "野日蒼茫悲鵬舍，水風陰濕弊貂裘。", "雞鳴候旦寧辭晦，松節凌霜幾換秋。", "兩首新詩千里道，感君情分獨知丘。"]'),
('beef46b3-d094-4907-ab78-d21746db56f7','印秀才至舒州見尋別後寄詩依韻和','徐鉉','宋','宋诗','song-poetry','','[]','羈游白社身雖屈，高步辭場道不卑。',64,'全唐诗/poet.song.0.json','["羈游白社身雖屈，高步辭場道不卑。", "投分共爲知我者，相尋多愧謫居時。", "離懷耿耿年來夢，厚意勤勤別後詩。", "今日谿邊正相憶，雪晴山秀柳絲垂。"]'),
('d7d3fa70-7034-4af3-9ac2-245c6a93d353','行園樹','徐鉉','宋','宋诗','song-poetry','','[]','松節凌霜久，蓬根逐吹頻。',24,'全唐诗/poet.song.0.json','["松節凌霜久，蓬根逐吹頻。", "羣生各有性，桃李但爭春。"]'),
('ed5ad5bb-7fa9-4537-a921-1b4f4eea0705','題雷公井','徐鉉','宋','宋诗','song-poetry','','[]','掩靄愚公谷，蕭寥羽客家。',24,'全唐诗/poet.song.0.json','["掩靄愚公谷，蕭寥羽客家。", "俗人知處所，應爲有桃花。"]'),
('7e7d686b-d7ba-4dd8-b16b-cbd3a538216c','送彭秀才','徐鉉','宋','宋诗','song-poetry','','[]','賈生去國已三年，短褐閑行皖水邊。',64,'全唐诗/poet.song.0.json','["賈生去國已三年，短褐閑行皖水邊。", "盡日野雲生舍下，有時京信到門前。", "無人與和投湘賦，愧子來浮訪戴船。", "滿袖新詩好迴去，莫隨騷客醉林泉。"]'),
('a9d8fc56-bf5a-4c12-8c23-e69c5c29f101','移饒州別周使君','徐鉉','宋','宋诗','song-poetry','','[]','正憐東道感賢侯，何幸高冠脫楚囚。',64,'全唐诗/poet.song.0.json','["正憐東道感賢侯，何幸高冠脫楚囚。", "皖伯臺前收別宴，喬公亭下艤行舟。", "四年去國身將老，百郡徵兵主尚憂。", "更向鄱陽河上去，青衫憔悴淚交流。"]'),
('6d2dfa39-7b5e-4468-bbdd-88e2ca6d4f0f','避難東歸依韻和黄秀才見寄','徐鉉','宋','宋诗','song-poetry','','[]','慼慼逢人問所之，東流相送向京畿。',64,'全唐诗/poet.song.0.json','["慼慼逢人問所之，東流相送向京畿。", "自甘逐客紉蘭佩，不料平民著戰衣。", "樹带荒村春冷落，江澄霽色霧霏微。", "時危道喪無才術，空手徘徊不忍歸。"]'),
('c55f549d-4887-442d-83a8-ae464761b8bc','酬郭先輩','徐鉉','宋','宋诗','song-poetry','','[]','太原郭夫子，行高文炳蔚。',192,'全唐诗/poet.song.0.json','["太原郭夫子，行高文炳蔚。", "弱齡負世譽，一舉游月窟。", "仙籍第三人，時人故稱屈。", "昔余吏西省，傾蓋名籍籍。", "及我竄羣舒，向風心鬰鬰。", "歸來暮江上，雲霧一披拂。", "雷雨不下施，猶作池中物。", "念君介然氣，感時思奮發。", "示我數篇文，與古爭馳突。", "綵縟粲英華，理深刮肌骨。", "古詩尤精奧，史論皆宏拔。", "舉此措諸民，何憂民不活。", "吁嗟吾道薄，與世長迂闊。", "顧我徒有心，數奇身正絀。", "論兵屬少年，經國須儒術。", "夫子無自輕，蒼生正愁疾。"]'),
('df9150ea-9e88-4111-9d6d-6f55ab29e5ff','和集賢鍾郎中','徐鉉','宋','宋诗','song-poetry','','[]','石渠冊府神仙署，當用明朝第一人。',64,'全唐诗/poet.song.0.json','["石渠冊府神仙署，當用明朝第一人。", "腰下別懸新印綬，堂中皆是故交親。", "龍池樹色供清景，浴殿香風接近鄰。", "從此翻飛應更遠，徧尋三十六天春。"]'),
('c48f4ea5-666e-4f98-9511-5d841821c9ca','送劉山陽','徐鉉','宋','宋诗','song-poetry','','[]','舊族知名士，朱衣宰楚城。',48,'全唐诗/poet.song.0.json','["舊族知名士，朱衣宰楚城。", "所嗟吾道薄，豈是主恩輕。", "戰鼓何時息，儒冠獨自行。", "此心多感激，相送若爲情。"]'),
('13c55cc8-f14a-4cf5-8a80-325be26887c2','題伏龜山北隅','徐鉉','宋','宋诗','song-poetry','','[]','茲山信岑寂，陰崖積蒼翠。',72,'全唐诗/poet.song.0.json','["茲山信岑寂，陰崖積蒼翠。", "水石何必多，宛有千巖意。", "孰知近人境，旦暮含佳氣。", "池影摇輕風，林光澹新霽。", "支頤藉芳草，自足忘世事。", "未得歸去來，聊爲宴居地。"]'),
('6020c922-18ab-4981-aeec-08a63a6e98be','送黄梅江明府','徐鉉','宋','宋诗','song-poetry','','[]','封疆多難正經綸，臺閣如何不用君。',64,'全唐诗/poet.song.0.json','["封疆多難正經綸，臺閣如何不用君。", "江上又勞爲小邑，篋中徒自有雄文。", "書生膽氣人誰信，遠俗歌謠主不聞。", "一首新詩無限意，再三吟咏向秋雲。"]'),
('92161169-3fed-4b3e-88e9-fbbb39da32c9','詠梅子真送郭先輩','徐鉉','宋','宋诗','song-poetry','','[]','忠臣本愛君，仁人本愛民。',120,'全唐诗/poet.song.0.json','["忠臣本愛君，仁人本愛民。", "寧知貴與賤，豈計名與身。", "梅生爲一尉，獻疏來君門。", "君門深萬里，金虎重千鈞。", "向永且不用，況復論子真。", "拂衣遂長往，高節邈無鄰。", "至今仙籍中，謂之梅真人。", "郭生負逸氣，百代繼遺塵。", "進退生自知，得喪吾不陳。", "斯民苟有幸，期子一朝伸。"]'),
('0deb8bbf-286d-48e7-bb4c-e2320b03b4ba','和蕭郎中午日見寄','徐鉉','宋','宋诗','song-poetry','','[]','細雨輕風采藥時，褰簾隠几更何爲。',64,'全唐诗/poet.song.0.json','["細雨輕風采藥時，褰簾隠几更何爲。", "豈知澤畔紉蘭客，來赴城中角黍期。", "多罪靜思如剉蘗，赦書纔聽似含飴。", "謝公制勝常閑暇，願接西州敵手棋。"]'),
('c1aee997-718f-4316-8be5-367e0bd7bd82','送黄秀才姑熟辟命','徐鉉','宋','宋诗','song-poetry','','[]','世亂離情苦，家貧色養難。',48,'全唐诗/poet.song.0.json','["世亂離情苦，家貧色養難。", "水雲孤棹去，風雨暮春寒。", "幕府才方急，騷人淚未乾。", "何時王道泰，萬里看鵬摶。"]'),
('e7b2fb25-3fc6-40f9-b30d-f0d7f6a539d0','送王四十五歸東都','徐鉉','宋','宋诗','song-poetry','','["\u79bb\u522b", "\u9001\u522b"]','海內兵方起，離筵淚易垂。',48,'全唐诗/poet.song.0.json','["海內兵方起，離筵淚易垂。", "憐君負米去，惜此落花時。", "想憶看來信，相寬指後期。", "殷勤手中柳，此是向南枝。"]'),
('aab9a7e7-68cd-4ce3-9740-b8992f22b082','和太常蕭少卿近郊馬上偶吟  其一','徐鉉','宋','宋诗','song-poetry','','[]','田園經雨綠分畦，飛蓋閑行九里堤。',64,'全唐诗/poet.song.0.json','["田園經雨綠分畦，飛蓋閑行九里堤。", "拂袖清風塵不起，滿川芳草路如迷。", "林開始覺晴天迥，潮上初驚浦岸齊。", "怪得仙郎詩句好，斷霞殘照遠山西。"]'),
('85628cdd-285f-429d-8eab-0919ee78eef0','和太常蕭少卿近郊馬上偶吟  其二','徐鉉','宋','宋诗','song-poetry','','[]','抱甕何人灌藥畦，金銜爲爾駐平堤。',64,'全唐诗/poet.song.0.json','["抱甕何人灌藥畦，金銜爲爾駐平堤。", "村橋野店景無限，綠水晴天思欲迷。", "橫笛乍隨輕吹斷，歸帆疑與遠山齊。", "鳳城迴望真堪畫，萬戶千門蔣嶠西。"]'),
('28db2870-ec2c-40af-ae1e-c9b3a710da98','拋毬樂辭二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','歌舞送飛毬，金觥碧玉籌。',36,'全唐诗/poet.song.0.json','["歌舞送飛毬，金觥碧玉籌。", "管弦桃李月，簾幕鳳凰樓。", "一笑千場醉，浮生任白頭。"]'),
('9b5a72d2-42cd-425f-8f10-cb7fd56f40a7','拋毬樂辭二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','灼灼傳花枝，紛紛度畫旂。',36,'全唐诗/poet.song.0.json','["灼灼傳花枝，紛紛度畫旂。", "不知紅燭下，照見彩毬飛。", "借勢因期尅，巫山暮雨歸。"]'),
('a0d83b91-ec22-4b89-99e0-6034a3807d70','離歌辭五首  其一','徐鉉','宋','宋诗','song-poetry','','[]','莫折紅芳樹，但知盡意看。',24,'全唐诗/poet.song.0.json','["莫折紅芳樹，但知盡意看。", "狂風幸無意，那忍折教殘。"]'),
('d34491df-fd4b-49bc-97e1-730cf5bcbed4','離歌辭五首  其二','徐鉉','宋','宋诗','song-poetry','','[]','朝日城南路，旌旗照綠蕪。',24,'全唐诗/poet.song.0.json','["朝日城南路，旌旗照綠蕪。", "使君何處去，桑下覓羅敷。"]'),
('47234c78-fc14-4e4a-a4fb-816e10bceb3a','離歌辭五首  其三','徐鉉','宋','宋诗','song-poetry','','[]','事與年俱往，情將分共深。',24,'全唐诗/poet.song.0.json','["事與年俱往，情將分共深。", "莫驚客鬢改，只是舊時心。"]'),
('d8056244-45fe-4f7c-9d0a-85cee8a335d2','離歌辭五首  其四','徐鉉','宋','宋诗','song-poetry','','[]','暫別勞相送，佳期願莫違。',24,'全唐诗/poet.song.0.json','["暫別勞相送，佳期願莫違。", "朱顔不須老，留取待郎歸。"]'),
('3d868704-6c27-4890-a856-ef160cf66594','離歌辭五首  其五','徐鉉','宋','宋诗','song-poetry','','[]','拂匣收珠佩，迴燈拭薄妝。',24,'全唐诗/poet.song.0.json','["拂匣收珠佩，迴燈拭薄妝。", "莫嫌春夜短，匹似楚襄王。"]'),
('ef6a0261-311a-49a9-a9fa-fac1b630369b','夢游三首  其一','徐鉉','宋','宋诗','song-poetry','','[]','魂夢悠揚不奈何，夜來還在故人家。',64,'全唐诗/poet.song.0.json','["魂夢悠揚不奈何，夜來還在故人家。", "香濛蠟燭時時暗，戶映屏風故故斜。", "檀的慢調銀字管，雲鬟低綴折枝花。", "天明又作人間別，洞口春深道路賒。"]'),
('5b6cd9e2-6d7c-4510-85fd-973ad0d18fb4','夢游三首  其二','徐鉉','宋','宋诗','song-poetry','','[]','繡幌銀屏杳靄間，若非魂夢到應難。',64,'全唐诗/poet.song.0.json','["繡幌銀屏杳靄間，若非魂夢到應難。", "窗前人靜偏宜夜，戶內春濃不識寒。", "蘸甲遞觴織似玉，含詞忍笑膩于檀。", "錦書若要知名字，滿縣花開不姓潘。"]'),
('f08151cc-42cc-4716-aa7e-ee1762ad9312','夢游三首  其三','徐鉉','宋','宋诗','song-poetry','','[]','南國佳人字玉兒，芙蓉雙臉遠山眉。',64,'全唐诗/poet.song.0.json','["南國佳人字玉兒，芙蓉雙臉遠山眉。", "仙郎有約長相憶，阿母無猜不得知。", "夢裏行雲還倏忽，暗中携手乍疑遲。", "因思別後閑窗下，織得迴文幾首詩。"]'),
('3ed739aa-0f4e-4dee-9180-e6d28e121d11','和蕭少卿見慶新居  其一','徐鉉','宋','宋诗','song-poetry','','[]','湘浦懷沙已不疑，京城賜第豈前期。',64,'全唐诗/poet.song.0.json','["湘浦懷沙已不疑，京城賜第豈前期。", "鼓聲到晚知坊遠，山色來多與靜宜。", "簪屨尚應憐故物，稻粱空自愧華池。", "新詩問我偏饒思，還念鷦鷯得一枝。"]'),
('5a28f7a6-b1e8-4920-8eb9-920e99d584ed','和蕭少卿見慶新居  其二','徐鉉','宋','宋诗','song-poetry','','[]','驚蓬偶駐知多幸，斷雁重聯愜素期。',64,'全唐诗/poet.song.0.json','["驚蓬偶駐知多幸，斷雁重聯愜素期。", "當戶小山如舊識，上牆幽蘚最相宜。", "清風不去因栽竹，隙地無多也鑿池。", "更喜良鄰有嘉樹，綠陰分得近南枝。"]'),
('76714d2b-1f8f-4f68-befb-62b4eb661121','送勳道人之建安','徐鉉','宋','宋诗','song-poetry','','[]','下國兵方起，君家義獨聞。',48,'全唐诗/poet.song.0.json','["下國兵方起，君家義獨聞。", "若爲輕世利，歸去卧溪雲。", "掛席衝嵐翠，携筇破蘚紋。", "離情似霜葉，江上正紛紛。"]'),
('64314f4e-e7c7-44ed-b31b-2935aceb853a','送許郎中歙州判官兼黟縣','徐鉉','宋','宋诗','song-poetry','','[]','嘗聞黟縣似桃源，況是優游冠玳筵。',64,'全唐诗/poet.song.0.json','["嘗聞黟縣似桃源，況是優游冠玳筵。", "遺愛非遥應卧理，祖風猶在好尋仙。", "朝衣舊識薰香史，祿米初營種秫田。", "大抵宦游須自適，莫辭離別二三年。"]'),
('d93c4f9b-933b-4770-b350-d8609583ef4f','送彭秀才南游','徐鉉','宋','宋诗','song-poetry','','[]','問君孤棹去何之，玉笥春風楚水西。',64,'全唐诗/poet.song.0.json','["問君孤棹去何之，玉笥春風楚水西。", "山上斷雲分翠靄，林間晴雪入澄溪。", "琴心酒趣神相會，道士仙童手共携。", "他日時清更隨計，莫如劉阮洞中迷。"]'),
('5a8b6d0a-6dd3-4e92-b4e4-2af9f70dbf5b','和明上人除夜見寄','徐鉉','宋','宋诗','song-poetry','','[]','酌酒圍爐久，愁襟默自增。',48,'全唐诗/poet.song.0.json','["酌酒圍爐久，愁襟默自增。", "長年逢歲暮，多病見兵興。", "夜色開庭燎，寒威入硯冰。", "湯師無別念，吟坐一燈凝。"]'),
('b16ab4a7-691b-4e67-8ad5-1a4cc311a077','正初和鄂州邊郎中見寄','徐鉉','宋','宋诗','song-poetry','','[]','潦倒含香客，淒涼賦鵩人。',48,'全唐诗/poet.song.0.json','["潦倒含香客，淒涼賦鵩人。", "未能全卷舌，終擬學垂綸。", "故友暌離久，音書問訊頻。", "相思俱老大，又見一年新。"]'),
('7c1b20d4-0d0c-4f10-a9c6-1e0a36a0bc32','送劉司直出宰','徐鉉','宋','宋诗','song-poetry','','[]','之子有雄文，風標秀不羣。',48,'全唐诗/poet.song.0.json','["之子有雄文，風標秀不羣。", "低飛從墨綬，逸志在青雲。", "柳色臨流動，春光到縣分。", "賢人多靜理，未爽醉醺醺。"]'),
('9e136d21-d006-4c64-885e-0e9079664316','送從兄赴臨川幕','徐鉉','宋','宋诗','song-poetry','','[]','梁王籍寵就東藩，還召鄒枚坐兔園。',64,'全唐诗/poet.song.0.json','["梁王籍寵就東藩，還召鄒枚坐兔園。", "今日好論天下事，昔年同受主人恩。", "石頭城下春潮滿，金柅亭邊綠樹繁。", "唯有音書慰離別，一杯相送別無言。"]'),
('1e2da188-0f34-4f89-9a44-1db6070cf34d','送龔員外赴江州幕','徐鉉','宋','宋诗','song-poetry','','[]','煩君更上築金臺，世難民勞藉俊才。',64,'全唐诗/poet.song.0.json','["煩君更上築金臺，世難民勞藉俊才。", "自有聲名馳羽檄，不妨談笑奉罇罍。", "元規樓迥清風滿，匡俗仙春畫障開。", "莫忘故人離別恨，海潮迴處寄書來。"]'),
('a6d9230a-83c9-4483-9f3f-b0b886533533','送朱先輩尉廬陵','徐鉉','宋','宋诗','song-poetry','','[]','我重朱夫子，依然見古人。',48,'全唐诗/poet.song.0.json','["我重朱夫子，依然見古人。", "成名無愧色，得祿及慈親。", "莫歎官資屈，寧論活計貧。", "平生心氣在，終在靜邊塵。"]'),
('46698569-9455-48ba-bb9b-26ee9ec753f1','送德林郎中學士赴東府得酒并序','徐鉉','宋','宋诗','song-poetry','','[]','酌此杯中物，茱萸滿把秋。',48,'全唐诗/poet.song.0.json','["酌此杯中物，茱萸滿把秋。", "今朝將送別，他日是忘憂。", "世亂方多事，年加易得愁。", "政成頻一醉，亦未減風流。"]'),
('ad8b4c5c-dc85-4c6a-aab0-791d025afbdb','送陳先生之洪并寄蕭少卿','徐鉉','宋','宋诗','song-poetry','','[]','聞君仙袂指洪涯，我憶情人別路賒。',64,'全唐诗/poet.song.0.json','["聞君仙袂指洪涯，我憶情人別路賒。", "知有歡娛游楚澤，更無書札到京華。", "雲間驛閣連江靜，春滿西山倚漢斜。", "此處相逢應見問，爲言搔首望龍沙。"]'),
('3c5f8ca7-11ab-421b-89b8-6d03df2f67fe','送龔明府九江歸寧','徐鉉','宋','宋诗','song-poetry','','[]','茂宰隳官去，扁舟著綵衣。',48,'全唐诗/poet.song.0.json','["茂宰隳官去，扁舟著綵衣。", "湓城春酒熟，匡阜野花稀。", "解纜垂楊綠，開帆宿鷺飛。", "一朝吾道泰，還逐落潮歸。"]'),
('d0de5eba-2cd6-42c8-91b0-f3553a8eba76','和江西蕭少卿見寄二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','亡羊岐路愧司南，二紀窮通聚散三。',64,'全唐诗/poet.song.0.json','["亡羊岐路愧司南，二紀窮通聚散三。", "老去何妨從笑傲，病來看欲懶朝參。", "離腸似線常憂斷，世態如湯不可探。", "珍重加餐省思慮，時時斟酒壓山嵐。"]'),
('52dc01b6-da6b-41b1-bf55-bb3ef11008fb','和江西蕭少卿見寄二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','身遥上國三千里，名在朝中二十春。',64,'全唐诗/poet.song.0.json','["身遥上國三千里，名在朝中二十春。", "金印不須辭入幕，麻衣曾此歎迷津。", "卷舒由我真齊物，憂喜忘心即養神。", "世路風波自翻覆，虛舟無計得沉淪。"]'),
('297bc7e3-eb9a-45c8-90f9-30011c6944c5','送薛少卿赴青陽','徐鉉','宋','宋诗','song-poetry','','[]','我愛陶靖節，吏隠從弦歌。',132,'全唐诗/poet.song.0.json','["我愛陶靖節，吏隠從弦歌。", "我愛費徵君，高卧歸九華。", "清風激頹波，來者何以加。", "我志兩不遂，漂淪浩無涯。", "數奇時且亂，此圖今愈賒。", "賢哉薛夫子，高舉凌晨霞。", "安民即是道，投足皆爲家。", "功名與權位，悠悠何用誇。", "携朋出遠郊，酌酒藉平沙。", "雲收遠天靜，江闊片帆斜。", "離懷與企羨，南望長咨嗟。"]'),
('4afc363d-e8c2-4ba1-a4fa-6695941caa0c','送高起居之涇縣','徐鉉','宋','宋诗','song-poetry','','[]','右史罷朝歸，之官句水湄。',132,'全唐诗/poet.song.0.json','["右史罷朝歸，之官句水湄。", "別我行千里，送君傾一巵。", "酒罷長歎息，此歎君應悲。", "亂中吾道薄，卿族舊人稀。", "胡爲佩銅墨，去此白玉墀。", "吏事豈所堪，民病何可醫。", "藏用清其心，此外慎勿爲。", "縣郭有佳境，千峰谿水西。", "雲樹杳迴合，巖巒互蔽虧。", "彈琴坐其中，世事吾不知。", "時時寄書札，以慰長相思。"]'),
('4d5d84c3-3521-433a-ade8-4b13da146199','宿茅山寄舍弟','徐鉉','宋','宋诗','song-poetry','','[]','茅許稟靈氣，一家同上賓。',48,'全唐诗/poet.song.0.json','["茅許稟靈氣，一家同上賓。", "仙山空有廟，舉世更無人。", "獨往誠違俗，浮名亦累真。", "當年各自勉，雲洞鎮長春。"]'),
('f1de9adf-559d-4f2f-a39d-552ad62a39b9','晚憩白鶴廟寄句容張少府','徐鉉','宋','宋诗','song-poetry','','[]','日入林初靜，山空暑更寒。',48,'全唐诗/poet.song.0.json','["日入林初靜，山空暑更寒。", "泉鳴細巖竇，鶴唳眇雲端。", "拂榻安棋局，焚香戴道冠。", "望君殊不見，終夕凭欄干。"]'),
('01a36baa-f3c2-41ea-a6ef-8969f012544d','題紫陽觀','徐鉉','宋','宋诗','song-poetry','','[]','南朝名士富仙才，追步東鄉遂不迴。',64,'全唐诗/poet.song.0.json','["南朝名士富仙才，追步東鄉遂不迴。", "丹井自深桐暗老，祠宮長在鶴頻來。", "巖邊桂樹攀仍倚，洞口桃花落復開。", "惆悵霓裳太平事，一函真跡鎖昭臺。"]'),
('1047829a-6cf0-4a92-8eae-1b4966334806','贈奚道士','徐鉉','宋','宋诗','song-poetry','','[]','先生曾有洞天期，猶傍天壇摘紫芝。',64,'全唐诗/poet.song.0.json','["先生曾有洞天期，猶傍天壇摘紫芝。", "處世自能心混沌，全真誰見德支離。", "玉霄塵閉人長在，金鼎功成俗未知。", "他日飈輪謁茅許，願同雞犬去相隨。"]'),
('0eb90f9e-9b84-49e3-b433-d68e1a6825ec','題碧巖亭贈孫尊師','徐鉉','宋','宋诗','song-poetry','','[]','絕境何人識，高亭萬象含。',96,'全唐诗/poet.song.0.json','["絕境何人識，高亭萬象含。", "凭軒臨樹杪，送目極天南。", "積靄生泉洞，歸雲鎖石龕。", "丹霞披翠巘，白鳥带晴嵐。", "仙去留虛室，龍歸漲碧潭。", "幽巖君獨愛，玄味我曾耽。", "世上愁何限，人間事久諳。", "終須脫羈鞅，來此會空談。"]'),
('141ae8bd-a4e2-4b34-be81-9a32595f8496','題白鶴廟','徐鉉','宋','宋诗','song-poetry','','[]','平生心事向玄關，一入仙鄉似舊山。',64,'全唐诗/poet.song.0.json','["平生心事向玄關，一入仙鄉似舊山。", "白鶴唳空晴眇眇，丹砂流澗暮潺潺。", "嘗嗟多病嫌中藥，擬問真經乞小還。", "滿洞烟霞互陵亂，何峰臺榭是蕭閑。"]'),
('f3ff5c75-41af-4469-80bb-d3adb2b9c86c','步虛詞五首  其一','徐鉉','宋','宋诗','song-poetry','','[]','氣爲還元正，心由抱一靈。',48,'全唐诗/poet.song.0.json','["氣爲還元正，心由抱一靈。", "凝神歸罔象，飛步入青冥。", "整服乘三素，旋綱躡九星。", "瓊章開後學，稽首奉真經。"]'),
('fe398e7e-cb9a-498c-8956-da3ba0443753','步虛詞五首  其二','徐鉉','宋','宋诗','song-poetry','','[]','天帝黄金闕，真人紫錦書。',48,'全唐诗/poet.song.0.json','["天帝黄金闕，真人紫錦書。", "霓裳紛蔽景，羽服迥臨虛。", "白鶴能爲使，班麟解駕車。", "靈符終願借，轉共世情疏。"]'),
('87208d5a-50a8-45d1-8612-d7b08160c012','步虛詞五首  其三','徐鉉','宋','宋诗','song-poetry','','[]','聖主過幽谷，虛皇在蕊宮。',48,'全唐诗/poet.song.0.json','["聖主過幽谷，虛皇在蕊宮。", "五千宗物母，七字秘神童。", "世人金壺遠，人間玉籥空。", "唯餘養身法，修此與天通。"]'),
('7ee49032-3d57-4a09-9cd1-2ab63cebdbda','步虛詞五首  其四','徐鉉','宋','宋诗','song-poetry','','[]','何處求玄解，人間有洞天。',48,'全唐诗/poet.song.0.json','["何處求玄解，人間有洞天。", "勤行皆是道，謫下尚爲仙。", "蔽景乘朱鳳，排虛駕紫烟。", "不嫌園吏傲，願在玉宸前。"]'),
('31b023f7-7a33-4b60-8594-b2d41521bf16','步虛詞五首  其五','徐鉉','宋','宋诗','song-poetry','','[]','三素霏霏遠，盟威凜凜寒。',48,'全唐诗/poet.song.0.json','["三素霏霏遠，盟威凜凜寒。", "火鈴空滅沒，星斗曉闌干。", "佩響流虛殿，爐烟在醮壇。", "蕭寥不可極，驂駕上雲端。"]'),
('3588a5ee-6cbb-4c9f-ba1a-a2105efcfc76','留題','徐鉉','宋','宋诗','song-poetry','','[]','瑶壇醮罷晚雲開，羽客分飛俗士迴。',32,'全唐诗/poet.song.0.json','["瑶壇醮罷晚雲開，羽客分飛俗士迴。", "爲報移文不須勒，未曾游處待重來。"]'),
('591d0ef6-bfdc-42be-9995-bd9198379aea','和陳洗馬山莊新泉','徐鉉','宋','宋诗','song-poetry','','[]','已開山館待抽簪，更要巖泉欲洗心。',64,'全唐诗/poet.song.0.json','["已開山館待抽簪，更要巖泉欲洗心。", "常被松聲迷細韻，急流花片落高岑。", "便疏淺瀨穿莎徑，始有清光映竹林。", "何日煎茶醖香酒，沙邊同聽暝猿吟。"]'),
('dc3e52b6-d85f-4119-88b2-638ecefe12e1','奉和七夕應令','徐鉉','宋','宋诗','song-poetry','','[]','今宵星漢共晶光，應笑羅敷嫁侍郎。',64,'全唐诗/poet.song.0.json','["今宵星漢共晶光，應笑羅敷嫁侍郎。", "斗柄易傾離恨促，河流不盡後期長。", "靜聞天籟疑鳴佩，醉折荷花想豔妝。", "誰見宣猷堂上宴，一篇清韻振金鐺。"]'),
('ec2704b8-2120-4f29-8127-9588d479fef0','又和八日','徐鉉','宋','宋诗','song-poetry','','[]','微雲疏雨淡新秋，曉夢依稀十二樓。',64,'全唐诗/poet.song.0.json','["微雲疏雨淡新秋，曉夢依稀十二樓。", "故作別離應有以，擬延更漏共無由。", "那教人世長多恨，未必天仙不解愁。", "博望苑中殘酒醒，香風佳氣獨遲留。"]'),
('9f1542cd-efc7-4e1b-89ed-275ab86480bb','和印先輩及第後獻座主朱舍人郊居之作','徐鉉','宋','宋诗','song-poetry','','[]','成名郊外掩柴扉，樹影蟬聲共息機。',64,'全唐诗/poet.song.0.json','["成名郊外掩柴扉，樹影蟬聲共息機。", "積雨暗封青蘚徑，好風輕透白綀衣。", "嘉魚始賦人爭誦，荆玉頻收國自肥。", "獨坐公廳正煩暑，喜吟新詠見玄微。"]'),
('7595248a-0979-4a53-84b9-65a61c3a92d3','和致仕張尚書新創道院','徐鉉','宋','宋诗','song-poetry','','[]','梓澤成新致，金丹有舊情。',48,'全唐诗/poet.song.0.json','["梓澤成新致，金丹有舊情。", "挂冠朝睡足，隠几暮江清。", "藥圃分輕綠，松窗起細聲。", "養高寧厭病，默坐對諸生。"]'),
('13152116-37aa-47a1-a0c5-9d97c3dee900','和尉遲贊善秋暮僻居','徐鉉','宋','宋诗','song-poetry','','[]','登高節物最堪憐，小嶺疏林對檻前。',64,'全唐诗/poet.song.0.json','["登高節物最堪憐，小嶺疏林對檻前。", "輕吹斷時雲縹緲，夕陽明處水澄鮮。", "江城秋早催寒事，望苑朝稀足晏眠。", "庭有菊花罇有酒，若方陶令愧猶賢。"]'),
('b2433410-3421-47cf-a2d9-1c86a7872c82','和陳贊善致仕還京口','徐鉉','宋','宋诗','song-poetry','','[]','海門山下一漁舟，中有高人未白頭。',64,'全唐诗/poet.song.0.json','["海門山下一漁舟，中有高人未白頭。", "已駕安車歸故里，尚通閨籍在龍樓。", "泉聲潄玉窗前落，江色和烟檻外流。", "今日君臣厚終始，不須辛苦畫雙牛。"]'),
('24baa1ad-c24f-4560-a4ba-d94b2ffc4761','京使迴自臨川得從兄書寄詩依韻和','徐鉉','宋','宋诗','song-poetry','','[]','珍重還京使，殷勤話故人。',48,'全唐诗/poet.song.0.json','["珍重還京使，殷勤話故人。", "別離長挂夢，寵祿不關身。", "趣向今成道，聲華舊絕塵。", "莫嗟容鬢老，詩句逐時新。"]'),
('862bb5ef-1239-493a-bcad-2c667c5fd933','陪鄭王相公賦簷前垂冰應教依韻','徐鉉','宋','宋诗','song-poetry','','[]','窗外虛明雪乍晴，簷前垂霤盡成冰。',64,'全唐诗/poet.song.0.json','["窗外虛明雪乍晴，簷前垂霤盡成冰。", "長廊瓦疊行行密，晚院風高寸寸增。", "玉指乍拈簪尚愧，金階時墜磬難勝。", "晨餐堪醒曹參酒，自恨空腸病不能。"]'),
('0c29f3cb-9cbd-49fe-90df-74be8d7a9c36','送禮部潘尚書致仕還建安','徐鉉','宋','宋诗','song-poetry','','[]','名遂功成累復輕，鱸魚因起舊鄉情。',64,'全唐诗/poet.song.0.json','["名遂功成累復輕，鱸魚因起舊鄉情。", "履聲初下金華省，帆影看離石首城。", "化劍津頭尋故老，同亭會上問仙卿。", "冥鴻高舉真難事，相送何須淚滿纓。"]'),
('3cc5cf60-013c-449d-af5e-149d7eb14387','和尉遲贊善病中見寄','徐鉉','宋','宋诗','song-poetry','','[]','仙郎移病暑天過，却似冥鴻避罻羅。',64,'全唐诗/poet.song.0.json','["仙郎移病暑天過，却似冥鴻避罻羅。", "晝夢乍驚風動竹，夜吟時覺露霑莎。", "情親稍喜貧居近，性懶猶嫌上直多。", "望苑恩深期勿藥，青雲岐路未蹉跎。"]'),
('004cb6fb-9f53-4f05-b21f-1fc9780c0e4a','池州陳使君見示游齊山詩因寄','徐鉉','宋','宋诗','song-poetry','','[]','往歲曾遊弄水亭，齊峰濃翠暮軒橫。',64,'全唐诗/poet.song.0.json','["往歲曾遊弄水亭，齊峰濃翠暮軒橫。", "哀猿出檻心雖喜，傷鳥聞弦勢易驚。", "病後簪纓殊寡興，老來泉石倍關情。", "今朝池口風波靜，遥賀山前有頌聲。"]'),
('472870f9-36a3-4493-aa8f-3a7e0b44f92f','再領制誥和王明府見賀','徐鉉','宋','宋诗','song-poetry','','[]','蹇步還依列宿邊，拱辰重認舊雲天。',64,'全唐诗/poet.song.0.json','["蹇步還依列宿邊，拱辰重認舊雲天。", "自嗟多難飄零困，不似當年膽氣全。", "雞樹晚花疏向日，龍池輕浪細含烟。", "從來不解爲身計，一葉悠悠任大川。"]'),
('d2682a22-cc50-4101-b1d0-78bf35a0159d','送高舍人使嶺南','徐鉉','宋','宋诗','song-poetry','','[]','西掖官曹近，南溟道路遥。',72,'全唐诗/poet.song.0.json','["西掖官曹近，南溟道路遥。", "使星將渡漢，仙掌乍乘潮。", "柳映靈和折，梅依大庾飄。", "江帆風淅淅，山館雨蕭蕭。", "陸賈真迂闊，終童久寂寥。", "送君何限意，把酒一長謠。"]'),
('38f4583c-0514-4fb8-aae0-e4517a197428','和王明府見寄','徐鉉','宋','宋诗','song-poetry','','[]','時情世難消我道，薄宦流年厄此身。',64,'全唐诗/poet.song.0.json','["時情世難消我道，薄宦流年厄此身。", "莫歎京華同寂寞，曾經兵革共漂淪。", "對山開戶唯求靜，貰酒留賓不道貧。", "善政空多尚淹屈，不知誰是解憂民。"]'),
('33146baf-43f8-4d0c-9eff-98ec5d5787f5','和方泰州見寄','徐鉉','宋','宋诗','song-poetry','','[]','逐客悽悽重入京，舊愁新恨兩難勝。',64,'全唐诗/poet.song.0.json','["逐客悽悽重入京，舊愁新恨兩難勝。", "雲收楚塞千山雪，風結秦淮一尺冰。", "置醴筵空情豈盡，投湘文就思如凝。", "更殘月落知孤坐，遥望船窗一點星。"]'),
('fce875ba-50c2-4b80-b04a-3d77c0b1e411','文獻太子挽歌辭五首  其一','徐鉉','宋','宋诗','song-poetry','','[]','國有承祧重，人知秉哲尊。',48,'全唐诗/poet.song.0.json','["國有承祧重，人知秉哲尊。", "清風來望苑，遺烈在東藩。", "此日升緱嶺，何因到寢門。", "天高不可問，烟靄共昏昏。"]'),
('1dd6f6f2-b24a-45d4-b9af-b288a9126499','文獻太子挽歌辭五首  其二','徐鉉','宋','宋诗','song-poetry','','[]','夏啟我君子，周儲上帝賓。',48,'全唐诗/poet.song.0.json','["夏啟我君子，周儲上帝賓。", "音容一飄忽，功業自紛綸。", "露泣承華月，風驚麗正塵。", "空餘商嶺客，行哭下宜春。"]'),
('f3de1596-55c0-401d-bab6-8b9ead0600d1','文獻太子挽歌辭五首  其三','徐鉉','宋','宋诗','song-poetry','','[]','出處成交讓，經綸有大功。',48,'全唐诗/poet.song.0.json','["出處成交讓，經綸有大功。", "淚碑瓜步北，棠樹蒜山東。", "百揆方時敘，重離遂不融。", "故臣偏感咽，曾是歎三窮。"]'),
('943c4954-6d75-48db-9835-cd47b7bd253b','文獻太子挽歌辭五首  其四','徐鉉','宋','宋诗','song-poetry','','[]','甲觀光陰促，園陵天地長。',48,'全唐诗/poet.song.0.json','["甲觀光陰促，園陵天地長。", "簫笳咽無韻，賓御哭相將。", "盛烈傳彝鼎，遺文被樂章。", "君臣知己分，零淚亂無行。"]'),
('96a1439e-1efb-4415-b8ab-289a4db677ab','文獻太子挽歌辭五首  其五','徐鉉','宋','宋诗','song-poetry','','[]','綵仗清晨出，非同齒胄時。',48,'全唐诗/poet.song.0.json','["綵仗清晨出，非同齒胄時。", "愁烟鎖平甸，朔吹繞寒枝。", "楚客來何補，緱山去莫追。", "迴瞻飛蓋處，掩袂不勝悲。"]'),
('0f32b902-92f1-43b2-9549-07355da8816e','送王員外宰德安','徐鉉','宋','宋诗','song-poetry','','[]','家世朱門貴，官資粉署優。',48,'全唐诗/poet.song.0.json','["家世朱門貴，官資粉署優。", "今爲百里長，應好五峰游。", "柳影連彭澤，湖光接庾樓。", "承明須再入，官滿莫淹留。"]'),
('ec72560b-3fbf-4303-8171-d7e198e18519','以端谿硯酬張員外水精珠兼和來篇','徐鉉','宋','宋诗','song-poetry','','[]','請以端谿潤，酬君水玉明。',48,'全唐诗/poet.song.0.json','["請以端谿潤，酬君水玉明。", "方圓雖異器，功用信俱呈。", "自得山川秀，能分日月精。", "巾箱各珍重，所貴在交情。"]'),
('bed524be-ee83-42e1-9d51-cae60171e79c','奉使九華山中塗遇青陽薛郎中','徐鉉','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','故人相別動相思，此地相逢豈素期。',64,'全唐诗/poet.song.0.json','["故人相別動相思，此地相逢豈素期。", "九子峰前閒未得，五谿橋上坐多時。", "甘泉從幸余知忝，宣室徵還子未遲。", "且飲一杯消別恨，野花風起漸離披。"]'),
('fb686192-96b6-455d-878c-018075c1e860','奉命南使經彭澤','徐鉉','宋','宋诗','song-poetry','','[]','遠使程途未一分，離心常要醉醺醺。',32,'全唐诗/poet.song.0.json','["遠使程途未一分，離心常要醉醺醺。", "那堪彭澤門前立，黄菊蕭疏不見君。"]'),
('74382f73-c036-4322-9856-516c540400e9','南都遇前嘉魚劉令言游閩嶺作此與之','徐鉉','宋','宋诗','song-poetry','','[]','我持使節經韶石，君作閒遊過武夷。',64,'全唐诗/poet.song.0.json','["我持使節經韶石，君作閒遊過武夷。", "兩地山光成獨賞，隔年鄉思暗相知。", "洪涯壇上長岑寂，孺子亭前自別離。", "珍重分岐一杯酒，强加餐飯數吟詩。"]'),
('abd3a148-7f23-402b-ac47-8c938d20292f','閣皁山','徐鉉','宋','宋诗','song-poetry','','[]','殿影高低雲掩映，松陰繚繞步徘徊。',32,'全唐诗/poet.song.0.json','["殿影高低雲掩映，松陰繚繞步徘徊。", "從今莫厭簪裾累，不是乘軺不得來。"]'),
('bba6bec6-78cd-4221-9a9a-6dd1ae348951','玉笥山留題','徐鉉','宋','宋诗','song-poetry','','[]','仙鄉會應遠，王事知何極。',72,'全唐诗/poet.song.0.json','["仙鄉會應遠，王事知何極。", "征傳莫辭勞，玉峰聊一息。", "形骸已銷散，心想都凝寂。", "真氣自清虛，非關好松石。", "九仙皆積學，洞壑多遺跡。", "遊子歸去來，胡爲但征役。"]'),
('93796370-0c63-491a-9ad8-aaeac303a90d','廬陵別朱觀先輩','徐鉉','宋','宋诗','song-poetry','','[]','桂籍知名有幾人，翻飛相續上青雲。',64,'全唐诗/poet.song.0.json','["桂籍知名有幾人，翻飛相續上青雲。", "解憐才子寧唯我，遠作卑官尚見君。", "嶺外獨持嚴助節，宮中誰薦長卿文。", "新詩試爲重高詠，朝漢臺前不可聞。"]'),
('0b35b07d-f179-4876-b483-dc0ad9929a2e','文彧少卿文山郎中交好深至二紀已餘暌別數年二子長逝奉使嶺表塗次南康弔孫氏之孤於其家睹文彧手書於僧室慷慨悲歎留題此詩','徐鉉','宋','宋诗','song-poetry','','[]','弔孫家虛座弔諸孤，張叟僧房見手書。',65,'全唐诗/poet.song.0.json','["弔孫家虛座弔諸孤，張叟僧房見手書。", "二紀歡游今若此，滿衣零淚欲何如。", "腰間金印從如斗，鏡裏霜華已滿梳。", "珍重遠公應笑我，塵心唯此未能除。"]'),
('ac8f8db6-b4ef-4eb5-80a1-08ce74871b34','朱處士相與有山水之願見送至南康作此以別之','徐鉉','宋','宋诗','song-poetry','','[]','弔憐君送我至南康，更憶梅花庾嶺芳。',33,'全唐诗/poet.song.0.json','["弔憐君送我至南康，更憶梅花庾嶺芳。", "多少仙山共遊在，願君百歲尚康强。"]'),
('88da2792-659f-4d74-93af-e0b65a5b8c33','清明日清遠峽作','徐鉉','宋','宋诗','song-poetry','','[]','弔嶺外春過半，途中火又新。',25,'全唐诗/poet.song.0.json','["弔嶺外春過半，途中火又新。", "殷勤清遠峽，留戀北歸人。"]'),
('9ed4f35d-7521-4ad0-aa57-4ee0fcc0ddde','迴至南康題紫極宮裏道士房','徐鉉','宋','宋诗','song-poetry','','[]','弔王事信靡盬，飲冰安足辭。',85,'全唐诗/poet.song.0.json','["弔王事信靡盬，飲冰安足辭。", "胡爲擁征傳，乃至天南陲。", "天南非我鄉，留滯忽踰時。", "還經羽人家，豁若雲霧披。", "何以寬我懷，老莊有微辭。", "達士無不可，至人豈偏爲。", "客愁勿復道，爲君吟此詩。"]'),
('b57df64b-b901-4c6c-8109-7524e7879459','和歙州陳使君見寄','徐鉉','宋','宋诗','song-poetry','','[]','弔新安風景好，時令肅轅門。',121,'全唐诗/poet.song.0.json','["弔新安風景好，時令肅轅門。", "身貴心彌下，功多口不言。", "韜鈐家法在，儒雅素風存。", "簪履陪游盛，鄉閭俗化敦。", "臨窗山色秀，繞郭水聲喧。", "纖絡文章麗，矜嚴道義尊。", "樓臺秋月靜，京庾晚雲屯。", "曉吹傳衙鼓，晴陽展信旛。", "一篇貽友好，千里倍心論。", "未見歸驂動，空能役夢魂。"]'),
('2b2a5929-afee-415a-96dc-520ee7e92d2c','和賈員外戩見贈玉蕊花栽','徐鉉','宋','宋诗','song-poetry','','[]','瓊瑶一族带花來，便斸蒼苔手自栽。',32,'全唐诗/poet.song.0.json','["瓊瑶一族带花來，便斸蒼苔手自栽。", "喜見唐昌舊顔色，爲君判病酌金罍。"]'),
('79e5d933-132c-48ad-9f62-2a158ab1d2c8','光穆皇后挽歌三首  其一','徐鉉','宋','宋诗','song-poetry','','[]','仙馭期難改，坤儀道自光。',48,'全唐诗/poet.song.0.json','["仙馭期難改，坤儀道自光。", "閟宮新表德，沙麓舊膺祥。", "素帟堯門掩，凝笳畢陌長。", "東風慘陵樹，無復見親桑。"]'),
('422aa33a-7264-424b-817f-fbd8499ddbb2','光穆皇后挽歌三首  其二','徐鉉','宋','宋诗','song-poetry','','[]','永樂留虛位，長陵啟夕扉。',48,'全唐诗/poet.song.0.json','["永樂留虛位，長陵啟夕扉。", "返虞嚴吉仗，復土掩空衣。", "功業投三母，光靈極四妃。", "唯應彤史在，不與露花晞。"]'),
('73dd5bba-3cfe-48cf-b2d5-079f4061264c','光穆皇后挽歌三首  其三','徐鉉','宋','宋诗','song-poetry','','[]','隠隠閶門路，烟雲曉更愁。',48,'全唐诗/poet.song.0.json','["隠隠閶門路，烟雲曉更愁。", "空瞻金輅出，非是濯龍游。", "德感人倫正，風行內職修。", "還隨偶物化，同此畏軒丘。"]'),
('e22066ca-c269-4bfa-a204-dade372fecf6','嚴相公宅牡丹','徐鉉','宋','宋诗','song-poetry','','[]','但是豪家重牡丹，爭如丞相閣前看。',64,'全唐诗/poet.song.0.json','["但是豪家重牡丹，爭如丞相閣前看。", "鳳樓日暖開偏早，雞樹陰濃謝更難。", "數朵已應迷國豔，一枝何幸上塵冠。", "不知更許憑欄否，爛漫春光未肯殘。"]'),
('c0494ab5-f7e3-44ca-8560-9447eaf891eb','侍宴賦得歸雁','徐鉉','宋','宋诗','song-poetry','','[]','夜靜羣動息，翩翩一雁歸。',48,'全唐诗/poet.song.0.json','["夜靜羣動息，翩翩一雁歸。", "清音天際遠，寒影月中微。", "何處雲同宿，長空雪共飛。", "陽和常借便，免與素心違。"]'),
('471b0379-868c-4ef0-a504-0a3c9ad3c346','又賦早春書事','徐鉉','宋','宋诗','song-poetry','','[]','苑裏芳華早，皇家勝事多。',48,'全唐诗/poet.song.0.json','["苑裏芳華早，皇家勝事多。", "弓聲達春氣，弈思養天和。", "暖酒紅爐火，浮舟綠水波。", "雪晴農事起，擊壤聽賡歌。"]'),
('c9e9449c-bb66-43cd-97c0-f6a8d6465cfd','依韻和令公大王薔薇詩','徐鉉','宋','宋诗','song-poetry','','[]','綠樹成陰後，羣芳稍歇時。',216,'全唐诗/poet.song.0.json','["綠樹成陰後，羣芳稍歇時。", "誰將新濯錦，挂向最長枝。", "卷箔香先入，憑欄影任移。", "賞頻嫌酒渴，吟苦怕霜髭。", "架迥籠雲幄，庭虛展繡帷。", "有情縈舞袖，無力罥遊絲。", "嫩蕊鶑偷采，柔條柳伴垂。", "荀池波自照，梁苑客嘗窺。", "玉李尋皆謝，金桃亦暗衰。", "花中應獨貴，庭下故開遲。", "委豔妝苔砌，分華借槿籬。", "低昂勻灼爍，濃淡疊參差。", "幸植王宮裏，仍逢宰府知。", "芳心向誰許，醉態不能支。", "芍藥天教避，玫瑰衆共嗤。", "光明烘晝景，潤膩裛輕𩅰。", "麗似期神女，珍如重衛姬。", "君王偏屬詠，七子盡搜奇。"]'),
('c6a27fcc-b659-40d1-bfb3-a844fb7e746c','和門下殷侍郎新茶二十韻','徐鉉','宋','宋诗','song-poetry','','[]','暖吹入春園，新芽競粲然。',240,'全唐诗/poet.song.0.json','["暖吹入春園，新芽競粲然。", "才教鷹嘴拆，未放雪花妍。", "荷杖青林下，携筐旭景前。", "孕靈資雨露，鍾秀自山川。", "碾後香彌遠，烹來色更鮮。", "名隨土地貴，味逐水泉遷。", "力藉流黄暖，形模紫筍圓。", "正當鑽柳火，遥想湧金泉。", "任道時新物，須依古法煎。", "輕甌浮綠乳，孤竈散餘烟。", "甘薺非予匹，宮槐讓我先。", "竹孤空冉冉，荷弱謾田田。", "解渴消殘酒，清神減夜眠。", "十漿何足饋，百榼盡堪捐。", "采擷唯憂晚，營求不計錢。", "任公因焙顯，陸氏有經傳。", "愛甚真成僻，嘗多合得仙。", "亭臺虛靜處，風月艷陽天。", "自可臨泉石，何妨雜管弦。", "東山似蒙頂，願得從諸賢。"]'),
('c7875c18-12db-4c98-b9fa-01b351a7f1cb','春雪應制','徐鉉','宋','宋诗','song-poetry','','[]','繁陰連曙景，瑞雪灑芳辰。',48,'全唐诗/poet.song.0.json','["繁陰連曙景，瑞雪灑芳辰。", "勢密猶疑臘，風和始覺春。", "縈林開玉蕊，飄座裛香塵。", "欲識宸心悅，雲謠慰兆人。"]'),
('de01e981-15ec-4d5b-b1c2-a452617b2653','進雪詩','徐鉉','宋','宋诗','song-poetry','','[]','欲使新正識有年，故飄輕絮伴春還。',64,'全唐诗/poet.song.0.json','["欲使新正識有年，故飄輕絮伴春還。", "近看瓊樹籠銀闕，遠想瑶池带玉關。", "潤逐麳麰鋪綠野，暖隨杯酒上朱顔。", "朝來花萼樓中宴，數曲賡歌雅頌間。"]'),
('5c0a3d00-7520-4c2a-b63d-582a8224e8ce','自題山亭三首  其一','徐鉉','宋','宋诗','song-poetry','','[]','簪組非無累，園林未是歸。',24,'全唐诗/poet.song.0.json','["簪組非無累，園林未是歸。", "世喧長不到，何必故山薇。"]'),
('413b6892-d77a-43fa-b0e3-d4ee4c6c6085','自題山亭三首  其二','徐鉉','宋','宋诗','song-poetry','','[]','小舫行乘月，高齋卧看山。',24,'全唐诗/poet.song.0.json','["小舫行乘月，高齋卧看山。", "退公聊自足，爭敢望長閑。"]'),
('2423042d-4f5d-47c8-9451-b7165e818998','自題山亭三首  其三','徐鉉','宋','宋诗','song-poetry','','[]','跂石仍臨水，披襟復挂冠。',24,'全唐诗/poet.song.0.json','["跂石仍臨水，披襟復挂冠。", "機心忘未得，棋局與魚竿。"]'),
('1331728f-fdde-4027-afda-5f38f700a529','和陳表用員外求酒','徐鉉','宋','宋诗','song-poetry','','[]','暑天頻雨亦頻晴，簾外閑雲重復輕。',32,'全唐诗/poet.song.0.json','["暑天頻雨亦頻晴，簾外閑雲重復輕。", "珍重一壺酬絕唱，向風遥想醉吟聲。"]'),
('54dec904-89ad-48ee-86b5-328c123025c6','奉和右省僕射西亭高卧作','徐鉉','宋','宋诗','song-poetry','','[]','院靜蒼苔積，庭幽怪石欹。',96,'全唐诗/poet.song.0.json','["院靜蒼苔積，庭幽怪石欹。", "蟬聲當檻急，虹影向簷垂。", "晝漏猶憐永，叢蘭未覺衰。", "疏篁巢翡翠，折葦覆鸕鷀。", "對酒襟懷曠，圍棋旨趣遲。", "景皆隨所尚，物各遂其宜。", "道與時相會，才非民所羈。", "賦詩貽座客，秋事爾何悲。"]'),
('9a5b8d1f-5edd-4c88-ba7a-8f166553f7cf','憶新淦觴池寄孟賓于員外','徐鉉','宋','宋诗','song-poetry','','[]','往年淦水駐行軒，引得清流似月圓。',64,'全唐诗/poet.song.0.json','["往年淦水駐行軒，引得清流似月圓。", "自有谿光還碧甃，不勞人力遞金船。", "潤滋苔蘚欺茵席，聲入杉松當管弦。", "珍重詩人頻管領，莫教塵土咽潺潺。"]'),
('011d72a5-bf00-4aad-ad86-5a2b6cb20aa6','右省僕射後湖亭閒宴鉉以宿直先歸賦詩留獻','徐鉉','宋','宋诗','song-poetry','','[]','湖上一陽生，虛亭啟高宴。',48,'全唐诗/poet.song.0.json','["湖上一陽生，虛亭啟高宴。", "楓林烟際出，白鳥波心見。", "主人忘貴達，座客容疵賤。", "獨慚殘照催，歸宿明光殿。"]'),
('9db901cb-974d-4e3b-9613-d2bea126b961','送孟賓于員外還新淦','徐鉉','宋','宋诗','song-poetry','','[]','暫來城闕不從容，却佩銀魚隠玉峰。',64,'全唐诗/poet.song.0.json','["暫來城闕不從容，却佩銀魚隠玉峰。", "雙澗水邊欹醉石，九仙臺下聽風松。", "題詩翠壁稱逋客，采藥春畦狎老農。", "野鶴乘軒雲出岫，不知何日再相逢。"]'),
('ac738206-c867-494b-ab1e-9bddfca8dff8','孟君別後相續寄書作此酬之','徐鉉','宋','宋诗','song-poetry','','[]','多病怯煩暑，短才憂近職。',48,'全唐诗/poet.song.0.json','["多病怯煩暑，短才憂近職。", "跂足北窗風，遥懷浩無極。", "故人易成別，詩句空相憶。", "尺素寄天涯，淦江秋水色。"]'),
('385f464a-4fc6-43c9-bcad-1916ae491ebe','納后夕侍宴','徐鉉','宋','宋诗','song-poetry','','[]','天上軒星正，雲開湛露垂。',72,'全唐诗/poet.song.0.json','["天上軒星正，雲開湛露垂。", "禮容過渭水，宴喜勝瑶池。", "彩霧籠花燭，升龍肅羽儀。", "君臣歡樂日，文物盛明時。", "簾捲銀河轉，香凝玉漏遲。", "華封傾祝意，觴酒與聲詩。"]'),
('1ddc07df-0de1-418e-9788-98e51adf95b2','又三絕  其一','徐鉉','宋','宋诗','song-poetry','','[]','時平物茂歲功成，重翟排雲到玉京。',32,'全唐诗/poet.song.0.json','["時平物茂歲功成，重翟排雲到玉京。", "四海未知春色至，今宵先入九重城。"]'),
('0836271c-2809-420b-af19-47e4cce0157e','又三絕  其二','徐鉉','宋','宋诗','song-poetry','','[]','銀燭金爐禁漏移，月輪初照萬年枝。',32,'全唐诗/poet.song.0.json','["銀燭金爐禁漏移，月輪初照萬年枝。", "造舟已似文王事，卜世應同八百期。"]'),
('477aae78-4bcf-4125-8a49-573726809fea','又三絕  其三','徐鉉','宋','宋诗','song-poetry','','[]','漢主承乾帝道光，天家花燭宴昭陽。',32,'全唐诗/poet.song.0.json','["漢主承乾帝道光，天家花燭宴昭陽。", "六衣盛禮如金屋，彩筆分題似柏梁。"]'),
('ba24ec00-7c0c-4f30-bbee-ce0d9ae9d52b','北苑侍宴雜詠詩 竹','徐鉉','宋','宋诗','song-poetry','','[]','勁節生宮苑，虛心奉豫遊。',24,'全唐诗/poet.song.0.json','["勁節生宮苑，虛心奉豫遊。", "自然名價重，不羨渭川侯。"]'),
('2c24b0c9-4ca8-4cc1-98b4-08e59f977e62','北苑侍宴雜詠詩 松','徐鉉','宋','宋诗','song-poetry','','[]','細韻風中遠，寒青雪後濃。',24,'全唐诗/poet.song.0.json','["細韻風中遠，寒青雪後濃。", "繁陰堪避雨，效用待東封。"]'),
('4bb1d2ca-33ea-4745-adce-b0d561b38bb1','北苑侍宴雜詠詩 水','徐鉉','宋','宋诗','song-poetry','','[]','碧草垂低岸，東風起細波。',24,'全唐诗/poet.song.0.json','["碧草垂低岸，東風起細波。", "橫汾從游宴，何謝到天河。"]'),
('9cc2a2b1-c7c7-4d4e-927a-5ac99e08d0b0','北苑侍宴雜詠詩 風','徐鉉','宋','宋诗','song-poetry','','[]','昨朝纔解凍，今日又開花。',24,'全唐诗/poet.song.0.json','["昨朝纔解凍，今日又開花。", "帝力無人識，誰知玩物華。"]'),
('ad409111-c32c-44ad-8578-d64d2f2f260b','北苑侍宴雜詠詩 菊','徐鉉','宋','宋诗','song-poetry','','[]','細麗披金彩，氛氳散遠馨。',24,'全唐诗/poet.song.0.json','["細麗披金彩，氛氳散遠馨。", "汎杯頻奉賜，緣解制頹齡。"]'),
('5b740bd6-94a9-46be-a13b-451c1f060499','柳枝詞十首  其一','徐鉉','宋','宋诗','song-poetry','','[]','金馬詞臣賦小詩，梨園弟子唱新詞。',32,'全唐诗/poet.song.0.json','["金馬詞臣賦小詩，梨園弟子唱新詞。", "君恩還似東風意，先入靈和蜀柳枝。"]'),
('ec94d378-300d-4d6a-9001-5a0296aefcd6','柳枝詞十首  其二','徐鉉','宋','宋诗','song-poetry','','[]','百草千花共待春，綠楊顔色最驚人。',32,'全唐诗/poet.song.0.json','["百草千花共待春，綠楊顔色最驚人。", "天邊雨露年年在，上苑芳華歲歲新。"]'),
('7202ae3e-7d4f-47c4-88dc-fd0cbd24a407','柳枝詞十首  其三','徐鉉','宋','宋诗','song-poetry','','[]','長愛龍池二月時，毿毿金線弄春姿。',32,'全唐诗/poet.song.0.json','["長愛龍池二月時，毿毿金線弄春姿。", "假饒葉落枝空後，更有梨園笛裏吹。"]'),
('72dfe952-4e50-4f03-88ee-7623b6024d50','柳枝詞十首  其四','徐鉉','宋','宋诗','song-poetry','','[]','綠水成文柳带摇，東風初到不鳴條。',32,'全唐诗/poet.song.0.json','["綠水成文柳带摇，東風初到不鳴條。", "龍舟欲過偏留戀，萬縷輕絲拂御橋。"]'),
('210a73cb-453b-402a-b6de-3ed684edca2b','柳枝詞十首  其五','徐鉉','宋','宋诗','song-poetry','','[]','百尺長條婉麴塵，詩題不盡畫難真。',32,'全唐诗/poet.song.0.json','["百尺長條婉麴塵，詩題不盡畫難真。", "憑君折向人間種，還似君恩處處春。"]'),
('9960ec03-98c0-43da-a756-91ead6dd32fb','柳枝詞十首  其六','徐鉉','宋','宋诗','song-poetry','','[]','風暖雲開晚照明，翠條深映鳳皇城。',32,'全唐诗/poet.song.0.json','["風暖雲開晚照明，翠條深映鳳皇城。", "人間欲識靈和態，聽取新詞玉管聲。"]'),
('6365fdd4-5440-4f31-beb8-b98d00c05ced','柳枝詞十首  其七','徐鉉','宋','宋诗','song-poetry','','[]','醉折垂楊唱柳枝，金城三月走金羈。',32,'全唐诗/poet.song.0.json','["醉折垂楊唱柳枝，金城三月走金羈。", "年年爲愛新條好，不覺蒼華也似絲。"]'),
('2bedbe45-6fd5-4af8-9dc1-86ce1b65d6da','柳枝詞十首  其八','徐鉉','宋','宋诗','song-poetry','','[]','新春花柳競芳姿，偏愛垂楊拂地枝。',32,'全唐诗/poet.song.0.json','["新春花柳競芳姿，偏愛垂楊拂地枝。", "天子徧教詞客賦，宮中要唱洞簫詞。"]'),
('0a59f3f2-1fe3-4834-afb9-089b36b673bc','柳枝詞十首  其九','徐鉉','宋','宋诗','song-poetry','','[]','凝碧池頭蘸翠漣，鳳皇樓畔簇晴烟。',32,'全唐诗/poet.song.0.json','["凝碧池頭蘸翠漣，鳳皇樓畔簇晴烟。", "新詞欲詠知難詠，說與雙成入管弦。"]'),
('e4baf6ce-b0d2-42c4-ba4c-d26e9f0e2c63','柳枝詞十首  其一○','徐鉉','宋','宋诗','song-poetry','','[]','侍從甘泉與未央，移舟偏要近垂楊。',32,'全唐诗/poet.song.0.json','["侍從甘泉與未央，移舟偏要近垂楊。", "櫻桃未綻梅先老，折得柔條百尺長。"]'),
('a9034174-f585-4118-b92b-eee02d8054de','奉和宮傅相公懷舊見寄四十韻','徐鉉','宋','宋诗','song-poetry','','[]','謝傅功成德望全，鸞臺初下正蕭然。',384,'全唐诗/poet.song.0.json','["謝傅功成德望全，鸞臺初下正蕭然。", "摶風乍息三千里，感舊重懷四十年。", "西掖新官同賈馬，南朝興運似開天。", "文辭職業分工拙，流輩班資讓後先。", "每愧陋容勞刻畫，長慚頑石費雕鎸。", "晨趨綸掖吟春永，夕會精廬待月圓。", "立馬有時同草詔，聯鑣幾處共成篇。", "閑歌柳葉翻新曲，醉詠桃花促綺筵。", "少壯況逢時世好，經過寧慮歲華遷。", "雲龍得路須騰躍，社櫟非材合棄捐。", "再謁湘江猶是幸，兩還宣室竟何緣。", "已知瑕玷勞磨瑩，又得官司重接連。", "聽漏分宵趨建禮，從遊同召赴甘泉。", "雲開閶闔分臺殿，風過華林度管弦。", "行止不離宮仗影，衣裾嘗惹御爐烟。", "師資稷契論中禮，依止山公典小銓。", "多謝天波垂赤管，敢教晨景過華磚。", "翾飛附驥方經遠，巨楫垂風遂濟川。", "玉燭調時鈞軸正，台階平處德星懸。", "巖廊禮絕威容肅，布素情深友好偏。", "長擬營巢安大厦，忽經操鉞領中權。", "吳門日麗龍銜節，京口沙晴鷁畫船。", "蓋代名高方赫赫，戀恩心切更乾乾。", "袁安辭氣忠仍懇，吳漢精誠直且專。"]'),
('94059114-ac1c-4802-b9cb-a319fafb948a','右省僕射相公垂覽和詩復貽長句輒次來韻','徐鉉','宋','宋诗','song-poetry','','[]','西院春歸道思深，披衣閑聽暝猿吟。',64,'全唐诗/poet.song.0.json','["西院春歸道思深，披衣閑聽暝猿吟。", "鋪陳政事留黄閣，偃息神機在素琴。", "玉柄暫時疏末座，瑶華頻復惠清音。", "開晴便作東山約，共賞烟霞放曠心。"]'),
('2aea95aa-f3fa-4198-8507-0c5e54964817','九日落星山登高','徐鉉','宋','宋诗','song-poetry','','[]','秋暮天高稻穟成，落星山上會諸賓。',64,'全唐诗/poet.song.0.json','["秋暮天高稻穟成，落星山上會諸賓。", "黄花汎酒依流俗，白髮滿頭思古人。", "巖影晚看雲出岫，湖光遥見客垂綸。", "風烟不改年長度，終待林泉老此身。"]'),
('63b4d1a5-8963-4ad0-abd9-7d3964ca6991','十日和張少監','徐鉉','宋','宋诗','song-poetry','','[]','重陽高會古平臺，吟徧秋光始下來。',64,'全唐诗/poet.song.0.json','["重陽高會古平臺，吟徧秋光始下來。", "黄菊後期香未減，新詩捧得眼還開。", "每因佳節知身老，却憶前歡似夢迴。", "且喜清時屢行樂，是非名利盡悠哉。"]'),
('3c050942-e64c-4e31-b5c0-45ae1acb79ca','御筵送鄧王','徐鉉','宋','宋诗','song-poetry','','[]','禁裏秋光似水清，林烟池影共離情。',64,'全唐诗/poet.song.0.json','["禁裏秋光似水清，林烟池影共離情。", "暫移黄閣只三載，却望紫垣都數程。", "滿座清風天子送，隨車甘雨郡人迎。", "綺霞閣上詩題在，從此還應有頌聲。"]'),
('10d5b39d-05c9-4599-a5d6-4f01291bae8a','和張少監晚菊','徐鉉','宋','宋诗','song-poetry','','[]','憶共庭蘭倚砌栽，柔條輕吹獨依隈。',64,'全唐诗/poet.song.0.json','["憶共庭蘭倚砌栽，柔條輕吹獨依隈。", "自知佳節終堪賞，爲惜流光未忍開。", "采擷也須盈掌握，馨香還解滿罇罍。", "今朝旬假猶無事，更好登臨汎一杯。"]'),
('c9e86210-b672-41db-9912-52e3c7b2af17','送馮侍御','徐鉉','宋','宋诗','song-poetry','','[]','聞君竹馬戲毗陵，誰道觀風自六卿。',64,'全唐诗/poet.song.0.json','["聞君竹馬戲毗陵，誰道觀風自六卿。", "今日聲明光舊物，共看旌旆擁書生。", "斬蛟橋下谿烟碧，射虎亭邊草路清。", "應念筵中倍離恨，老來偏重十年兄。"]'),
('cac7a89b-e5c9-40ef-bbca-b21094881d2b','又絕句寄題毗陵驛','徐鉉','宋','宋诗','song-poetry','','[]','曾持使節駐毗陵，長與州人有舊情。',32,'全唐诗/poet.song.0.json','["曾持使節駐毗陵，長與州人有舊情。", "爲向驛橋風月道，舍人髭鬢白千莖。"]'),
('80fdcfcc-9a0d-4c22-8f47-b5afec1dff75','陳侍郎宅觀花燭','徐鉉','宋','宋诗','song-poetry','','[]','今夜銀河萬里秋，人言織女嫁牽牛。',64,'全唐诗/poet.song.0.json','["今夜銀河萬里秋，人言織女嫁牽牛。", "珮聲寥亮和金奏，燭影熒煌映玉鈎。", "座客亦從天子賜，更籌須爲主人留。", "世間盛事君知否，朝下鸞臺夕鳳樓。"]'),
('462d3c33-9f26-4d25-a3f9-cc2886a7e7dc','送蕭尚書致仕歸廬陵','徐鉉','宋','宋诗','song-poetry','','[]','江海分飛二十春，重論前事不堪聞。',64,'全唐诗/poet.song.0.json','["江海分飛二十春，重論前事不堪聞。", "主憂臣辱誰非我，曲突徙薪唯有君。", "金紫滿身皆外物，雪霜垂領便離羣。", "鶴歸華表望不盡，玉笥山頭多白雲。"]'),
('288bb601-05cd-42c8-99d7-bfde0afb9d47','賦得秋江晚照','徐鉉','宋','宋诗','song-poetry','','[]','落日照平流，晴空萬里秋。',48,'全唐诗/poet.song.0.json','["落日照平流，晴空萬里秋。", "輕明動楓葉，點的亂沙鷗。", "罾網魚梁靜，籉簦稻穗收。", "不教行樂倦，冉冉下城樓。"]'),
('55c8800e-e40e-453e-9157-229abf530ae7','奉和子龍大監與舍弟贈答之什','徐鉉','宋','宋诗','song-poetry','','[]','石渠東觀兩優賢，明主知臣豈偶然。',64,'全唐诗/poet.song.0.json','["石渠東觀兩優賢，明主知臣豈偶然。", "鵷鷺分行皆接武，金蘭同好共忘年。", "懷恩未遂林泉約，竊位空慚組綬懸。", "多少深情知不盡，好音相慰强成篇。"]'),
('836b81be-6f1e-4b90-8ec0-2da84f270b67','史館庭梅見其毫末歷載三十今已半枯同僚諸公唯相公與鉉在耳睹物興感率成短篇謹書獻上伏惟垂覽','徐鉉','宋','宋诗','song-poetry','','[]','東觀婆娑樹，曾憐甲坼時。',48,'全唐诗/poet.song.0.json','["東觀婆娑樹，曾憐甲坼時。", "繁英共攀折，芳歲幾推移。", "往事皆陳迹，清香亦暗衰。", "相看宜自喜，雙鬢合垂絲。"]'),
('066d9a19-5344-49d0-9274-9b2b77132937','太傅相公深感庭梅再成絕唱曲垂借示倍認知憐謹用舊韻攀和','徐鉉','宋','宋诗','song-poetry','','[]','禁省繁華地，含芳自一時。',48,'全唐诗/poet.song.0.json','["禁省繁華地，含芳自一時。", "雪英開復落，紅藥植還移。", "靜想分今昔，頻吟歎盛衰。", "多情共如此，爭免鬢成絲。"]'),
('9c6b3684-f686-44f7-9796-7e785056519c','太傅相公以庭梅二篇許舍弟同賦再迂藻思曲有虛稱謹依韻奉和庶申感謝','徐鉉','宋','宋诗','song-poetry','','[]','舊眷終無替，流光自足悲。',48,'全唐诗/poet.song.0.json','["舊眷終無替，流光自足悲。", "攀條感花萼，和曲許塤箎。", "前會成春夢，何人更己知。", "緣情聊借喻，爭敢道言詩。"]'),
('1507e8bb-f874-462a-89ee-7aff2f717a3a','和鍾大監汎舟同游見示','徐鉉','宋','宋诗','song-poetry','','[]','潮溝橫趣北山阿，一月三游未是多。',64,'全唐诗/poet.song.0.json','["潮溝橫趣北山阿，一月三游未是多。", "老去交親難暫舍，閒中滋味更無過。", "谿橋樹映行人渡，村徑風飄牧豎歌。", "孤櫂亂流偏有興，滿川晴日弄微波。"]'),
('3b2faff7-47d4-46e2-a25e-d2f3776b94fa','又和游光睦院','徐鉉','宋','宋诗','song-poetry','','[]','寺門山水際，清淺照孱顔。',48,'全唐诗/poet.song.0.json','["寺門山水際，清淺照孱顔。", "客櫂晚維岸，僧房猶掩關。", "日華穿竹靜，雲影過階閒。", "箕踞一長嘯，忘懷物我間。"]'),
('6a3a1696-7786-4545-ab59-f14fd8b05da0','和張少監舟中望蔣山','徐鉉','宋','宋诗','song-poetry','','[]','谿路向還背，前山高復重。',48,'全唐诗/poet.song.0.json','["谿路向還背，前山高復重。", "紛披紅葉樹，間鬭白雲峰。", "盡日慵移櫂，何年醉倚松。", "自知閑未得，不敢笑周顒。"]'),
('6be8e8e9-cc72-4f2a-8859-99450c0995d0','茱萸詩','徐鉉','宋','宋诗','song-poetry','','[]','萬物慶西成，茱萸獨擅名。',48,'全唐诗/poet.song.0.json','["萬物慶西成，茱萸獨擅名。", "房排紅結小，香透夾衣輕。", "宿露霑猶重，朝陽照更明。", "長和菊花酒，高宴奉西清。"]'),
('9667c285-4024-4ba1-a5d3-759a5b81a653','奉和御製茱萸','徐鉉','宋','宋诗','song-poetry','','[]','臺畔西風御果新，芳香精彩麗蕭辰。',64,'全唐诗/poet.song.0.json','["臺畔西風御果新，芳香精彩麗蕭辰。", "柔條細葉妝治好，紫蔕紅芳點綴勻。", "幾朵得陪天上宴，千株長作洞中春。", "今朝聖藻偏流詠，黄菊無由更敢鄰。"]'),
('0ab78740-d648-4290-8b54-24cc1be79bce','蒙恩賜酒奉旨令醉進詩以謝','徐鉉','宋','宋诗','song-poetry','','[]','明光殿裏夜迢迢，多病逢秋自寂寥。',64,'全唐诗/poet.song.0.json','["明光殿裏夜迢迢，多病逢秋自寂寥。", "蠟炬乍傳丹鳳詔，御題初認白雲謠。", "今宵幸識衢罇味，明日知停入閤朝。", "爲感君恩判一醉，不煩辛苦解金貂。"]'),
('98cf42b7-d2b2-497e-b27b-c9f4b6c3ca68','秋日汎舟賦蘋花','徐鉉','宋','宋诗','song-poetry','','[]','素豔擁行舟，清香覆碧流。',48,'全唐诗/poet.song.0.json','["素豔擁行舟，清香覆碧流。", "遠烟分的的，輕浪汎悠悠。", "雨歇平湖滿，風凉運瀆秋。", "今朝流詠處，即是白蘋洲。"]'),
('07b207a0-29c5-4f25-83ca-8948ff0df0f5','題梁王舊園','徐鉉','宋','宋诗','song-poetry','','[]','梁王舊館枕潮溝，共引垂藤繫小舟。',64,'全唐诗/poet.song.0.json','["梁王舊館枕潮溝，共引垂藤繫小舟。", "樹倚荒臺風淅淅，草埋欹石雨修修。", "門前不見鄒枚醉，池上時聞雁鶩愁。", "節士逢秋多感激，不須頻向此中游。"]'),
('ccec2d5a-63aa-44c4-92e2-de91cede2d95','奉酬度支陳員外','徐鉉','宋','宋诗','song-poetry','','[]','古來賢達士，馳騖唯羣書。',72,'全唐诗/poet.song.0.json','["古來賢達士，馳騖唯羣書。", "非禮誓弗習，違道無與居。", "儒家苦迂闊，遂將世情疏。", "吾友嗣世德，古風藹有餘。", "幸遇漢文皇，握蘭佩金魚。", "俯視長沙賦，悽悽將焉如。"]'),
('657ac7f9-3fef-402e-b269-15fed58bbba0','明道人歸西林求題院額作此送之','徐鉉','宋','宋诗','song-poetry','','[]','昔從岐陽狩，簪纓滿翠微。',48,'全唐诗/poet.song.0.json','["昔從岐陽狩，簪纓滿翠微。", "十年勞我夢，今日送師歸。", "曳尾龜應樂，乘軒鶴謾肥。", "含情題小篆，將去挂巖扉。"]'),
('8eba8c41-0f91-47cd-89de-5fcb023c1e79','送宣州丘判官','徐鉉','宋','宋诗','song-poetry','','[]','憲署游從阻，平臺道路賒。',48,'全唐诗/poet.song.0.json','["憲署游從阻，平臺道路賒。", "喜君馳後乘，於此會仙槎。", "緩酌遲飛蓋，微吟望綺霞。", "相迎在春渚，暫別莫咨嗟。"]'),
('26778cb8-57c8-41c3-b8d0-10fe856251b8','北使還襄邑道中作','徐鉉','宋','宋诗','song-poetry','','[]','九月三十日，獨行梁宋道。',48,'全唐诗/poet.song.0.json','["九月三十日，獨行梁宋道。", "河流激似飛，林葉翻如掃。", "程遥苦晝短，野迥知寒早。", "還家亦不閒，要且還家了。"]'),
('d0d846c4-33f2-4b1e-890d-981448a85fc8','禁中新月','徐鉉','宋','宋诗','song-poetry','','[]','今夕拜新月，沉沉禁署中。',48,'全唐诗/poet.song.0.json','["今夕拜新月，沉沉禁署中。", "玉繩疏間彩，金掌靜無風。", "節換知身老，時平見歲功。", "吟看北墀暝，蘭燼墜微紅。"]'),
('c62208ca-4719-43ab-8791-241cbf81187e','觀吉王花燭','徐鉉','宋','宋诗','song-poetry','','[]','王門嘉禮萬人觀，況是新承置醴歡。',64,'全唐诗/poet.song.0.json','["王門嘉禮萬人觀，況是新承置醴歡。", "花燭喧闐丞相府，星辰摇動遠遊冠。", "歌聲暫闋聞宮漏，雲影初開見露盤。", "帝里佳期頻賦頌，長留故事在金鑾。"]'),
('e91f1c16-f63f-4d6a-98fc-b22efa1a45bd','棋賭賦詩輸劉起居','徐鉉','宋','宋诗','song-poetry','','[]','刻燭知無取，爭先素未精。',48,'全唐诗/poet.song.0.json','["刻燭知無取，爭先素未精。", "本圖忘物我，何必計輸贏。", "賭墅終規利，焚囊亦近名。", "不如相視笑，高詠兩三聲。"]'),
('ebd4ec26-a6a8-4d50-b436-e162361ad1fb','春盡日游後湖贈劉起居','徐鉉','宋','宋诗','song-poetry','','[]','今朝湖上送春歸，萬頃澄波照白髭。',32,'全唐诗/poet.song.0.json','["今朝湖上送春歸，萬頃澄波照白髭。", "笑折殘花勸君酒，金丹成熟是何時。"]'),
('e92189cc-d4c9-4e4d-ac90-99b3dd731b29','送察院李侍御使廬陵因寄孟員外','徐鉉','宋','宋诗','song-poetry','','[]','繡衣乘驛急如星，山水何妨寄野情。',32,'全唐诗/poet.song.0.json','["繡衣乘驛急如星，山水何妨寄野情。", "肯向九仙臺下歇，閒聽孟叟醉吟聲。"]'),
('917aef64-97d5-4945-af1d-d615da1956fe','後湖訪古各賦一題得西邸','徐鉉','宋','宋诗','song-poetry','','[]','南朝藩閫地，八友舊招尋。',48,'全唐诗/poet.song.0.json','["南朝藩閫地，八友舊招尋。", "事往山光在，春晴草色深。", "曲池魚自樂，叢桂鳥頻吟。", "今日中興運，猶懷翰墨林。"]'),
('2f22d762-f0a8-4806-a198-fb0f81af3cfa','送德邁道人之豫章','徐鉉','宋','宋诗','song-poetry','','[]','禪靈橋畔落殘花，橋上離情對日斜。',64,'全唐诗/poet.song.0.json','["禪靈橋畔落殘花，橋上離情對日斜。", "顧我乘軒慚組綬，羨師飛錫指烟霞。", "樓中西嶺真君宅，門外南州處士家。", "莫道空談便無事，碧雲詩思更無涯。"]'),
('e546352e-fdc4-4aa1-98a9-75a331ce4358','送陳秘監歸泉州','徐鉉','宋','宋诗','song-poetry','','[]','風滿潮溝木葉飛，水邊行客駐驂騑。',64,'全唐诗/poet.song.0.json','["風滿潮溝木葉飛，水邊行客駐驂騑。", "三朝恩澤馮唐老，萬里鄉關賀監歸。", "世路窮通前事遠，半生談笑此心違。", "離歌不識高堂慶，特地令人淚滿衣。"]'),
('3ec3bfd0-4846-43e4-af97-38d23a2a803b','又聽霓裳羽衣曲送陳君','徐鉉','宋','宋诗','song-poetry','','[]','清商一曲遠人行，桃葉津頭月正明。',32,'全唐诗/poet.song.0.json','["清商一曲遠人行，桃葉津頭月正明。", "此是開元太平曲，莫教偏作別離聲。"]'),
('d2ad87dd-a580-4250-89fd-92f34ef1f02b','又題白鷺洲江鷗送陳君','徐鉉','宋','宋诗','song-poetry','','[]','白鷺洲邊江路斜，輕鷗接翼滿平沙。',128,'全唐诗/poet.song.0.json','["白鷺洲邊江路斜，輕鷗接翼滿平沙。", "吾徒來送遠行客，停舟爲爾長歎息。", "酒旗漁艇兩無猜，月影蘆花鎮相得。", "離筵一曲怨復清，滿座銷魂鳥不驚。", "人生不及水禽樂，安用虛名上麟閣。", "同心携手今如此，金鼎丹砂何寂寞。", "天涯後會眇難期，從此又應添白髭。", "願君不忘分飛處，長保翩翩潔白姿。"]'),
('f83a98bd-d906-4821-8cac-cdf0f8762585','奉和御製雪','徐鉉','宋','宋诗','song-poetry','','[]','豐登盈尺瑞，物象九門深。',48,'全唐诗/poet.song.0.json','["豐登盈尺瑞，物象九門深。", "璧照環丹砌，梅花滿上林。", "茶香偏自得，酒力詎難禁。", "別有寒郊外，銀河映玉岑。"]'),
('978758c2-c98b-4439-9a9d-5ede283602ff','奉和御製打毬','徐鉉','宋','宋诗','song-poetry','','[]','上閑精習渥洼驄，玉鏤花鞍錦覆騣。',64,'全唐诗/poet.song.0.json','["上閑精習渥洼驄，玉鏤花鞍錦覆騣。", "金埒無塵初裛露，朱旗向日自生風。", "雷傳畫鼓偏增氣，星度飛毬欲映空。", "共道宸遊因習武，凱歌猶似奏平戎。"]'),
('8a404587-9b45-4c33-a4b5-f3188c1dcc66','又五言','徐鉉','宋','宋诗','song-poetry','','[]','彩仗映花韉，春庭散曙烟。',48,'全唐诗/poet.song.0.json','["彩仗映花韉，春庭散曙烟。", "毬飛皆應手，馬駿不須鞭。", "仙樂飄雲外，祥風近日邊。", "籌多不虛發，制勝在機先。"]'),
('438872df-5198-4c64-9196-889fa390dd06','奉和御製春雨','徐鉉','宋','宋诗','song-poetry','','[]','祁祁甘雨正當春，草樹精神一倍新。',64,'全唐诗/poet.song.0.json','["祁祁甘雨正當春，草樹精神一倍新。", "勻灑農郊偏長麥，緩飄花檻不驚人。", "密隨宮仗環青輅，普逐皇恩下紫宸。", "霽後樓臺更堪望，滿園桃李間松筠。"]'),
('3633918b-f70a-43b8-a0d0-c64dd2dbffd3','冬至日奉和御製','徐鉉','宋','宋诗','song-poetry','','[]','吹律政知寬，迎長物倍安。',48,'全唐诗/poet.song.0.json','["吹律政知寬，迎長物倍安。", "初陽殊勝臘，積雪更添寒。", "庭實羅千品，珍符薦百般。", "羣臣同偶聖，不歎夜漫漫。"]'),
('48f3c584-0f3e-4baf-bf18-ee2437d4558d','奉和御製寒食十韻','徐鉉','宋','宋诗','song-poetry','','[]','朝陽散宿烟，登望思悠然。',120,'全唐诗/poet.song.0.json','["朝陽散宿烟，登望思悠然。", "簷影晴偏暖，雲容晚更鮮。", "共歡時景好，不惜歲華遷。", "旋試嬌驄步，新調寶瑟弦。", "宮花紅照耀，御水碧潺湲。", "歌吹清連夜，輜軿麗滿川。", "依林張幄幕，夾道建鞦韆。", "仙樂來天上，祥光起日邊。", "遊絲輕冉冉，芳草綠芊芊。", "聖製如春色，周流遍八埏。"]'),
('7044a06c-2e31-43ad-8989-5957aa1dfce7','奉和御製歲日二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','運曆三元正，升平太古同。',48,'全唐诗/poet.song.0.json','["運曆三元正，升平太古同。", "五侯皆輯瑞，四海盡占風。", "聖政乾行內，羣生壽域中。", "撞鐘元會罷，晃朗日升東。"]'),
('1ef1dbd7-7fa7-4075-b1f1-b0631d80b31b','奉和御製歲日二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','正仗臨軒萬國來，漢儀周禮盡堪咍。',64,'全唐诗/poet.song.0.json','["正仗臨軒萬國來，漢儀周禮盡堪咍。", "光浮雲蓋青龍轉，香透椒花白獸開。", "慶賜應時均億兆，卜年從此數京垓。", "羣臣共感文明運，況是天言誡懋哉。"]'),
('5243795f-be42-4f5d-b9c8-b4d74671deee','奉和御製上元燈','徐鉉','宋','宋诗','song-poetry','','[]','幔亭高敞九門前，銀箭遲遲夜漏遷。',64,'全唐诗/poet.song.0.json','["幔亭高敞九門前，銀箭遲遲夜漏遷。", "明月靜添華燭影，和風時度御爐烟。", "朱輪繡轂車聲接，玉勒金羈馬首駢。", "一曲雲謠飛聖藻，萬方歌詠仰堯天。"]'),
('91d1e460-ed78-4a00-a257-5f974bc7a74b','奉和御製烟','徐鉉','宋','宋诗','song-poetry','','[]','春晴纖靄映斜陽，羃羃偏能覆水鄉。',64,'全唐诗/poet.song.0.json','["春晴纖靄映斜陽，羃羃偏能覆水鄉。", "濃似慶雲同馥郁，薄如輕素自飛揚。", "堤橫新柳真成畫，樓對遥山正好望。", "誰見朝元香案上，龍旂交影共騰驤。"]'),
('3899a05f-cea9-48ce-aee9-617ef27a9e8b','奉和御製暑中書懷','徐鉉','宋','宋诗','song-poetry','','[]','浴殿晨開氣象新，虛亭金井轆轤鳴。',64,'全唐诗/poet.song.0.json','["浴殿晨開氣象新，虛亭金井轆轤鳴。", "陰成楊柳千絲密，凉入襟懷一扇輕。", "寒水乍沉朱李熟，薰綃長有好風生。", "高樓更稱頻臨望，臺笠行歌麥隴青。"]'),
('cc8969ca-3bb4-434a-a356-b0f6add571f7','奉和御製聞早蟬','徐鉉','宋','宋诗','song-poetry','','[]','綠樹陰陰愜豫遊，早蟬清韻遠還收。',64,'全唐诗/poet.song.0.json','["綠樹陰陰愜豫遊，早蟬清韻遠還收。", "喚迴晝夢和宮漏，引起微凉助麥秋。", "禁柳烟中飛乍覺，御溝聲裏聽偏幽。", "羣生遂性宸章悅，從此人間不識愁。"]'),
('2d5ac908-8d32-4792-af86-aada58fc5470','奉和御製夏中垂釣作','徐鉉','宋','宋诗','song-poetry','','[]','物茂時平日正長，翠華停馭睠方塘。',64,'全唐诗/poet.song.0.json','["物茂時平日正長，翠華停馭睠方塘。", "文竿乍拂圓荷動，頳尾時翻素荇香。", "睿賞只應從暇豫，聖恩寧肯間沉翔。", "吞舟自是貪芳餌，猶笑成湯一面張。"]'),
('c52a06fe-f572-4acd-8963-b77020b390d7','奉和御製殿前松兼以書事','徐鉉','宋','宋诗','song-poetry','','[]','長松修幹列承明，虎盼龍盤氣貌靈。',64,'全唐诗/poet.song.0.json','["長松修幹列承明，虎盼龍盤氣貌靈。", "風度乍聞琴曲調，巢高初見鶴儀形。", "枝籠陛戟寒生檻，葉带鑪烟翠滿庭。", "澗底山頭各生殖，託根爭似在青冥。"]'),
('8b314d21-40e5-4570-b490-2e4317ecef80','奉和御製扇','徐鉉','宋','宋诗','song-poetry','','[]','齊紈新裂月輪全，蟬雀分明彩翠鮮。',64,'全唐诗/poet.song.0.json','["齊紈新裂月輪全，蟬雀分明彩翠鮮。", "救暍自符仁主意，揚風須假手中扇。", "暫遮樓日霞光透，半掩歌唇寶靨圓。", "一曲睿調精比興，好將金石奉雕鎸。"]'),
('01b5246e-67e1-413d-8d1b-9e91341f0485','奉和御製棋二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','制法精微自帝堯，勢如天陣布週遭。',64,'全唐诗/poet.song.0.json','["制法精微自帝堯，勢如天陣布週遭。", "沉思迥覺忘千慮，妙訣終須附六韜。", "急劫未分香印匝，一枰初滿月華高。", "御詞仍許羣臣和，愁殺山中玉兔毫。"]'),
('282ef7f7-b18f-4e97-99a3-7ec076b5be54','奉和御製棋二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','常嫌羣藝用心麤，不及棋枰出萬途。',64,'全唐诗/poet.song.0.json','["常嫌羣藝用心麤，不及棋枰出萬途。", "妙似孫吳論上策，深如夔益贊訏謨。", "靜陳玉檻連琴榻，密映珠簾對酒壺。", "聖智縱橫歸掌握，一先終不費多圖。"]'),
('38e9dab4-5c2a-4c5c-8c4e-99fa9b1f41b9','奉和御製早春','徐鉉','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','羣生遂性得天真，陽景無私發秀勻。',64,'全唐诗/poet.song.0.json','["羣生遂性得天真，陽景無私發秀勻。", "堯曆永從新律正，皇恩散作萬方春。", "華林日麗紅苞拆，太液冰消綠浪新。", "天意分明啟昌運，岱宗即看報羣神。"]'),
('c6c3c0b7-bc81-4008-8135-f5332a1e3589','應制賞花','徐鉉','宋','宋诗','song-poetry','','[]','上林春暮紫英開，組繡成帷蔭玉階。',64,'全唐诗/poet.song.0.json','["上林春暮紫英開，組繡成帷蔭玉階。", "艷逐晨光隨步武，香和輕翠透襟懷。", "生成澤廣時芳茂，魚水情通樂韻諧。", "禁篽年年陪睿賞，何時梁甫奉燔柴。"]'),
('b02c146e-45a8-4289-a469-410b4498945e','和陳處士在雍丘見寄','徐鉉','宋','宋诗','song-poetry','','[]','衰薄喜多幸，退公誰與閑。',48,'全唐诗/poet.song.0.json','["衰薄喜多幸，退公誰與閑。", "高人乘興去，相望兩程間。", "卷箔有微雪，登樓無遠山。", "清談勝題贈，何日杖藜還。"]'),
('7449b0ad-b41a-4233-9893-1e8bf21014c0','送湯舍人之陳州','徐鉉','宋','宋诗','song-poetry','','[]','尼父恓惶地，離情向此偏。',48,'全唐诗/poet.song.0.json','["尼父恓惶地，離情向此偏。", "家貧聊復爾，道在肯徒然。", "詩景明松雪，鄉山隔水烟。", "三年須赴召，莫戀甕頭眠。"]'),
('050c9b53-31d0-4dc2-a78e-e013a7eb16e8','送阮監丞赴餘杭','徐鉉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','楊柳依依水岸斜，鷁舟東去思無涯。',64,'全唐诗/poet.song.0.json','["楊柳依依水岸斜，鷁舟東去思無涯。", "坐臨棋局延明月，行采題詩對落花。", "虛白亭中多宴賞，錢塘湖上剩烟霞。", "風光到處宜携酒，況有餘杭阿姥家。"]'),
('2447e354-273a-4a27-b785-a0bece6b49fe','送容州程員外端州吳員外','徐鉉','宋','宋诗','song-poetry','','[]','士生秉道義，公論重才名。',120,'全唐诗/poet.song.0.json','["士生秉道義，公論重才名。", "美哉雙白璧，高價等連城。", "昔在南國時，折桂嘗抗衡。", "今爲北朝客，通籍齊振纓。", "連鑣適炎徼，並命典州兵。", "地遠乃寄重，無爲憚遐征。", "俗雜則財難，當在通其情。", "投香與還珠，前哲有遺聲。", "君看奏諫者，接武趨承明。", "摻袂贈斯言，斯言勿見輕。"]'),
('7af3afc8-455a-4a2e-9c4a-0759bf8cb506','和潁川曹監軍','徐鉉','宋','宋诗','song-poetry','','[]','別離情緒兩難任，消遣唯應有醉吟。',64,'全唐诗/poet.song.0.json','["別離情緒兩難任，消遣唯應有醉吟。", "冉冉光陰玄鬢改，勤勤書札舊情深。", "凉宵夢寐清淮月，永日徘徊玉樹陰。", "野鶴乘軒無所用，角巾何日返中林。"]'),
('ba5e95c9-79f2-4cf6-9cfe-04ed104e8e3d','和清源太保閒居偶懷','徐鉉','宋','宋诗','song-poetry','','[]','朝退閒齋落葉天，道心真氣本仙源。',64,'全唐诗/poet.song.0.json','["朝退閒齋落葉天，道心真氣本仙源。", "簾前風月澄秋景，門外輪蹄任世喧。", "棋罷早寒生北戶，酒醒黄菊滿西園。", "時人自有思齊者，踐迹觀形不在言。"]'),
('8fceb2de-cf8c-4ac4-bbfe-4115dcab6c9a','又和寄光山徐員外','徐鉉','宋','宋诗','song-poetry','','[]','早年南國日追隨，冠劍晶熒佩陸離。',64,'全唐诗/poet.song.0.json','["早年南國日追隨，冠劍晶熒佩陸離。", "匪石心誠徒自許，浮雲蹤跡信難知。", "官閒從飲扶頭酒，地僻誰同敵手棋。", "門館舊恩今更重，高齋遥枉謝公詩。"]'),
('0b2ebb2a-8439-4b76-9200-24b660dd84da','和徐秘書','徐鉉','宋','宋诗','song-poetry','','[]','年少支離奈命何，悲秋懷舊苦吟多。',64,'全唐诗/poet.song.0.json','["年少支離奈命何，悲秋懷舊苦吟多。", "龍泉有氣終難掩，荆玉無瑕豈憚磨。", "會偶良工收杞梓，莫將閒夢挂烟蘿。", "他年得路摶風去，肯念今朝煦沫麽。"]'),
('364e2ffe-1bce-4788-97cc-24bc8b9d9b57','送汪處士還黟歙','徐鉉','宋','宋诗','song-poetry','','[]','孤雲野鶴任天真，乘興遊梁又適秦。',32,'全唐诗/poet.song.0.json','["孤雲野鶴任天真，乘興遊梁又適秦。", "興去却歸南國去，黄山何謝武陵春。"]'),
('93c2038b-867b-4388-adc0-e962c0143a0c','和翰長聞西樞副翰鄰居夜宴','徐鉉','宋','宋诗','song-poetry','','[]','開筵別有鄰居興，卜夜應憐禁漏長。',64,'全唐诗/poet.song.0.json','["開筵別有鄰居興，卜夜應憐禁漏長。", "舊友不期爭命駕，新姬憑寵剩傳觴。", "香烟結霧籠金鴨，燭焰成花照杏梁。", "京邑衣冠多勝賞，鱸魚爭敢道思鄉。"]'),
('002013d9-fb76-4e59-9e0b-83b3da77d0bf','和清源太保寄湖州潘郎中','徐鉉','宋','宋诗','song-poetry','','[]','老大離羣一倍愁，谿山風物且淹留。',64,'全唐诗/poet.song.0.json','["老大離羣一倍愁，谿山風物且淹留。", "醖成春酒誰斟酌，抄得新書自校讎。", "莫似牧之矜曠達，須教子重讓風流。", "恩門舊分知難忘，題取新詩上郡樓。"]'),
('8184773c-61bd-41f9-b445-dc7f4046950e','送南華張主簿改承縣','徐鉉','宋','宋诗','song-poetry','','[]','適去莊生邑，還臨孔父鄉。',48,'全唐诗/poet.song.0.json','["適去莊生邑，還臨孔父鄉。", "仍聞舊隠處，近在武夷傍。", "道氣年長度，儒風日以光。", "何時看解組，歸去事仙方。"]'),
('f875659f-040d-4f80-bf0a-d084a63a88ff','和白州錢使君上元夜侍宴','徐鉉','宋','宋诗','song-poetry','','[]','御宴宵陳敞百層，君恩芳景兩難勝。',64,'全唐诗/poet.song.0.json','["御宴宵陳敞百層，君恩芳景兩難勝。", "風傳天上九成樂，月映樓前萬樹燈。", "醉捧玉觴疑夢寐，靜臨丹檻似飛騰。", "因觀謝守窗中詠，自愧瀛洲是濫登。"]'),
('0c64ae90-dae1-4c10-bf28-16074b57dcd3','送蘇州梁補闕','徐鉉','宋','宋诗','song-poetry','','[]','軋軋朱輪道路長，虎丘山下剩春光。',64,'全唐诗/poet.song.0.json','["軋軋朱輪道路長，虎丘山下剩春光。", "軍城舊是吳王國，郡守曾爲諫署郎。", "祖席詠歌金玉振，下車條教蕙蘭香。", "青雲舊是高飛處，三載徘徊亦未妨。"]'),
('b725959a-50e0-4e6f-b074-a6393b562fa5','和金州錢太保春雨','徐鉉','宋','宋诗','song-poetry','','[]','濛濛膏雨遠空迷，點滴圓紋水繞堤。',64,'全唐诗/poet.song.0.json','["濛濛膏雨遠空迷，點滴圓紋水繞堤。", "柳带喜如和醉舞，花房愁似宿妝啼。", "烟籠麥隴連天闊，雲映漁舟掠岸低。", "廉使解分天子念，一篇騷雅慰蒸黎。"]'),
('12f5eaa7-636a-48ee-9db0-8368903ee04c','送高秀才','徐鉉','宋','宋诗','song-poetry','','[]','龍門一上嫌輕進，關塞西遊自愛山。',48,'全唐诗/poet.song.0.json','["龍門一上嫌輕進，關塞西遊自愛山。", "緱嶺春歸林影密，津橋人靜水聲閒。", "如今正得幽尋興，佗日青雲不易還。"]'),
('f5de7cd0-ee1c-4ee4-b7bb-bb03b7393052','送施州單員外','徐鉉','宋','宋诗','song-poetry','','[]','精金百鍊始知難，何似仙枝兩度攀。',64,'全唐诗/poet.song.0.json','["精金百鍊始知難，何似仙枝兩度攀。", "名逐鳳書歸故里，身從鳥道入巴山。", "詔宣遠俗皇恩厚，惠洽齊民利刃閑。", "珍重加餐順風土，歸來高步七人班。"]'),
('57ba0851-6bb0-4f85-97e1-ad3e41f24b83','送宣州張員外','徐鉉','宋','宋诗','song-poetry','','[]','故國干戈後，憐君得意歸。',48,'全唐诗/poet.song.0.json','["故國干戈後，憐君得意歸。", "綺霞橫郡閣，犀燭照漁磯。", "天迥青山遠，江平白鳥飛。", "此行同衣錦，況是老萊衣。"]'),
('cd017ecb-49fe-4237-a46b-f1a33c36cd51','和筠州談鍊師見寄','徐鉉','宋','宋诗','song-poetry','','[]','共嘆崑岡火，誰知玉自分。',48,'全唐诗/poet.song.0.json','["共嘆崑岡火，誰知玉自分。", "寂寥人境外，蕭索數峰雲。", "真籙終年秘，空歌偶得聞。", "應憐霸陵上，衰病故將軍。"]'),
('552757cd-4ce6-44b2-aff5-a7af7a856905','送吳郎西使成州','徐鉉','宋','宋诗','song-poetry','','[]','所向皆爲道，遐征豈足辭。',48,'全唐诗/poet.song.0.json','["所向皆爲道，遐征豈足辭。", "中華垂盡處，別路正秋時。", "高閣蘭臺筆，閒吟板屋詩。", "良工無棄物，珍重歲寒姿。"]'),
('c506cd61-4c4d-422e-99a1-e47f388d57c6','送下博陳員外','徐鉉','宋','宋诗','song-poetry','','[]','曠望叢臺路，飄颻楚塞人。',24,'全唐诗/poet.song.0.json','["曠望叢臺路，飄颻楚塞人。", "琴堂無故舊，何計免霑巾。"]'),
('32bd5779-9286-4a68-9ba7-6184aeb1ca47','送凈道人','徐鉉','宋','宋诗','song-poetry','','[]','北阜與西山，前期夢寐間。',48,'全唐诗/poet.song.0.json','["北阜與西山，前期夢寐間。", "羨師乘興去，應擬此生閑。", "喬木人誰在，鱸魚我未還。", "歸心寄秋水，東去日潺潺。"]'),
('134ed287-07c9-4220-95ff-8ffc3a418178','鄴都行在和刁秘書見寄','徐鉉','宋','宋诗','song-poetry','','[]','征袍結束從宸遊，邊上塵清見戍樓。',64,'全唐诗/poet.song.0.json','["征袍結束從宸遊，邊上塵清見戍樓。", "柏殿賦詩知是幸，茂陵多病自堪愁。", "清漳幽咽長流恨，銅雀荒凉幾換秋。", "深羨高眠全道氣，姓名應已在丹丘。"]'),
('1aee3b51-a0d0-46e3-8b91-eacf3a5243f6','和旻道人見寄','徐鉉','宋','宋诗','song-poetry','','[]','戎服非吾事，華纓寄此身。',48,'全唐诗/poet.song.0.json','["戎服非吾事，華纓寄此身。", "謬爲金馬客，本是釣鄉人。", "引領梁園雪，揚鞭輦路塵。", "知師亦多病，擁褐侍陽春。"]'),
('d75b368f-6ead-430c-a8f4-2d1fb6287372','和復州李太保酬筆','徐鉉','宋','宋诗','song-poetry','','[]','處處良工事筆鋒，宣毫自昔最稱雄。',64,'全唐诗/poet.song.0.json','["處處良工事筆鋒，宣毫自昔最稱雄。", "因思南國巾箱學，願入蘭臺掌握中。", "委質幸歸彫玉匣，操詞曾侍兔園公。", "一篇麗藻真閒暇，共仰才多道不窮。"]'),
('f8ec951c-6729-4c2a-ae83-82ec97a89ee6','送蒯員外東遊舊治','徐鉉','宋','宋诗','song-poetry','','[]','百歲猶强健，知君即地仙。',48,'全唐诗/poet.song.0.json','["百歲猶强健，知君即地仙。", "孤飛下華表，太息問桑田。", "故吏今誰在，高名昔共傳。", "伊余亦遺老，相送一潸然。"]'),
('e224b06d-52c6-4689-8f2c-f0cddb9551ea','送王監丞之歷陽','徐鉉','宋','宋诗','song-poetry','','[]','歎息曾遊處，江邊故郡城。',48,'全唐诗/poet.song.0.json','["歎息曾遊處，江邊故郡城。", "青襟空皓首，往事似前生。", "綠綬君重綰，華簪我尚榮。", "年衰俱近道，莫話別離情。"]'),
('7ea2e575-969e-4b4b-981c-69e58d2ae6d3','送阮殿丞之靜海','徐鉉','宋','宋诗','song-poetry','','[]','聞子東征效遠官，行行春色黯離魂。',64,'全唐诗/poet.song.0.json','["聞子東征效遠官，行行春色黯離魂。", "中途輟棹尋吳苑，西向登樓望海門。", "鵩舍曾嗟經歲謫，靈光空念巋然存。", "陵遷谷變今如此，爲我停驂盡酒罇。"]'),
('99a25ee6-cbd1-4acf-8370-726050f15d95','送周員外之達','徐鉉','宋','宋诗','song-poetry','','[]','之子敷王澤，迢迢蜀棧東。',48,'全唐诗/poet.song.0.json','["之子敷王澤，迢迢蜀棧東。", "頒條有餘刃，對酒與誰同。", "身占賢良籍，家傳道德風。", "遠民思靜理，即此是陰功。"]'),
('40bef844-9932-4695-a19e-700be1316fc8','送長社胡明府','徐鉉','宋','宋诗','song-poetry','','[]','黄綬繫未穩，桂枝香尚新。',48,'全唐诗/poet.song.0.json','["黄綬繫未穩，桂枝香尚新。", "琴堂寧久次，諫署正求人。", "皎皎凉秋月，飄飄清路塵。", "元常有遺翰，求作篋中珍。"]'),
('49ea39e6-25fc-4391-ae57-a4f7e478212d','送表姪達師歸鄱陽','徐鉉','宋','宋诗','song-poetry','','[]','故鄉禾黍世親稀，中表相尋只有師。',32,'全唐诗/poet.song.0.json','["故鄉禾黍世親稀，中表相尋只有師。", "惆悵離懷向何許，鄱陽湖上葉飛時。"]'),
('ed933bd8-cc0d-45d2-ba7b-b3ee78ac7218','送秘閣朱員外知復州','徐鉉','宋','宋诗','song-poetry','','[]','景陵山水舊知名，珍重詩人建隼行。',64,'全唐诗/poet.song.0.json','["景陵山水舊知名，珍重詩人建隼行。", "未免簿書勞利刃，省貪烟月縱高情。", "揚雄閣下諸生送，陸羽門前百吏迎。", "聖代羣賢皆得路，三年傾首望鵬程。"]'),
('2a3eb7d7-f4da-463d-9341-6a294547887e','送浄道人東遊','徐鉉','宋','宋诗','song-poetry','','[]','身服竺乾教，心爲鄒魯儒。',48,'全唐诗/poet.song.0.json','["身服竺乾教，心爲鄒魯儒。", "觀風遊稷下，訪古入中都。", "短景程途遠，寒原店舍孤。", "東州多俊造，能賞碧雲無。"]'),
('9bd13759-2f71-4718-95df-b310b830017e','送李道士南遊','徐鉉','宋','宋诗','song-poetry','','[]','雲水李道士，曾爲中貴人。',48,'全唐诗/poet.song.0.json','["雲水李道士，曾爲中貴人。", "綺紈終不戀，松鶴自相親。", "雲氣蒼梧晚，芳華紫蓋春。", "匏瓜老猶繫，惆悵望行塵。"]'),
('e933073d-109d-4cec-a989-5872fcfe5d7b','送國子徐博士之澧州','徐鉉','宋','宋诗','song-poetry','','[]','多才適世用，學者不遑處。',48,'全唐诗/poet.song.0.json','["多才適世用，學者不遑處。", "新詞八詠樓，更汎涔陽浦。", "行當應列宿，且復施甘雨。", "高齋閒坐時，清談孰爲伍。"]'),
('cd1d342e-3feb-426e-8e19-51005a5fc7f1','送錢副使黎陽發運','徐鉉','宋','宋诗','song-poetry','','[]','一盃寒食酒，珍重送君行。',48,'全唐诗/poet.song.0.json','["一盃寒食酒，珍重送君行。", "花影黎陽渡，春風浚水聲。", "汎舟無廢事，騁驥有修程。", "應用方無暇，何須愴別情。"]'),
('6df50e89-c133-4aa9-9f6f-92e8c204298c','寄張階州','徐鉉','宋','宋诗','song-poetry','','[]','儀甫秉忠信，神明自來舍。',48,'全唐诗/poet.song.0.json','["儀甫秉忠信，神明自來舍。", "絳灌雖不容，蠻貊皆從化。", "榮名任紛糾，道性常閒暇。", "傳語當途人，無爲勞歎吒。"]'),
('5f3b44ba-d377-4950-ad6d-6fe6ba53fd46','送文懿大師浄公西遊','徐鉉','宋','宋诗','song-poetry','','[]','乘興西遊誰與同，一囊詩藁一枝筇。',64,'全唐诗/poet.song.0.json','["乘興西遊誰與同，一囊詩藁一枝筇。", "厭棲廬岳蓮花社，却訪南山紫閣峰。", "懷古有時應悵望，尋幽何處不從容。", "關中風物常牽夢，老卧閑曹轉放慵。"]'),
('8c2b8037-ec19-4e99-8d8d-8407a1ddb0ec','奉和武功學士舍人紀贈文懿大師浄公  其一','徐鉉','宋','宋诗','song-poetry','','[]','舊國荒凉成黍稷，故交危脆似琉璃。',32,'全唐诗/poet.song.0.json','["舊國荒凉成黍稷，故交危脆似琉璃。", "高人獨喜湯師在，手把新文數道碑。"]'),
('7f0cfa50-556f-4df0-a7e2-8b6b962b29d1','奉和武功學士舍人紀贈文懿大師浄公  其二','徐鉉','宋','宋诗','song-poetry','','[]','滿卷文章爲世重，出塵心迹少人同。',32,'全唐诗/poet.song.0.json','["滿卷文章爲世重，出塵心迹少人同。", "騰騰自得修真理，不管浮生覺夢中。"]'),
('ec61659a-e4c2-46bb-8893-e29a2cfebd7f','奉和武功學士舍人紀贈文懿大師浄公  其三','徐鉉','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','文似春華鋪曉陌，思如泉涌注長江。',32,'全唐诗/poet.song.0.json','["文似春華鋪曉陌，思如泉涌注長江。", "詩情道性知無夢，頻見殘燈照曙窗。"]'),
('170eecb9-1395-4105-a405-3529ab1e71f3','奉和武功學士舍人紀贈文懿大師浄公  其四','徐鉉','宋','宋诗','song-poetry','','[]','已潔心源超世表，却緣詩句有時名。',32,'全唐诗/poet.song.0.json','["已潔心源超世表，却緣詩句有時名。", "初聞行業如耆宿，及見容顔是後生。"]'),
('b93df849-b16c-4952-a85c-e0223c21a03e','奉和武功學士舍人紀贈文懿大師浄公  其五','徐鉉','宋','宋诗','song-poetry','','[]','只有閒情搜景物，不將客鬢惜流光。',32,'全唐诗/poet.song.0.json','["只有閒情搜景物，不將客鬢惜流光。", "京華才子多文會，衆許清詞每擅場。"]'),
('82410c02-360e-4e67-9505-895447dc189a','奉和武功學士舍人紀贈文懿大師浄公  其六','徐鉉','宋','宋诗','song-poetry','','[]','惠遠禪師名素重，維摩居士室皆空。',32,'全唐诗/poet.song.0.json','["惠遠禪師名素重，維摩居士室皆空。", "羣公競有詩相贈，組繡珠璣滿袖中。"]'),
('ddfa0298-d186-4d4e-b96d-5864a277efb9','奉和武功學士舍人紀贈文懿大師浄公  其七','徐鉉','宋','宋诗','song-poetry','','[]','南朝人物古猶今，只恐前身是道林。',32,'全唐诗/poet.song.0.json','["南朝人物古猶今，只恐前身是道林。", "處處經行常自適，不妨譚笑不妨吟。"]'),
('0ae715ce-89ca-47e2-849b-a00eb63de525','奉和武功學士舍人紀贈文懿大師浄公  其八','徐鉉','宋','宋诗','song-poetry','','[]','往往冥搜宵不寐，時時任性晝仍眠。',32,'全唐诗/poet.song.0.json','["往往冥搜宵不寐，時時任性晝仍眠。", "高情麗句誰偏重，聖代詞臣李謫仙。"]'),
('d301ad2b-1a82-4152-8a24-7e099596f686','奉和武功學士舍人紀贈文懿大師浄公  其九','徐鉉','宋','宋诗','song-poetry','','[]','霜髯病叟掩閑扃，禪客相尋有故情。',32,'全唐诗/poet.song.0.json','["霜髯病叟掩閑扃，禪客相尋有故情。", "每憶江南初識面，至今猶得愛才名。"]'),
('f4d2dd6b-0df8-477a-bdab-af9a424b2db0','詠史','徐鉉','宋','宋诗','song-poetry','','[]','京洛多權豪，游服相追隨。',264,'全唐诗/poet.song.0.json','["京洛多權豪，游服相追隨。", "青牛中甸車，白馬連環羈。", "珩珮競照耀，紳組舊參差。", "騶鳴行人駐，倏若流風馳。", "名園不問主，下輦輒失嬉。", "秦官錫雕盤，光祿假羽巵。", "侏儒善爲優，邯鄲有名姬。", "坐客應餘論，顧眄成恩私。", "鹵簿留國門，誰何不敢譏。", "歸來卧華堂，瑣窗承文楣。", "武夫瑩庭階，璧璫攢榮題。", "列燭正晶熒，噴香常逶迤。", "明朝入君門，密侍白玉墀。", "開言迎合旨，羣公默無爲。", "乍請考工地，亦拜床下兒。", "吹噓枯稊生，指顧千鈞移。", "回瞻狥名士，獧介爾何施。", "朱雲折檻去，梅福棄官歸。", "寂寞揚子雲，口吃不能辭。", "著書述聖道，徒許俗人嗤。", "漢室已久壞，往事垂于茲。", "眇然千載下，慷慨有餘悲。"]'),
('a595060c-deec-4173-af19-860cfbb4aa86','送曾直館歸寧泉州','徐鉉','宋','宋诗','song-poetry','','[]','常憐客子倦征岐，誰似曾郎得意歸。',64,'全唐诗/poet.song.0.json','["常憐客子倦征岐，誰似曾郎得意歸。", "廳瑣石渠封簡冊，手持仙桂拜庭闈。", "舟橫劍浦凌清瀨，馬過猿巖點翠微。", "却笑遼東千歲鶴，下來空歎昔人非。"]'),
('5f73d2dc-488c-43b1-88f2-039fab97eeeb','送樂學士知舒州','徐鉉','宋','宋诗','song-poetry','','[]','憶在同安郡，誰知是勝游。',72,'全唐诗/poet.song.0.json','["憶在同安郡，誰知是勝游。", "仙山常獨往，騷客自忘憂。", "暫別經多難，勞生已白頭。", "羨君驅蒨旆，兼得漱清流。", "民俗常如古，風光最稱秋。", "短歌聊抒意，爲我謝沙鷗。"]'),
('b8ffe3f8-c6ba-4f38-bc8a-9960e4c6eee5','送慎大卿解官侍親','徐鉉','宋','宋诗','song-poetry','','[]','聖朝無事九卿閒，藹藹東門綵服還。',64,'全唐诗/poet.song.0.json','["聖朝無事九卿閒，藹藹東門綵服還。", "舊日高名齊汲鄭，今朝至行似曾顔。", "更憐霜髩垂玄髮，猶恨深居遠舊山。", "老鶴乘軒真自愧，徘徊空在稻粱間。"]'),
('2e60b63b-514c-4a85-baba-ffcd70b49463','代書寄泗州錢侍郎','徐鉉','宋','宋诗','song-poetry','','[]','起部紆兩綬，恢恢刃有餘。',48,'全唐诗/poet.song.0.json','["起部紆兩綬，恢恢刃有餘。", "既爲侍中郎，又復專城居。", "無久戀鈴閣，早應還直廬。", "浚川春水滿，珍重寄雙魚。"]'),
('9649de18-50ae-43ce-a710-8412a41fc0d7','寄舒州樂學士','徐鉉','宋','宋诗','song-poetry','','[]','皖伯臺前綠樹春，吳塘初下碧溪分。',32,'全唐诗/poet.song.0.json','["皖伯臺前綠樹春，吳塘初下碧溪分。", "舊遊風景長牽夢，遥羨高齋望白雲。"]'),
('f1a61717-221a-4a95-9b27-a6e454cbf8d1','送吳支使之長安','徐鉉','宋','宋诗','song-poetry','','[]','幕府清資新雨露，高陽舊第久塵埃。',32,'全唐诗/poet.song.0.json','["幕府清資新雨露，高陽舊第久塵埃。", "百年遺老知誰在，應喜遼東鶴下來。"]'),
('803b0032-15b8-42a2-9749-a7389935988b','和譚鍊師見寄','徐鉉','宋','宋诗','song-poetry','','[]','一別高人世事多，歸山歧路轉蹉跎。',64,'全唐诗/poet.song.0.json','["一別高人世事多，歸山歧路轉蹉跎。", "定知上藥延衰齒，每憶玄談養太和。", "任道人生如夢寐，也從時態起風波。", "錦囊真籙遥相許，只待飆輪更一過。"]'),
('a8a2711c-f0cd-4b45-82c9-3e98e8dd8c62','和錢秘監與邊諫議南宮同直贈答','徐鉉','宋','宋诗','song-poetry','','[]','筵上詩題共筆床，罇前酒興話高陽。',64,'全唐诗/poet.song.0.json','["筵上詩題共筆床，罇前酒興話高陽。", "心清自覺官曹簡，院靜先知節候凉。", "南國少年推貴重，東堂前輩讓賢良。", "好看雙鳳追飛處，胡粉新塗紫界牆。"]'),
('7cd1cc4c-e7d5-4449-b615-e1f0d8ffc57e','送周郎中還司','徐鉉','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','憶在廬山始識君，當時惟擬共眠雲。',64,'全唐诗/poet.song.0.json','["憶在廬山始識君，當時惟擬共眠雲。", "那知身計關前定，却向人間逐世紛。", "紫閣峰前欣獨往，銀臺門裏歎離羣。", "青囊舊有登真訣，莫遣閒人取次聞。"]'),
('9f63fa36-45f8-4fec-93d6-ee5fcb308c4a','太師相公挽歌詞二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','巖廊舊德漢儲師，富貴優游自古稀。',64,'全唐诗/poet.song.0.json','["巖廊舊德漢儲師，富貴優游自古稀。", "四序不能違代謝，九原誰可與同歸。", "精神恍惚騎龍尾，功業紛綸在虎闈。", "惆悵鳴珂洛陽道，素車丹旐奉靈衣。"]'),
('407f37e9-0917-480e-8d64-031932029f08','太師相公挽歌詞二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','風流安石在東山，曾許從容妓樂間。',64,'全唐诗/poet.song.0.json','["風流安石在東山，曾許從容妓樂間。", "傾蓋算來能幾日，逝川東去不知還。", "北邙原上寒雲結，鄭國門前曉月彎。", "祖奠欲收賓御散，滿衣零淚掩衰顔。"]'),
('58746d18-3036-4001-b3e9-e1b33f1d0d39','送贊寧道人歸浙中','徐鉉','宋','宋诗','song-poetry','','[]','故里夫差國，高名惠遠師。',48,'全唐诗/poet.song.0.json','["故里夫差國，高名惠遠師。", "君恩從野逸，歸棹逐凌澌。", "舊訪雖無念，牽懷亦有詩。", "因行過秦望，爲致李斯碑。"]'),
('c3fcea2f-e0c9-4f37-840c-c27401afe941','和元少卿送越僧','徐鉉','宋','宋诗','song-poetry','','[]','塵機息盡一真僧，唯有林泉捨未能。',64,'全唐诗/poet.song.0.json','["塵機息盡一真僧，唯有林泉捨未能。", "蓮社故人今暫別，稽山舊隠與誰登。", "時清豈覺前游改，道勝寧辭白髮增。", "遥羨高齋吟望處，孤雲野鶴是親朋。"]'),
('e0091cb3-588d-415b-b85a-5f28c1611bf9','代書寄談鍊師','徐鉉','宋','宋诗','song-poetry','','[]','朱山松桂翠連雲，中有清虛小隠居。',64,'全唐诗/poet.song.0.json','["朱山松桂翠連雲，中有清虛小隠居。", "密養丹砂存正氣，靜披瓊藴誦真文。", "塤箎金石心常在，圭組烟霞路自分。", "憑仗鄉人傳尺素，山前驚起白羊羣。"]'),
('5e98ccbe-74c0-4358-a22a-74234a257199','送鄭先輩及第西歸','徐鉉','宋','宋诗','song-poetry','','[]','春晚緱山路，華光滿翠微。',48,'全唐诗/poet.song.0.json','["春晚緱山路，華光滿翠微。", "憐君持郄桂，歸去著萊衣。", "故國幾人在，浮生萬事非。", "唯當拭病眼，看子九霄飛。"]'),
('8b3714e6-cf05-4854-ab49-19305711997e','送高先輩南歸','徐鉉','宋','宋诗','song-poetry','','[]','鄉國悲前事，風光屬後生。',48,'全唐诗/poet.song.0.json','["鄉國悲前事，風光屬後生。", "名從天上得，身入故都行。", "草色初裁綬，鵬飛不算程。", "自憐枯朽思，相送剩含情。"]'),
('89c44dc9-14a1-4bc8-b58c-6b35e0f4b489','送嚴秀才下第東歸','徐鉉','宋','宋诗','song-poetry','','[]','世胄今爲旅，多才懶自營。',48,'全唐诗/poet.song.0.json','["世胄今爲旅，多才懶自營。", "坦懷君子道，惜別故人情。", "歸棹春潮滿，郊居海月明。", "雄文不輕售，須待最高名。"]'),
('069c8f5d-ef1c-4094-99c9-c376ac8bfe44','送周味道秀才東歸見別依韻','徐鉉','宋','宋诗','song-poetry','','[]','庭闈勞夢想，孤棹度江關。',48,'全唐诗/poet.song.0.json','["庭闈勞夢想，孤棹度江關。", "駿馬猶論價，荆藍且抱還。", "晚花縈綵服，疏雨映家山。", "頻見春官說，明年待鑄顔。"]'),
('6336e7f1-7244-49e2-8aec-a559e871c039','送曾秀才','徐鉉','宋','宋诗','song-poetry','','[]','淦水神仙宅，仙山夾縣樓。',48,'全唐诗/poet.song.0.json','["淦水神仙宅，仙山夾縣樓。", "吾孫好詩句，歸詠故鄉秋。", "紫竹遮書幌，紅蕉拂釣舟。", "東堂有平路，莫謁外諸侯。"]'),
('1afe3b68-82c0-4e5a-9ad8-273a5892095f','寄玉笥山沈道士','徐鉉','宋','宋诗','song-poetry','','[]','珍重江南沈鍊師，未曾相識久相思。',64,'全唐诗/poet.song.0.json','["珍重江南沈鍊師，未曾相識久相思。", "已全真氣能從俗，不墜家風善賦詩。", "玉笥共游知早晚，金貂回顧覺喧卑。", "多慚書札遥相問，更望刀圭換白髭。"]'),
('370368f1-8e86-46a9-9d4f-dbc7fcb33a97','和錢秘監旅居秋懷二首  其一','徐鉉','宋','宋诗','song-poetry','','[]','秘監疏朝謁，門前長綠苔。',48,'全唐诗/poet.song.0.json','["秘監疏朝謁，門前長綠苔。", "未愁玄鬢改，且喜素秋來。", "獨坐翻棋勢，閑行繞藥栽。", "凉風入書幌，時動水沉灰。"]'),
('6f3bc529-65f1-4a6b-b5f3-f3ef4254a291','和錢秘監旅居秋懷二首  其二','徐鉉','宋','宋诗','song-poetry','','[]','閒靜無凡客，開罇共醉醒。',48,'全唐诗/poet.song.0.json','["閒靜無凡客，開罇共醉醒。", "琴彈碧玉調，書展太玄經。", "酒熟看黄菊，詩成寫素屏。", "晚來蕭灑甚，山鳥下中庭。"]'),
('53e71c06-6004-4b67-98cf-935b9919da8a','送元道人還水西寺','徐鉉','宋','宋诗','song-poetry','','[]','李白高吟處，師歸掩竹關。',48,'全唐诗/poet.song.0.json','["李白高吟處，師歸掩竹關。", "道心明月靜，詩思碧雲閑。", "綠樹寒凌雪，飛泉響遍山。", "自慚丘壑志，皓首不知還。"]'),
('e935bd1e-62f2-4486-8c29-9728dd8a6355','送李秀才歸建安','徐鉉','宋','宋诗','song-poetry','','[]','昔聞武夷士，皆是帝曾孫。',96,'全唐诗/poet.song.0.json','["昔聞武夷士，皆是帝曾孫。", "李君即其人，命舛道常存。", "愛子已折桂，華組耀閨門。", "吾身可拂衣，綵服歸丘園。", "捧觴慶北堂，其樂不可言。", "清溪環幽居，遠岫橫前軒。", "彈琴詠招隠，芳意飄若蘭。", "老夫無此分，何必矜彈冠。"]'),
('23b55de9-48fb-4dba-8585-12651bfc2c16','和李太保寄刁秘書','徐鉉','宋','宋诗','song-poetry','','[]','名位雖卑道自光，訟庭無事俗平康。',64,'全唐诗/poet.song.0.json','["名位雖卑道自光，訟庭無事俗平康。", "簾間尚覺琴床暖，院靜偏聞酒甕香。", "養性已知無病染，持廉唯恐有名彰。", "主人莫訝暌違遠，千仞由來有鳳翔。"]'),
('0f7a2710-3144-4867-b525-21508a7fd404','又和刁秘書寄李太保','徐鉉','宋','宋诗','song-poetry','','[]','百里臨民自可憐，青雲何必藉階緣。',64,'全唐诗/poet.song.0.json','["百里臨民自可憐，青雲何必藉階緣。", "家貧聊欲資三徑，政簡無非草太玄。", "處衆忘懷均物我，程才不器任方員。", "江湖相望真堪喜，聚散悲歡盡偶然。"]'),
('c6e4cecd-b26c-4a67-98a2-646ffa54be71','送坊州賈監軍','徐鉉','宋','宋诗','song-poetry','','[]','聖主欲東封，憐君四護戎。',48,'全唐诗/poet.song.0.json','["聖主欲東封，憐君四護戎。", "鄉心經霸岸，詩思省豳風。", "舊業今成旅，朱顔已變翁。", "忘懷一盃酒，閑夜與誰同。"]'),
('297b7ce2-161c-477b-bde4-e3aba6f5381e','送李補闕知韶州','徐鉉','宋','宋诗','song-poetry','','[]','南國求良牧，中朝輟諫官。',72,'全唐诗/poet.song.0.json','["南國求良牧，中朝輟諫官。", "君恩偏念遠，臣節豈辭難。", "騎影過梅嶺，溪聲上贛灘。", "曲江宜訪古，韶石好憑欄。", "詩景緣情遠，民心逐政寬。", "衰翁尋舊分，爲致葛洪丹。"]'),
('0fc5a2c7-2f47-4fe7-a559-d048df8f7530','送修武鄭主簿糾郡梓潼兼寄王舍人八韻','徐鉉','宋','宋诗','song-poetry','','[]','杖策辭清浴，驅車向梓潼。',96,'全唐诗/poet.song.0.json','["杖策辭清浴，驅車向梓潼。", "棲鸞才乍展，叱馭氣方雄。", "暫割趨庭戀，將伸糾郡功。", "詩清衝密雪，別酒愬寒風。", "山水秦關外，烟花錦里東。", "府公名素重，語掾道仍同。", "坐嘯新知洽，隨行舊分通。", "當令從此去，不復數文翁。"]'),
('c4a5111f-47dd-4ddd-815d-04e10a406c04','和李秀才雪中求酒','徐鉉','宋','宋诗','song-poetry','','[]','雪英飄灑繞虛廊，曉景沉沉朔吹狂。',64,'全唐诗/poet.song.0.json','["雪英飄灑繞虛廊，曉景沉沉朔吹狂。", "銀闕晶熒標帝里，桂華紛糅認仙鄉。", "少年風味新吟動，老叟襟懷萬事忘。", "自倒空罇酬絕唱，書幃聊得泛寒光。"]'),
('f98cf741-4399-496a-bf1d-468c62c195f5','送謝著作之濠梁','徐鉉','宋','宋诗','song-poetry','','[]','謝客乘軺去，清和景物初。',48,'全唐诗/poet.song.0.json','["謝客乘軺去，清和景物初。", "淮流宜映月，濠上好觀魚。", "吏事應微撓，吟情自有餘。", "偏州莫留滯，東觀待繙書。"]'),
('0d9527af-c9d6-4e29-8bab-28c134a1de19','代書寄宋州錢大監','徐鉉','宋','宋诗','song-poetry','','[]','衰朽經煩暑，慵將病共侵。',48,'全唐诗/poet.song.0.json','["衰朽經煩暑，慵將病共侵。", "北窗時企足，東望一披襟。", "秘監清罇滿，平臺綠樹深。", "年來書信少，何以慰離心。"]'),
('d321766e-5eab-486d-a00f-6981142ee6d8','送錢先輩之虔州','徐鉉','宋','宋诗','song-poetry','','[]','子實東南美，來參第一流。',48,'全唐诗/poet.song.0.json','["子實東南美，來參第一流。", "從容持片玉，談笑運前籌。", "贛石連雲秀，廉泉带月秋。", "可憐行樂地，況從板輿遊。"]'),
('d531615a-cbdf-4fea-a459-a650c227b297','送阮洗馬之全州','徐鉉','宋','宋诗','song-poetry','','[]','望苑迴先馬，山城駐使車。',24,'全唐诗/poet.song.0.json','["望苑迴先馬，山城駐使車。", "塗中值歸雁，頻寄北來書。"]'),
('9399ccfe-1ef7-453d-8a2b-9503be6a07c0','觀燈玉臺體十首  其一','徐鉉','宋','宋诗','song-poetry','','[]','吳歌楚舞玉詩新，華燈蘭焰動魚鱗。',32,'全唐诗/poet.song.0.json','["吳歌楚舞玉詩新，華燈蘭焰動魚鱗。", "臺前共道明如晝，醉裏唯愁夜向晨。"]'),
('b57d30f5-2214-452e-8d5f-e52d3ed1ae46','觀燈玉臺體十首  其二','徐鉉','宋','宋诗','song-poetry','','[]','綺席金爐香正燃，銅壺銀箭漏初傳。',32,'全唐诗/poet.song.0.json','["綺席金爐香正燃，銅壺銀箭漏初傳。", "天迴星月迷燈燭，風過樓臺度管弦。"]'),
('434b7128-3833-4f64-bb45-3ca0d387e513','觀燈玉臺體十首  其三','徐鉉','宋','宋诗','song-poetry','','[]','雙闕重闉夜不關，金車寶馬曉應還。',32,'全唐诗/poet.song.0.json','["雙闕重闉夜不關，金車寶馬曉應還。", "亭亭明月臨瑶席，灼灼華燈照玉顔。"]'),
('8f2ae94f-300e-4e69-abbf-9d4009828cce','觀燈玉臺體十首  其四','徐鉉','宋','宋诗','song-poetry','','[]','火樹燈山高入雲，紅筵翠幄自成春。',32,'全唐诗/poet.song.0.json','["火樹燈山高入雲，紅筵翠幄自成春。", "游女有時還解佩，青樓何處不留人。"]'),
('6dd8f0e1-c422-4acd-9669-fb2b007d0318','觀燈玉臺體十首  其五','徐鉉','宋','宋诗','song-poetry','','[]','帝京風景不曾秋，萬戶千門夜更遊。',32,'全唐诗/poet.song.0.json','["帝京風景不曾秋，萬戶千門夜更遊。", "玓瓅銀鞍連繡轂，晶熒珠網掛瓊鈎。"]'),
('90154bf1-d7ec-4f6a-ad9b-35595de89aed','觀燈玉臺體十首  其六','徐鉉','宋','宋诗','song-poetry','','[]','夜未央，明月光。',20,'全唐诗/poet.song.0.json','["夜未央，明月光。", "熒煌九華燭，交影照歌梁。"]'),
('db7a7de4-a681-4014-91d3-24bcb22fff13','觀燈玉臺體十首  其七','徐鉉','宋','宋诗','song-poetry','','[]','敞麗譙，披綺寮。',20,'全唐诗/poet.song.0.json','["敞麗譙，披綺寮。", "歌聲和夜漏，火樹似花朝。"]'),
('53cd7671-2e3d-48f2-ac20-7b3a5d5a64c6','觀燈玉臺體十首  其八','徐鉉','宋','宋诗','song-poetry','','[]','星漢斜，樂無涯。',20,'全唐诗/poet.song.0.json','["星漢斜，樂無涯。", "明月千門雪，銀燈萬樹花。"]'),
('2aad67d5-fef1-4a48-aafd-c16edd0f8bee','觀燈玉臺體十首  其九','徐鉉','宋','宋诗','song-poetry','','[]','撫雲璈，吹玉簫。',20,'全唐诗/poet.song.0.json','["撫雲璈，吹玉簫。", "艷舞迴羅袂，香風閃步摇。"]'),
('02f2f7e7-3266-4ec8-acc4-ded38a2bb833','觀燈玉臺體十首  其一○','徐鉉','宋','宋诗','song-poetry','','[]','日照花，七香車。',20,'全唐诗/poet.song.0.json','["日照花，七香車。", "歌舞平陽第，經過趙李家。"]'),
('12bba77f-2874-4bc0-bbd6-2caef83d4003','和李秀才端午日見寄','徐鉉','宋','宋诗','song-poetry','','[]','角黍菖蒲酒，年年舊俗諳。',48,'全唐诗/poet.song.0.json','["角黍菖蒲酒，年年舊俗諳。", "采衣君自樂，白髮我何堪。", "靜味瑶華句，閒思玉柄譚。", "報之長命縷，祝慶在圖南。"]'),
('4b94a4b8-2ef9-4a41-818f-25eaaa720a36','送清道人歸西山','徐鉉','宋','宋诗','song-poetry','','[]','嘗憶漱甘醴，洪涯藥臼旁。',48,'全唐诗/poet.song.0.json','["嘗憶漱甘醴，洪涯藥臼旁。", "今來眇如夢，此景未曾忘。", "圭組老無味，林泉路更長。", "羨師從此去，當暑扣雲房。"]'),
('965dc12f-7efc-4c54-a314-28c052fc0843','送張學士赴西川','徐鉉','宋','宋诗','song-poetry','','[]','右蜀分憂輟近臣，翩翩旄節下青冥。',64,'全唐诗/poet.song.0.json','["右蜀分憂輟近臣，翩翩旄節下青冥。", "單車唯載支機石，夙駕長先使者星。", "已有清風馳棧道，猶酣別酒過長亭。", "佗年報政徵黄入，留取文翁舊典刑。"]'),
('ab90101d-8ce2-4cf5-a5bd-7f5a56b7051b','和李宗諤秀才贈蒯員外','徐鉉','宋','宋诗','song-poetry','','[]','性僻時難偶，神清壽有餘。',48,'全唐诗/poet.song.0.json','["性僻時難偶，神清壽有餘。", "曾施卓魯政，舊講老莊書。", "賤更襟懷曠，貧猶世利疏。", "聖君將就見，慎無買山居。"]'),
('8f5bbee4-3793-4f4f-8472-f93132d2a253','送德明道人還東林','徐鉉','宋','宋诗','song-poetry','','[]','每憶曾遊處，東林惠遠房。',48,'全唐诗/poet.song.0.json','["每憶曾遊處，東林惠遠房。", "老來情更重，師去興何長。", "澗曲泉聲咽，松深露氣香。", "題詩寄楚老，惆悵不成章。"]'),
('b719ea39-e25d-438b-a5e5-4dfb90783ed0','送馮中允使蜀','徐鉉','宋','宋诗','song-poetry','','[]','莫笑皤然一病翁，百年交分兩家同。',64,'全唐诗/poet.song.0.json','["莫笑皤然一病翁，百年交分兩家同。", "今朝倒屣迎王粲，舊日清談賞阿戎。", "玉壘無辭軺傳送，金閨初喜姓名通。", "青城山下逢仙客，爲說心丹未輟功。"]'),
('3d116e82-a1a1-4868-b952-77ff94697bd9','送新除國博徐員外知婺州','徐鉉','宋','宋诗','song-poetry','','[]','憐君盡室泛安流，職重官新未白頭。',64,'全唐诗/poet.song.0.json','["憐君盡室泛安流，職重官新未白頭。", "楚老歡迎歸舊里，春風留戀過揚州。", "逢時肯更嗟庭樹，屬詠還應上郡樓。", "宗黨故人鄉外少，勤勤書札緩離愁。"]'),
('7ef4b494-3df6-4db1-b96c-758f1b2b58b6','送望江張明府','徐鉉','宋','宋诗','song-poetry','','[]','之官別是榮，詔許侍親行。',48,'全唐诗/poet.song.0.json','["之官別是榮，詔許侍親行。", "溫凊自爲樂，烟波不算程。", "山留丹竈室，俗有故鄉情。", "無使千年後，空傳麴令名。"]'),
('7053fdd4-b6e3-495f-ae7d-034a1686a3d1','送廖舍人江南安撫','徐鉉','宋','宋诗','song-poetry','','[]','上天本愛民，治亂當有時。',132,'全唐诗/poet.song.0.json','["上天本愛民，治亂當有時。", "傷嗟江表人，三災迭擾之。", "如何遭盛明，不能免流離。", "王澤限遐遠，孰云天聽卑。", "賢哉廖夫子，盡忠不顧私。", "朝聞青蒲奏，暮見軺車馳。", "愚聞奉使者，受命不受辭。", "但使民瘼瘳，無憂國賦虧。", "貞觀笑割股，文侯諭治皮。", "學古平生事，行行當在茲。", "贈言聊執手，願子副心期。"]'),
('a419dc89-8b15-4fba-82d8-cf9b49315e51','送陳使君之同州','徐鉉','宋','宋诗','song-poetry','','[]','太守驅征旆，翩翩西過關。',48,'全唐诗/poet.song.0.json','["太守驅征旆，翩翩西過關。", "冰容先臘至，膏雨逐春還。", "綠樹游沙苑，高樓看華山。", "從來京輔地，出入盡崇班。"]'),
('91d2ee95-4292-4c7e-bb63-6d82627b4a7e','和元少卿雪','徐鉉','宋','宋诗','song-poetry','','[]','朔風飛雪徧遥天，爲瑞偏宜在臘前。',64,'全唐诗/poet.song.0.json','["朔風飛雪徧遥天，爲瑞偏宜在臘前。", "有客棹舟將命友，何人高卧共稱賢。", "瑶花散亂紛臨席，玉樹晶熒爛滿川。", "閒想冰容比君子，始知姑射有神仙。"]'),
('aafff6b9-27b8-4635-b69b-4ba870f75ff3','送頵道人還西山','徐鉉','宋','宋诗','song-poetry','','[]','嘗憶洪崖澗，穿雲路萬尋。',48,'全唐诗/poet.song.0.json','["嘗憶洪崖澗，穿雲路萬尋。", "曾經照玄鬢，未得卸朝簪。", "老去馳莊蝶，年來有越吟。", "羨師從此去，舊隠翠微深。"]'),
('d978beac-72c9-4b38-be2d-8285672712c3','送歷陽方明府','徐鉉','宋','宋诗','song-poetry','','[]','古縣橫江北，弦歌似武城。',48,'全唐诗/poet.song.0.json','["古縣橫江北，弦歌似武城。", "善辭金馬召，欣著綵衣行。", "舊感河山色，離愁浚水聲。", "外門廬井在，相送幾重情。"]'),
('c1927de2-4db2-4c60-87fd-c6a8f049dc9b','送李著作之漢陽','徐鉉','宋','宋诗','song-poetry','','[]','聞道驅征旆，行行至漢陽。',48,'全唐诗/poet.song.0.json','["聞道驅征旆，行行至漢陽。", "初程微雨霽，滿路落花香。", "遠宦心常適，青雲去未妨。", "惟餘親戚分，惆悵上河梁。"]'),
('d5ba7939-a834-439c-aeb2-c78f9b886ed9','哭刑部侍郎喬公詩','徐鉉','宋','宋诗','song-poetry','','[]','舉世重文雅，夫君更質真。',120,'全唐诗/poet.song.0.json','["舉世重文雅，夫君更質真。", "曾嗟混雞鶴，終日異緇磷。", "詞賦離騷客，封章諫諍臣。", "襟懷道家侶，標格古時人。", "逸老誠云福，遺形未免貧。", "求文空得草，埋玉遂爲塵。", "靜想忘年契，冥思接武晨。", "連宵洽杯酒，分日掌絲綸。", "蠹簡書陳事，遺孤託世親。", "前賢同此歎，非我獨霑巾。"]'),
('4bc4f213-eb2c-4a89-a77c-39b6f9c04a17','吳王挽詞  其一','徐鉉','宋','宋诗','song-poetry','','[]','倏忽千齡盡，冥茫萬事空。',48,'全唐诗/poet.song.0.json','["倏忽千齡盡，冥茫萬事空。", "青松洛陽陌，荒草建康宮。", "道德遺文在，興衰自古同。", "受恩無補報，反袂泣途窮。"]'),
('405a0282-6eff-42af-a46f-f4b7f2be9f52','吳王挽詞  其二','徐鉉','宋','宋诗','song-poetry','','[]','土德承餘烈，江南廣舊恩。',48,'全唐诗/poet.song.0.json','["土德承餘烈，江南廣舊恩。", "一朝人事變，千古信書存。", "哀挽周原道，銘旌鄭國門。", "此生雖未死，寂寞已銷魂。"]'),
('f761e78a-66fd-4965-867c-cf9c345f3454','和元宗元日大雪登樓','徐鉉','宋','宋诗','song-poetry','','[]','一宿東林正氣和，便隨仙仗放春華。',64,'全唐诗/poet.song.0.json','["一宿東林正氣和，便隨仙仗放春華。", "散飄白絮惟分影，輕綴青旗始見花。", "落砌更依宮舞轉，入樓偏向御衣斜。", "嚴徐共待金門詔，願布堯言賀萬家。"]'),
('b56ea48b-10b8-44c9-9d35-a05cc2bc0cbe','句  其一','徐鉉','宋','宋诗','song-poetry','','[]','一夜黄星照官渡，本初何面見田豐。',16,'全唐诗/poet.song.0.json','["一夜黄星照官渡，本初何面見田豐。"]'),
('6b1c2e0e-b1ac-4731-bd0f-cb4b2281aabf','句  其二','徐鉉','宋','宋诗','song-poetry','','[]','井泉分地脈，砧杵共秋聲。',12,'全唐诗/poet.song.0.json','["井泉分地脈，砧杵共秋聲。"]'),
('b0c12763-71c5-43f6-aee3-90c377778b9b','句  其三','徐鉉','宋','宋诗','song-poetry','','[]','鍾山祠畔宿烟晴，玉澗橋邊碧樹椿。',16,'全唐诗/poet.song.0.json','["鍾山祠畔宿烟晴，玉澗橋邊碧樹椿。"]'),
('fe5e6faa-4cee-451f-a208-684747139bf5','存目','徐鉉','宋','宋诗','song-poetry','','[]','詩題：貢院鎖宿聞呂員外使高麗贈送首句：聖化今無外。',25,'全唐诗/poet.song.0.json','["詩題：貢院鎖宿聞呂員外使高麗贈送首句：聖化今無外。"]'),
('0e22a40a-4f5a-4da4-8ff4-7483b8142099','題義門胡氏華林書院','宋琪','宋','宋诗','song-poetry','','[]','賢良肄業文方盛，孝友傳家族更豪。',64,'全唐诗/poet.song.0.json','["賢良肄業文方盛，孝友傳家族更豪。", "旌表特恩門第貴，御書新賜姓名高。", "謀孫有後榮非數，待士無疏衆豈勞。", "我想華林終未到，只因氣概屬仙曹。"]'),
('cfeadf96-1cbe-46a4-9dc6-b00101145c4b','懷夢英大師','趙逢','宋','宋诗','song-poetry','','["\u534e\u5c71"]','林巒影裏有清賢，與我相知二十年。',64,'全唐诗/poet.song.0.json','["林巒影裏有清賢，與我相知二十年。", "書札愛工精玉筯，利名拋捨住金田。", "吟容賈島稱詩匠，辭許劉靈作酒仙。", "別後近聞棲華嶽，亂雲應得恣情眠。"]'),
('056fdfae-07e8-44e5-a932-25ac50adf3dd','句  其一','卞震','宋','宋诗','song-poetry','','[]','雨壁長秋菌，風枝落病蟬。',12,'全唐诗/poet.song.0.json','["雨壁長秋菌，風枝落病蟬。"]'),
('b9d55170-bc25-44d6-a371-7086f3c2065e','句  其二','卞震','宋','宋诗','song-poetry','','[]','老筇搘瘦影，寒木憑吟身。',12,'全唐诗/poet.song.0.json','["老筇搘瘦影，寒木憑吟身。"]'),
('f885d9d4-b377-4674-b4ee-cb79e5fe8953','句  其三','卞震','宋','宋诗','song-poetry','','[]','詩債到春無處避，離愁因醉暫時無。',16,'全唐诗/poet.song.0.json','["詩債到春無處避，離愁因醉暫時無。"]'),
('8c8c791f-d6d0-457d-a770-ed4f70cff1a7','句  其四','卞震','宋','宋诗','song-poetry','','[]','茶香解睡磨鐺煮，山色牽懷著屐登。',16,'全唐诗/poet.song.0.json','["茶香解睡磨鐺煮，山色牽懷著屐登。"]'),
