('09bc842e-8f54-4cd4-80e7-e5d893ebb541','答僧慧文  其二','釋曉榮','宋','宋诗','song-poetry','','[]','一念周沙界，日用萬般通。',24,'全唐诗/poet.song.0.json','["一念周沙界，日用萬般通。", "湛然常寂滅，常展自家風。"]'),
('aed70828-a0fd-4b9a-bc1b-ac8ddbd82172','留鶴贈廖融','潘若沖','宋','宋诗','song-poetry','','[]','峭格數年同野興，一官才罷共船歸。',64,'全唐诗/poet.song.0.json','["峭格數年同野興，一官才罷共船歸。", "稻粱少飼教長瘦，羽翼無傷任遠飛。", "側耳聽吟侵靜燭，銜花作舞带斜暉。", "朝天萬里不將去，留伴高人向釣磯。"]'),
('3640fd6f-274d-4e4f-933b-2bc5c1df5be3','寄南嶽廖融','潘若沖','宋','宋诗','song-poetry','','["\u8861\u5c71"]','曾經別墅住行蹤，春浪和烟撼釣筒。',64,'全唐诗/poet.song.0.json','["曾經別墅住行蹤，春浪和烟撼釣筒。", "共步幽亭連石蘚，寄眠靜榻带松風。", "秋來頻夢嶽雲白，別後應添鶴頂紅。", "又泛汴舟隨汴水，不堪南望思忡忡。"]'),
('790cb21f-cfe2-47ab-920b-f8d2de04aa2d','聞融與鶴相繼而亡感賦絕句','潘若沖','宋','宋诗','song-poetry','','["\u8861\u5c71"]','南嶽僧來共歎吁，風亭月榭已荒蕪。',32,'全唐诗/poet.song.0.json','["南嶽僧來共歎吁，風亭月榭已荒蕪。", "先生去世未十日，留伴高吟鶴亦徂。"]'),
('0e686b92-2ccc-458f-9649-dd771fe41801','哭廖融','潘若沖','宋','宋诗','song-poetry','','[]','天喪我良知，無言雙淚垂。',48,'全唐诗/poet.song.0.json','["天喪我良知，無言雙淚垂。", "惟求相見夢，永絕寄來詩。", "應有異人吊，從茲雅道衰。", "春風古原上，新塚草離離。"]'),
('75e20c12-6b17-4d81-88d7-ab9a11af1d9f','贈王正己','潘若沖','宋','宋诗','song-poetry','','[]','兩捧歌詩寄，公餘即展開。',48,'全唐诗/poet.song.0.json','["兩捧歌詩寄，公餘即展開。", "無時惟北望，何日逐南來。", "夢裏得芳草，笛中聞落梅。", "終朝一携手，江上有樓臺。"]'),
('49aff695-96e2-4fad-981a-f3bdbc09405c','北海題渚宮','竇儼','宋','宋诗','song-poetry','','[]','紀南南望水城寬，水色天光混一般。',32,'全唐诗/poet.song.0.json','["紀南南望水城寬，水色天光混一般。", "大抵江鄉足詩景，詠吟如把畫圖看。"]'),
('01e6d957-19ef-492b-87c7-6e490cf8325f','偈答百丈僧','釋道常','宋','宋诗','song-poetry','','[]','不要三乘要祖宗，三乘不要與君同。',32,'全唐诗/poet.song.0.json','["不要三乘要祖宗，三乘不要與君同。", "君今欲會通宗旨，後夜猿啼在亂峰。"]'),
('85dd39e2-e4a4-4f99-8751-172a8e3d87ac','宿廖融山齋','楊徽之','宋','宋诗','song-poetry','','[]','清和春尚在，歡醉日何長。',48,'全唐诗/poet.song.0.json','["清和春尚在，歡醉日何長。", "谷鳥隨柯轉，庭花奪酒香。", "初晴巖翠滴，嚮晚樹陰凉。", "別有堪吟處，相留宿草堂。"]'),
('93c4dadf-42f9-45c1-a45f-70e817318bb8','峨眉','楊徽之','宋','宋诗','song-poetry','','[]','嘉州山水地，二蜀最爲美。',24,'全唐诗/poet.song.0.json','["嘉州山水地，二蜀最爲美。", "翠嶺疊峨眉，長瀾湧錦水。"]'),
('e0649e70-4047-44b2-b63f-833691aabe58','翠光亭','楊徽之','宋','宋诗','song-poetry','','[]','釣舟浮淺瀨，岡舍晚重林。',24,'全唐诗/poet.song.0.json','["釣舟浮淺瀨，岡舍晚重林。", "雲放千峰出，花藏一徑深。"]'),
('c9217b2a-7467-402e-90bb-072f5ab9f30f','嘉州作','楊徽之','宋','宋诗','song-poetry','','[]','俗遇臘辰持藥獻，吏逢衙日隔花參。',32,'全唐诗/poet.song.0.json','["俗遇臘辰持藥獻，吏逢衙日隔花參。", "耆宿因來問封部，竹籬西畔是雲南。"]'),
('cb29a42b-ecda-4f6b-9301-d4e77fe0393c','禁林讌會之什','楊徽之','宋','宋诗','song-poetry','','[]','星移歲律應青陽，得奉羣英集玉堂。',96,'全唐诗/poet.song.0.json','["星移歲律應青陽，得奉羣英集玉堂。", "龍鳳雙飛觀御札，雲霞五色詠天章。", "禁林漸覺清風暖，仙界元知白日長。", "詔出紫泥封去潤，朝迴蓮燭賜來香。", "二篇稱奬恩尤重，萬國傳聞道更光。", "何幸微才逢盛事，願因史冊紀餘芳。"]'),
('da7acaa7-be7f-4aa3-94da-e13efb0697c6','漢陽晚泊','楊徽之','宋','宋诗','song-poetry','','[]','傍橋吟望漢陽城，山徧樓臺徹上層。',64,'全唐诗/poet.song.0.json','["傍橋吟望漢陽城，山徧樓臺徹上層。", "犬吠竹籬沽酒客，鶴隨苔岸洗衣僧。", "疏鐘未徹聞寒漏，斜月初沈見遠燈。", "夜靜鄰船問行計，曉帆相與向巴陵。"]'),
('a3df95a4-e03d-4b65-8d52-5c5c5afa7d4e','寒食寄鄭起侍郎','楊徽之','宋','宋诗','song-poetry','','["\u5bd2\u98df\u8282", "\u601d\u4e61", "\u5199\u666f"]','清明時節出郊原，寂寂山城柳映門。',64,'全唐诗/poet.song.0.json','["清明時節出郊原，寂寂山城柳映門。", "水隔淡烟脩竹寺，路經疏雨落花村。", "天寒酒薄難成醉，地迥樓高易斷魂。", "回首故山千里外，別離心緒向誰言。"]'),
('25379efa-4c27-4377-9eae-424ca2d6954e','贈譚先生','楊徽之','宋','宋诗','song-poetry','','[]','古觀重重遶翠微，杉松深處掩雙扉。',64,'全唐诗/poet.song.0.json','["古觀重重遶翠微，杉松深處掩雙扉。", "雲生萬壑投龍去，海隔三山放鶴歸。", "花洞宴遊春日永，石壇朝禮曙星稀。", "每聽高論長生理，擬向塵中便拂衣。"]'),
('80e6f9b5-ff11-443a-a84f-49d05b7fcaca','送夢英大師','楊徽之','宋','宋诗','song-poetry','','[]','獨携瓶錫欲春殘，深入終南路屈盤。',64,'全唐诗/poet.song.0.json','["獨携瓶錫欲春殘，深入終南路屈盤。", "萬象幽玄吟裏見，一心圓寂定中觀。", "翠微寺在杉松老，紫閣峰高水石寒。", "莫憑危欄臨北望，滿城烟草是長安。"]'),
('00f40d0d-1ba9-49ba-8303-908d95e6f5a2','句  其一','楊徽之','宋','宋诗','song-poetry','','[]','戍樓烟自直，戰地雨長腥。',12,'全唐诗/poet.song.0.json','["戍樓烟自直，戰地雨長腥。"]'),
('a678ea07-51c9-4d18-9b98-8d2a5abe23a6','句  其二','楊徽之','宋','宋诗','song-poetry','','[]','偶題巖石雲生筆，閑遶庭松露濕衣。',16,'全唐诗/poet.song.0.json','["偶題巖石雲生筆，閑遶庭松露濕衣。"]'),
('d111b184-5d3a-4c5a-809e-41af9569a168','句  其三','楊徽之','宋','宋诗','song-poetry','','[]','新霜染楓葉，皓月借蘆花。',12,'全唐诗/poet.song.0.json','["新霜染楓葉，皓月借蘆花。"]');
